INSERT INTO `email_logs` (`id`, `template_id`, `recipient`, `subject`, `content`, `created_at`, `sent_at`, `status`, `tracking_token`, `error_message`, `opened_at`, `template_key`, `user_id`) VALUES
(400, NULL, 'Illyrianc@gmail.com', 'Vervollständigen Sie Ihre KYC-Verifizierung', '<!DOCTYPE html>\n<html>\n<head>\n    <meta charset=\"UTF-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n    <title>Vervollständigen Sie Ihre KYC-Verifizierung</title>\n    <style>\n        body {\n            font-family: -apple-system, BlinkMacSystemFont, \"Segoe UI\", Roboto, \"Helvetica Neue\", Arial, sans-serif;\n            line-height: 1.6;\n            color: #333;\n            margin: 0;\n            padding: 0;\n            background-color: #f4f4f4;\n        }\n        .email-container {\n            max-width: 600px;\n            margin: 0 auto;\n            background-color: #ffffff;\n        }\n        .email-header {\n            background: linear-gradient(135deg, #2950a8, #2da9e3);\n            color: white;\n            padding: 30px;\n            text-align: center;\n            border-radius: 10px 10px 0 0;\n        }\n        .email-header h1 {\n            margin: 0;\n            font-size: 28px;\n            font-weight: 700;\n        }\n        .email-header p {\n            margin: 5px 0 0 0;\n            font-size: 14px;\n            opacity: 0.9;\n        }\n        .email-body {\n            padding: 30px;\n            background-color: #ffffff;\n        }\n        .email-footer {\n            background-color: #f9f9f9;\n            color: #333;\n            padding: 25px;\n            text-align: left;\n            font-size: 14px;\n        }\n        .email-footer p {\n            margin: 5px 0;\n        }\n        .email-footer a {\n            color: #007bff;\n            text-decoration: none;\n        }\n        .signature {\n            margin-top: 40px;\n            border-top: 1px solid #e0e0e0;\n            padding-top: 25px;\n            font-size: 14px;\n            color: #555;\n            text-align: center;\n        }\n        .signature img {\n            height: 50px;\n            margin: 0 auto 12px;\n            display: block;\n        }\n        .signature strong {\n            color: #111;\n            font-size: 15px;\n        }\n        .signature a {\n            color: #007bff;\n            text-decoration: none;\n        }\n        .signature p {\n            font-size: 12px;\n            color: #777;\n            line-height: 1.5;\n            margin-top: 8px;\n        }\n        .footer {\n            text-align: center;\n            font-size: 12px;\n            color: #777;\n            padding: 15px;\n            background: #f1f3f5;\n        }\n        a {\n            color: #2950a8;\n            text-decoration: none;\n        }\n        h2 {\n            color: #2950a8;\n            margin-top: 0;\n        }\n        h3 {\n            color: #2950a8;\n        }\n        ul {\n            padding-left: 20px;\n        }\n        li {\n            margin-bottom: 8px;\n        }\n        .button {\n            display: inline-block;\n            padding: 12px 24px;\n            background: linear-gradient(135deg, #2950a8, #2da9e3);\n            color: white !important;\n            text-decoration: none;\n            border-radius: 5px;\n            font-weight: bold;\n            margin: 10px 0;\n        }\n        .button:hover {\n            opacity: 0.9;\n        }\n        @media only screen and (max-width: 600px) {\n            .email-body {\n                padding: 20px;\n            }\n            .email-header {\n                padding: 20px;\n            }\n            .signature img {\n                height: 45px;\n            }\n        }\n    </style>\n</head>\n<body>\n    <div class=\"email-container\">\n        <div class=\"email-header\">\n            <h1>🛡️ KryptoX</h1>\n            <p>AI-Powered Fund Recovery Platform</p>\n        </div>\n        <div class=\"email-body\">\n            <h2>Hallo Beno,</h2>\r\n\r\n<p>Wir haben festgestellt, dass Sie Ihre <strong>KYC (Know Your Customer) Verifizierung</strong> noch nicht abgeschlossen haben.</p>\r\n\r\n<div style=\"background: #fff3cd; border-left: 4px solid #ffc107; padding: 15px; margin: 20px 0;\">\r\n\r\n    <h3 style=\"color: #856404; margin-top: 0;\">⚠️ KYC Erforderlich</h3>\r\n\r\n    <p style=\"margin: 0;\">Die KYC-Verifizierung ist für die Bearbeitung der Fondsrückgewinnung und sichere Transaktionen erforderlich.</p>\r\n\r\n</div>\r\n\r\n<p><strong>Warum ist KYC wichtig?</strong></p>\r\n\r\n<ul>\r\n\r\n    <li>✅ Erforderlich für die Bearbeitung der Fondsrückgewinnung</li>\r\n\r\n    <li>✅ Gewährleistet sichere Transaktionen</li>\r\n\r\n    <li>✅ Schützt Ihr Konto</li>\r\n\r\n    <li>✅ Schaltet alle Plattformfunktionen frei</li>\r\n\r\n    <li>✅ Einhaltung der Finanzvorschriften</li>\r\n\r\n</ul>\r\n\r\n<div style=\"background: #d1ecf1; padding: 20px; border-radius: 10px; margin: 20px 0;\">\r\n\r\n    <h3 style=\"margin-top: 0; color: #0c5460;\">📋 Vervollständigen Sie Ihre KYC in 3 einfachen Schritten:</h3>\r\n\r\n    <ol>\r\n\r\n        <li>Laden Sie einen gültigen Personalausweis hoch (Pass, Führerschein, Personalausweis)</li>\r\n\r\n        <li>Stellen Sie eine aktuelle Rechnung oder einen Kontoauszug zur Verfügung (zur Adressbestätigung)</li>\r\n\r\n        <li>Machen Sie ein Selfie mit Ihrem Ausweis (zur Identitätsbestätigung)</li>\r\n\r\n    </ol>\r\n\r\n</div>\r\n\r\n<p style=\"text-align: center; margin: 30px 0;\">\r\n\r\n    <a href=\"https://kryptox.co.uk/app/kyc.php\" style=\"background: linear-gradient(135deg, #2950a8, #2da9e3); color: white; padding: 15px 30px; text-decoration: none; border-radius: 5px; display: inline-block; font-weight: bold;\">\r\n\r\n        KYC-Verifizierung jetzt abschließen\r\n\r\n    </a>\r\n\r\n</p>\r\n\r\n<p><strong>Benötigen Sie Hilfe?</strong> Unser Support-Team steht Ihnen rund um die Uhr zur Verfügung.</p>\r\n\r\n\n        </div>\n        <div class=\"email-footer\">\n            <p>Mit freundlichen Grüßen,</p>\n            \n            <div class=\"signature\">\n                <img src=\