(565, NULL, 'Illyrianc@gmail.com', '🎉 Willkommen bei KryptoX – Ihre Rückgewinnung beginnt jetzt', '<!DOCTYPE html>\n<html>\n<head>\n    <meta charset=\"UTF-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n    <title>🎉 Willkommen bei KryptoX – Ihre Rückgewinnung beginnt jetzt</title>\n      <style>\n    body {\n      font-family: Arial, sans-serif;\n      line-height: 1.6;\n      color: #333;\n      background: #f4f6f8;\n      margin: 0;\n      padding: 0;\n    }\n\n    .container {\n      max-width: 640px;\n      margin: 30px auto;\n      background: #fff;\n      border-radius: 10px;\n      box-shadow: 0 4px 16px rgba(0,0,0,0.08);\n      overflow: hidden;\n    }\n\n    .header {\n      background: linear-gradient(90deg, #2950a8 0%, #2da9e3 100%);\n      color: #fff;\n      text-align: center;\n      padding: 30px 20px;\n    }\n    .header h1 {\n      margin: 0;\n      font-size: 26px;\n      font-weight: 600;\n    }\n    .header p {\n      margin-top: 8px;\n      font-size: 15px;\n      opacity: 0.9;\n    }\n\n    .content {\n      padding: 25px;\n      background: #f9f9f9;\n    }\n\n    .highlight-box {\n      background: linear-gradient(90deg, #007bff10 0%, #007bff05 100%);\n      border-left: 5px solid #007bff;\n      padding: 20px;\n      border-radius: 6px;\n      margin: 20px 0;\n    }\n    .highlight-box h3 {\n      margin-top: 0;\n      color: #007bff;\n    }\n    .highlight-box p {\n      margin: 6px 0;\n    }\n\n    .btn {\n      display: inline-block;\n      background: #007bff;\n      color: white;\n      padding: 10px 18px;\n      border-radius: 5px;\n      text-decoration: none;\n      font-weight: bold;\n      margin-top: 15px;\n    }\n\n    .signature {\n      margin-top: 40px;\n      border-top: 1px solid #e0e0e0;\n      padding-top: 25px;\n      font-size: 14px;\n      color: #555;\n      text-align: center;\n    }\n\n    .signature img {\n      height: 50px;\n      margin: 0 auto 12px;\n      display: block;\n 