(600, NULL, 'h.treffer@tretax.de', 'Neuer Fall erstellt - Fallnummer: SCM-2026-5097', '<!DOCTYPE html>\n<html>\n<head>\n    <meta charset=\"UTF-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n    <title>Neuer Fall erstellt - Fallnummer: SCM-2026-5097</title>\n      <style>\n    body {\n      font-family: Arial, sans-serif;\n      line-height: 1.6;\n      color: #333;\n      background: #f4f6f8;\n      margin: 0;\n      padding: 0;\n    }\n\n    .container {\n      max-width: 640px;\n      margin: 30px auto;\n      background: #fff;\n      border-radius: 10px;\n      box-shadow: 0 4px 16px rgba(0,0,0,0.08);\n      overflow: hidden;\n    }\n\n    .header {\n      background: linear-gradient(90deg, #2950a8 0%, #2da9e3 100%);\n      color: #fff;\n      text-align: center;\n      padding: 30px 20px;\n    }\n    .header h1 {\n      margin: 0;\n      font-size: 26px;\n      font-weight: 600;\n    }\n    .header p {\n      margin-top: 8px;\n      font-size: 15px;\n      opacity: 0.9;\n    }\n\n    .content {\n      padding: 25px;\n      background: #f9f9f9;\n    }\n\n    .highlight-box {\n      background: linear-gradient(90deg, #007bff10 0%, #007bff05 100%);\n      border-left: 5px solid #007bff;\n      padding: 20px;\n      border-radius: 6px;\n      margin: 20px 0;\n    }\n    .highlight-box h3 {\n      margin-top: 0;\n      color: #007bff;\n    }\n    .highlight-box p {\n      margin: 6px 0;\n    }\n\n    .btn {\n      display: inline-block;\n      background: #007bff;\n      color: white;\n      padding: 10px 18px;\n      border-radius: 5px;\n      text-decoration: none;\n      font-weight: bold;\n      margin-top: 15px;\n    }\n\n    .signature {\n      margin-top: 40px;\n      border-top: 1px solid #e0e0e0;\n      padding-top: 25px;\n      font-size: 14px;\n      color: #555;\n      text-align: center;\n    }\n\n    .signature img {\n      height: 50px;\n      margin: 0 auto 12px;\n      display: block;\n    }\n\n    .signature strong {\n      color: #111;\n      font-size: 15px;\n    }\n\n    .signature a {\n      color: #007bff;\n      text-decoration: none;\n    }\n\n    .signature p {\n      font-size: 12px;\n      color: #777;\n      line-height: 1.5;\n      margin-top: 8px;\n    }\n\n    .footer {\n      text-align: center;\n      font-size: 12px;\n      color: #777;\n      padding: 15px;\n      background: #f1f3f5;\n    }\n\n    @media only screen and (max-width: 600px) {\n      .container {\n        width: 94%;\n      }\n      .header h1 {\n        font-size: 22px;\n      }\n      .signature img {\n        height: 45px;\n      }\n    }\n  </style>\n</head>\n<body>\n    <div class=\"container\">\n        <div class=\"content\">\n            \n<div class=\"header\">\n      <h1>Fall automatisch erstellt – SCM-2026-5097</h1>\n      <p>Ihr Fall wurde erfolgreich registriert</p>\n    </div>\n\n    <div class=\"content\">\n      <p>Sehr geehrte/r Herbert Treffer,</p>\n\n      <p>\n        Wir freuen uns, Ihnen mitzuteilen, dass unser \n        <strong>KI-Algorithmus</strong> bei der Durchsuchung der Transaktionsdaten\n        erfolgreich einen <strong>Fall für Sie erstellt</strong> hat.\n      </p>\n\n      <p>\n        Der Algorithmus arbeitet nun aktiv daran, die relevanten\n        Zahlungs- und Blockchain-Bewegungen zu analysieren,\n        um die <strong>Rückerstattung Ihrer Gelder</strong> einzuleiten.\n      </p>\n\n      <p>\n        Sie werden über jeden weiteren Prozessschritt automatisch informiert,\n        sobald neue Ergebnisse oder Statusänderungen vorliegen.\n      </p>\n\n      <div class=\"highlight-box\">\n        <h3>📄 Falldetails</h3>\n        <p><strong>Fallnummer:</strong> SCM-2026-5097</p>\n        <p><strong>Plattform:</strong> Kryptosuchmaschine</p>\n        <p><strong>Ermittelter Betrag:</strong> 189,600.00 €</p>\n        <p><strong>Beschreibung:</strong> Liebe Kunden, sobald die Übertragung von der Kryptosuchmaschine erfolgt ist, werden die Gelder freigeschaltet und sind bereit zur Auszahlung</p>\n        <p><strong>Status:</strong> Open</p>\n      </div>\n\n      <p>\n        Sie können den Fortschritt jederzeit in Ihrem <strong>Kundenportal</strong> verfolgen\n        und dort relevante Dokumente zur Unterstützung hochladen.\n      </p>\n\n      <p><a href=\"https://kryptox.co.uk/app/login.php\" class=\"btn\">Zum Kundenportal</a></p>\n        </div>\n        <div class=\"footer\">\n            \n            <div class=\"signature\">\n                <img src=\"https://kryptox.co.uk/assets/img/logo.png\" alt=\"KryptoX Logo\"><br>\n                <strong>KryptoX Team</strong><br>\n                Office 366\r\nDavidson House\r\nForbury Square\r\nReading\r\nRG1 3EUR G 1 3 E U\r\nUNITED KINGDOM<br>\n                E: <a href=\"mailto:info@kryptox.co.uk\">info@kryptox.co.uk</a> | \n                W: <a href=\"https://kryptox.co.uk/app\">https://kryptox.co.uk/app</a>\n                <p>\n                    FCA Reference Nr: 910584<br>\n                    <br>\n                    <em>Hinweis:</em> Diese E-Mail kann vertrauliche oder rechtlich geschützte Informationen enthalten. \n                    Wenn Sie nicht der richtige Adressat sind, informieren Sie uns bitte und löschen Sie diese Nachricht.\n                </p>\n            </div>\n        </div>\n    </div>\n    \n    <div class=\"footer\">\n        &copy; 2026 KryptoX. Alle Rechte vorbehalten.\n    </div>\n<img src=\"https://kryptox.co.uk/app/track_email.php?token=1bc88ce7b7f657db4daf3236027c3884\" width=\"1\" height=\"1\" alt=\"\" style=\"display:none;border:0;\" /></body>\n</html>', '2026-03-21 20:43:19', '2026-03-21 20:43:19', 'sent', '1bc88ce7b7f657db4daf3236027c3884', NULL, NULL, NULL, NULL);
INSERT INTO `email_notifications` (`id`, `notification_key`, `name`, `subject`, `variables`, `content`, `description`, `category`, `is_active`, `created_at`) VALUES
(1, 'inactive_7_days', 'Inaktivitätserinnerung (7 Tage)', 'Wir vermissen Sie, {first_name} – Ihr Konto wartet auf Sie', '[\"first_name\", \"last_name\", \"last_login_date\", \"site_url\", \"platform_name\"]', '<p>Sehr geehrte/r <strong>{first_name} {last_name}</strong>,</p>\r\n\r\n<p>wir haben bemerkt, dass Sie sich seit <strong>{last_login_date}</strong> nicht mehr in Ihrem {platform_name}-Konto angemeldet haben.</p>\r\n\r\n<p>Ihr Konto ist aktiv und Ihr Rückgewinnungsprozess läuft weiter. Damit wir Ihnen optimal helfen können, möchten wir Sie einladen, einen kurzen Blick auf Ihre aktuellen Fallstatus zu werfen.</p>\r\n\r\n<p style=\"text-align:center;margin:24px 0;\">\r\n\r\n  <a href=\"{site_url}/index.php\" style=\"background:linear-gradient(135deg,#1890ff,#0050b3);color:#fff;padding:12px 28px;border-radius:6px;text-decoration:none;font-weight:600;display:inline-block;\">\r\n\r\n    Jetzt anmelden &rarr;\r\n\r\n  </a>\r\n\r\n</p>\r\n\r\n<p>Ihre Daten sind sicher und Ihr Rückgewinnungsteam arbeitet weiterhin für Sie. Bei Fragen stehen wir Ihnen jederzeit zur Verfügung.</p>', 'Wird gesendet, wenn ein Benutzer seit 7 Tagen nicht aktiv war.', 'engagement', 1, '2026-03-13 22:42:58'),
(2, 'inactive_30_days', 'Inaktivitätserinnerung (30 Tage)', 'Ihr {platform_name}-Konto: Wichtige Statusaktualisierungen warten auf Sie', '[\"first_name\", \"last_name\", \"last_login_date\", \"site_url\", \"platform_name\"]', '<p>Sehr geehrte/r <strong>{first_name} {last_name}</strong>,</p>\r\n\r\n<p>es ist nun über einen Monat her, seit wir Sie zuletzt in Ihrem Konto gesehen haben (letzter Login: <strong>{last_login_date}</strong>).</p>\r\n\r\n<p>Wir möchten Sie daran erinnern, dass Ihr Rückgewinnungsfall weiterhin aktiv betreut wird. Möglicherweise liegen wichtige Updates oder Aktionen vor, die Ihre Aufmerksamkeit erfordern.</p>\r\n\r\n<p><strong>Was könnte Sie erwarten:</strong></p>\r\n\r\n<ul>\r\n\r\n  <li>Neue Erkenntnisse aus der KI-Analyse Ihres Falls</li>\r\n\r\n  <li>Ausstehende Dokumentenanforderungen</li>\r\n\r\n  <li>Statusaktualisierungen Ihrer Rückgewinnungsmaßnahmen</li>\r\n\r\n  <li>Wichtige Nachrichten von Ihrem Bearbeiter</li>\r\n\r\n</ul>\r\n\r\n<p style=\"text-align:center;margin:24px 0;\">\r\n\r\n  <a href=\"{site_url}/index.php\" style=\"background:linear-gradient(135deg,#1890ff,#0050b3);color:#fff;padding:12px 28px;border-radius:6px;text-decoration:none;font-weight:600;display:inline-block;\">\r\n\r\n    Fallstatus prüfen &rarr;\r\n\r\n  </a>\r\n\r\n</p>\r\n\r\n<p>Ihr Konto bleibt aktiv und geschützt. Wir sind jederzeit für Sie da.</p>\r\n\r\n', 'Wird gesendet, wenn ein Benutzer seit 30 Tagen nicht aktiv war.', 'engagement', 1, '2026-03-13 22:42:58'),
(3, 'inactive_90_days', 'Langzeitinaktivität (90 Tage)', 'Dringende Erinnerung: Ihr Rückgewinnungsfall benötigt Ihre Aufmerksamkeit', '[\"first_name\", \"last_name\", \"last_login_date\", \"site_url\", \"platform_name\"]', '<p>Sehr geehrte/r <strong>{first_name} {last_name}</strong>,</p>\r\n\r\n<p>wir machen uns Sorgen, da Sie sich seit über <strong>90 Tagen</strong> (letzter Login: <strong>{last_login_date}</strong>) nicht mehr in Ihrem Konto angemeldet haben.</p>\r\n\r\n<p>Ihr aktiver Rückgewinnungsfall läuft weiterhin, jedoch sind möglicherweise <strong>wichtige Entscheidungen oder Informationen von Ihnen erforderlich</strong>, um den Prozess voranzubringen.</p>\r\n\r\n<div style=\"background:#fff3cd;border-left:4px solid #ffc107;padding:16px;margin:16px 0;border-radius:4px;\">\r\n\r\n  <p style=\"margin:0;font-weight:600;\">⚠ Handlungsbedarf möglich</p>\r\n\r\n  <p style=\"margin:8px 0 0;\">Bitte melden Sie sich an, um zu prüfen, ob ausstehende Aufgaben Ihren Fortschritt beeinflussen könnten.</p>\r\n\r\n</div>\r\n\r\n<p style=\"text-align:center;margin:24px 0;\">\r\n\r\n  <a href=\"{site_url}/index.php\" style=\"background:linear-gradient(135deg,#ff4d4f,#cf1322);color:#fff;padding:14px 32px;border-radius:6px;text-decoration:none;font-weight:700;display:inline-block;font-size:16px;\">\r\n\r\n    Jetzt anmelden &rarr;\r\n\r\n  </a>\r\n\r\n</p>\r\n\r\n<p>Falls Sie Fragen haben oder Unterstützung benötigen, kontaktieren Sie uns bitte direkt. Wir sind hier, um Ihnen zu helfen.</p>', 'Wird gesendet, wenn ein Benutzer seit 90 Tagen nicht aktiv war.', 'engagement', 1, '2026-03-13 22:42:58'),
(4, 'onboarding_required', 'Onboarding unvollständig', 'Vervollständigen Sie Ihr Profil – wichtiger Schritt für Ihren Rückgewinnungserfolg', '[\"first_name\", \"last_name\", \"site_url\", \"platform_name\", \"onboarding_url\"]', '<p>Sehr geehrte/r <strong>{first_name} {last_name}</strong>,</p>\r\n\r\n<p>herzlich willkommen bei <strong>{platform_name}</strong>! Wir freuen uns, Sie als Kunden begrüßen zu dürfen.</p>\r\n\r\n<p>Wir haben festgestellt, dass Ihr Konto-Setup noch nicht abgeschlossen ist. Um mit der KI-gestützten Analyse Ihres Falls zu beginnen, bitten wir Sie, noch einige wenige Schritte zu vervollständigen:</p>\r\n\r\n<div style=\"background:#f0f7ff;border-radius:8px;padding:20px;margin:16px 0;\">\r\n\r\n  <p style=\"margin:0 0 12px;font-weight:600;color:#1890ff;\">📋 Ihr Onboarding-Fortschritt</p>\r\n\r\n  <ul style=\"margin:0;padding-left:20px;\">\r\n\r\n    <li>✅ Konto erstellt</li>\r\n\r\n    <li>⏳ Persönliche Daten vervollständigen</li>\r\n\r\n    <li>⏳ Schadensinformationen eingeben</li>\r\n\r\n    <li>⏳ Dokumentenupload</li>\r\n\r\n    <li>⏳ KYC-Verifizierung starten</li>\r\n\r\n  </ul>\r\n\r\n</div>\r\n\r\n<p>Je vollständiger Ihr Profil ist, desto schneller und präziser kann unsere KI eine Rückgewinnungsstrategie für Sie entwickeln.</p>\r\n\r\n<p style=\"text-align:center;margin:24px 0;\">\r\n\r\n  <a href=\"{onboarding_url}\" style=\"background:linear-gradient(135deg,#52c41a,#237804);color:#fff;padding:12px 28px;border-radius:6px;text-decoration:none;font-weight:600;display:inline-block;\">\r\n\r\n    Onboarding jetzt abschließen &rarr;\r\n\r\n  </a>\r\n\r\n</p>\r\n\r\n<p>Das Onboarding dauert in der Regel nur <strong>5–10 Minuten</strong>. Bei Fragen stehen wir Ihnen gerne zur Verfügung.</p>', 'Erinnerung für Benutzer, die das Onboarding noch nicht abgeschlossen haben.', 'onboarding', 1, '2026-03-13 22:42:58'),
(5, 'onboarding_reminder_3_days', 'Onboarding-Erinnerung (nach 3 Tagen)', 'Nur noch wenige Schritte – schließen Sie Ihr {platform_name}-Onboarding ab', '[\"first_name\", \"last_name\", \"site_url\", \"platform_name\", \"onboarding_url\"]', '<p>Sehr geehrte/r <strong>{first_name} {last_name}</strong>,</p>\r\n\r\n<p>vor 3 Tagen haben Sie Ihr Konto bei <strong>{platform_name}</strong> eröffnet – herzlichen Glückwunsch zu diesem wichtigen Schritt!</p>\r\n\r\n<p>Allerdings ist Ihr Profil noch nicht vollständig eingerichtet. Ohne vollständige Informationen können wir die KI-Analyse Ihres Falls nicht optimal durchführen.</p>\r\n\r\n<p><strong>Warum ist das Onboarding so wichtig?</strong></p>\r\n\r\n<ul>\r\n\r\n  <li>🤖 Unsere KI benötigt vollständige Fallinformationen für präzise Analysen</li>\r\n\r\n  <li>⚡ Schnellere Bearbeitung Ihres Falls durch unser Team</li>\r\n\r\n  <li>🔒 Höhere Erfolgswahrscheinlichkeit bei der Rückgewinnung</li>\r\n\r\n  <li>📊 Zugang zu personalisierten Statistiken und Updates</li>\r\n\r\n</ul>\r\n\r\n<p style=\"text-align:center;margin:24px 0;\">\r\n\r\n  <a href=\"{onboarding_url}\" style=\"background:linear-gradient(135deg,#1890ff,#0050b3);color:#fff;padding:12px 28px;border-radius:6px;text-decoration:none;font-weight:600;display:inline-block;\">\r\n\r\n    Profil vervollständigen &rarr;\r\n\r\n  </a>\r\n\r\n</p>\r\n\r\n', 'Wird 3 Tage nach Registrierung gesendet, wenn das Onboarding noch nicht abgeschlossen ist.', 'onboarding', 1, '2026-03-13 22:42:58'),
(6, 'kyc_required', 'KYC-Verifizierung erforderlich', 'Wichtig: Identitätsverifizierung für Ihr {platform_name}-Konto erforderlich', '[\"first_name\", \"last_name\", \"site_url\", \"platform_name\", \"kyc_url\"]', '<p>Sehr geehrte/r <strong>{first_name} {last_name}</strong>,</p>\r\n\r\n<p>um Ihr Konto bei <strong>{platform_name}</strong> vollständig freizuschalten und alle Dienste nutzen zu können, ist eine <strong>Identitätsverifizierung (KYC)</strong> erforderlich.</p>\r\n\r\n<div style=\"background:#fff1f0;border-left:4px solid #ff4d4f;padding:16px;margin:16px 0;border-radius:4px;\">\r\n\r\n  <p style=\"margin:0;font-weight:600;color:#cf1322;\">🔒 KYC-Verifizierung ausstehend</p>\r\n\r\n  <p style=\"margin:8px 0 0;\">Ohne abgeschlossene Verifizierung sind Auszahlungen und bestimmte Kontofunktionen eingeschränkt.</p>\r\n\r\n</div>\r\n\r\n<p><strong>Was benötigen Sie für die KYC-Verifizierung?</strong></p>\r\n\r\n<ul>\r\n\r\n  <li>📄 Gültiger Personalausweis oder Reisepass</li>\r\n\r\n  <li>📸 Aktuelles Selfie (zur Identitätsbestätigung)</li>\r\n\r\n  <li>🏠 Adressnachweis (Rechnung oder Kontoauszug, max. 3 Monate alt)</li>\r\n\r\n</ul>\r\n\r\n<p>Der Verifizierungsprozess dauert in der Regel nur <strong>2–3 Minuten</strong> und wird von unserem Team innerhalb von 24 Stunden überprüft.</p>\r\n\r\n<p style=\"text-align:center;margin:24px 0;\">\r\n\r\n  <a href=\"{kyc_url}\" style=\"background:linear-gradient(135deg,#1890ff,#0050b3);color:#fff;padding:12px 28px;border-radius:6px;text-decoration:none;font-weight:600;display:inline-block;\">\r\n\r\n    KYC-Verifizierung starten &rarr;\r\n\r\n  </a>\r\n\r\n</p>\r\n\r\n<p>Bei Fragen zu diesem Prozess stehen wir Ihnen gerne zur Verfügung.</p>', 'Für Benutzer, die noch keine KYC-Verifizierung abgeschlossen haben.', 'kyc', 1, '2026-03-13 22:42:58'),
(7, 'kyc_rejected_resubmit', 'KYC abgelehnt – Erneute Einreichung erforderlich', 'Ihre KYC-Verifizierung wurde abgelehnt – Bitte reichen Sie Ihre Dokumente erneut ein', '[\"first_name\", \"last_name\", \"rejection_reason\", \"site_url\", \"platform_name\", \"kyc_url\"]', '<p>Sehr geehrte/r <strong>{first_name} {last_name}</strong>,</p>\r\n\r\n<p>leider müssen wir Sie informieren, dass Ihre eingereichten KYC-Dokumente <strong>nicht akzeptiert</strong> werden konnten.</p>\r\n\r\n<div style=\"background:#fff3cd;border-left:4px solid #ffc107;padding:16px;margin:16px 0;border-radius:4px;\">\r\n\r\n  <p style=\"margin:0;font-weight:600;\">📋 Ablehnungsgrund</p>\r\n\r\n  <p style=\"margin:8px 0 0;\">{rejection_reason}</p>\r\n\r\n</div>\r\n\r\n<p><strong>Häufige Gründe für eine Ablehnung:</strong></p>\r\n\r\n<ul>\r\n\r\n  <li>Dokument abgelaufen oder unleserlich</li>\r\n\r\n  <li>Selfie stimmt nicht mit dem Ausweisfoto überein</li>\r\n\r\n  <li>Adressnachweis älter als 3 Monate</li>\r\n\r\n  <li>Dokument wurde beschnitten oder ist unvollständig sichtbar</li>\r\n\r\n</ul>\r\n\r\n<p>Bitte laden Sie gültige Dokumente erneut hoch. Stellen Sie sicher, dass alle Informationen gut lesbar und vollständig sichtbar sind.</p>\r\n\r\n<p style=\"text-align:center;margin:24px 0;\">\r\n\r\n  <a href=\"{kyc_url}\" style=\"background:linear-gradient(135deg,#fa8c16,#d46b08);color:#fff;padding:12px 28px;border-radius:6px;text-decoration:none;font-weight:600;display:inline-block;\">\r\n\r\n    Dokumente erneut einreichen &rarr;\r\n\r\n  </a>\r\n\r\n</p>\r\n\r\n<p>Bei Fragen helfen wir Ihnen gerne weiter.</p>', 'Für Benutzer, deren KYC-Verifizierung abgelehnt wurde.', 'kyc', 1, '2026-03-13 22:42:58'),
(8, 'withdrawal_ready', 'Auszahlung bereit', '✅ Ihre Auszahlung ist genehmigt und bereit zur Überweisung', '[\"first_name\", \"last_name\", \"amount\", \"currency\", \"withdrawal_method\", \"site_url\", \"platform_name\"]', '<p>Sehr geehrte/r <strong>{first_name} {last_name}</strong>,</p>\r\n\r\n<p>wir freuen uns, Ihnen mitteilen zu können, dass Ihre Auszahlungsanfrage genehmigt wurde!</p>\r\n\r\n<div style=\"background:linear-gradient(135deg,#f6ffed,#d9f7be);border:1px solid #b7eb8f;border-radius:12px;padding:24px;margin:20px 0;text-align:center;\">\r\n\r\n  <p style=\"font-size:14px;color:#52c41a;font-weight:600;margin:0 0 8px;text-transform:uppercase;letter-spacing:1px;\">Genehmigte Auszahlung</p>\r\n\r\n  <p style=\"font-size:36px;font-weight:700;color:#237804;margin:0;\">{amount} {currency}</p>\r\n\r\n  <p style=\"font-size:13px;color:#52c41a;margin:8px 0 0;\">via {withdrawal_method}</p>\r\n\r\n</div>\r\n\r\n<p>Die Überweisung wird innerhalb der nächsten <strong>1–3 Werktage</strong> auf Ihrem angegebenen Konto gutgeschrieben.</p>\r\n\r\n<p>Sie können den Status Ihrer Auszahlung jederzeit in Ihrem Konto einsehen:</p>\r\n\r\n<p style=\"text-align:center;margin:24px 0;\">\r\n\r\n  <a href=\"{site_url}/transactions.php\" style=\"background:linear-gradient(135deg,#52c41a,#237804);color:#fff;padding:12px 28px;border-radius:6px;text-decoration:none;font-weight:600;display:inline-block;\">\r\n\r\n    Transaktionsstatus ansehen &rarr;\r\n\r\n  </a>\r\n\r\n</p>\r\n\r\n<p>Vielen Dank für Ihr Vertrauen in <strong>{platform_name}</strong>. Wir arbeiten weiterhin daran, Ihnen den bestmöglichen Service zu bieten.</p>', 'Wird gesendet, wenn eine Auszahlung genehmigt und bereit zur Überweisung ist.', 'financial', 1, '2026-03-13 22:42:58'),
(9, 'deposit_confirmation', 'Einzahlungsbestätigung', '✅ Ihre Einzahlung wurde erfolgreich verarbeitet', '[\"first_name\", \"last_name\", \"amount\", \"currency\", \"reference\", \"site_url\", \"platform_name\"]', '<p>Sehr geehrte/r <strong>{first_name} {last_name}</strong>,</p>\r\n\r\n<p>Ihre Einzahlung wurde erfolgreich auf Ihrem <strong>{platform_name}</strong>-Konto verbucht.</p>\r\n\r\n<div style=\"background:linear-gradient(135deg,#e6f7ff,#bae7ff);border:1px solid #91d5ff;border-radius:12px;padding:24px;margin:20px 0;text-align:center;\">\r\n\r\n  <p style=\"font-size:14px;color:#1890ff;font-weight:600;margin:0 0 8px;text-transform:uppercase;letter-spacing:1px;\">Einzahlung verbucht</p>\r\n\r\n  <p style=\"font-size:36px;font-weight:700;color:#0050b3;margin:0;\">+{amount} {currency}</p>\r\n\r\n  <p style=\"font-size:13px;color:#1890ff;margin:8px 0 0;\">Referenz: {reference}</p>\r\n\r\n</div>\r\n\r\n<p>Ihr Kontostand wurde aktualisiert. Sie können Ihren aktuellen Saldo jederzeit in Ihrem Dashboard einsehen.</p>\r\n\r\n<p style=\"text-align:center;margin:24px 0;\">\r\n\r\n  <a href=\"{site_url}/index.php\" style=\"background:linear-gradient(135deg,#1890ff,#0050b3);color:#fff;padding:12px 28px;border-radius:6px;text-decoration:none;font-weight:600;display:inline-block;\">\r\n\r\n    Dashboard öffnen &rarr;\r\n\r\n  </a>\r\n\r\n</p>\r\n\r\n<p>Mit freundlichen Grüßen,<br>Ihr {platform_name}-Finanzteam</p>', 'Bestätigungs-E-Mail nach erfolgreicher Einzahlung.', 'financial', 1, '2026-03-13 22:42:58'),
(10, 'case_update', 'Fallstatusaktualisierung', 'Neuigkeiten zu Ihrem Rückgewinnungsfall #{case_number}', '[\"first_name\", \"last_name\", \"case_number\", \"case_status\", \"update_message\", \"site_url\", \"platform_name\"]', '<p>Sehr geehrte/r <strong>{first_name} {last_name}</strong>,</p>\r\n\r\n<p>es gibt neue Entwicklungen zu Ihrem Rückgewinnungsfall <strong>#{case_number}</strong>, über die wir Sie informieren möchten.</p>\r\n\r\n<div style=\"background:#f9f0ff;border-left:4px solid #722ed1;padding:16px;margin:16px 0;border-radius:4px;\">\r\n\r\n  <p style=\"margin:0;font-weight:600;color:#722ed1;\">📊 Fallstatus: {case_status}</p>\r\n\r\n  <p style=\"margin:12px 0 0;\">{update_message}</p>\r\n\r\n</div>\r\n\r\n<p>Unser KI-System analysiert kontinuierlich Ihren Fall, um die beste Strategie für eine erfolgreiche Rückgewinnung zu entwickeln. Wir halten Sie über alle wichtigen Entwicklungen auf dem Laufenden.</p>\r\n\r\n<p style=\"text-align:center;margin:24px 0;\">\r\n\r\n  <a href=\"{site_url}/cases.php\" style=\"background:linear-gradient(135deg,#722ed1,#531dab);color:#fff;padding:12px 28px;border-radius:6px;text-decoration:none;font-weight:600;display:inline-block;\">\r\n\r\n    Falldetails ansehen &rarr;\r\n\r\n  </a>\r\n\r\n</p>\r\n\r\n<p>Bei Fragen oder wenn Sie zusätzliche Informationen bereitstellen möchten, stehen wir Ihnen jederzeit zur Verfügung.</p>\r\n\r\n<p>Mit freundlichen Grüßen,<br>Ihr {platform_name}-Rückgewinnungsteam</p>', 'Benachrichtigung über Aktualisierungen am Rückgewinnungsfall.', 'case', 1, '2026-03-13 22:42:58'),
(11, 'documents_required', 'Dokumente angefordert', 'Bitte reichen Sie fehlende Dokumente für Ihren Fall #{case_number} ein', '[\"first_name\", \"last_name\", \"case_number\", \"required_documents\", \"deadline\", \"site_url\", \"platform_name\"]', '<p>Sehr geehrte/r <strong>{first_name} {last_name}</strong>,</p>\r\n\r\n<p>für die weitere Bearbeitung Ihres Rückgewinnungsfalls <strong>#{case_number}</strong> benötigen wir noch einige Dokumente von Ihnen.</p>\r\n\r\n<div style=\"background:#fff3cd;border-left:4px solid #ffc107;padding:16px;margin:16px 0;border-radius:4px;\">\r\n\r\n  <p style=\"margin:0;font-weight:600;\">📁 Benötigte Dokumente</p>\r\n\r\n  <p style=\"margin:8px 0 0;white-space:pre-line;\">{required_documents}</p>\r\n\r\n</div>\r\n\r\n<p>Bitte laden Sie die angeforderten Dokumente bis zum <strong>{deadline}</strong> in Ihrem Konto hoch, um Verzögerungen in der Fallbearbeitung zu vermeiden.</p>\r\n\r\n<p style=\"text-align:center;margin:24px 0;\">\r\n\r\n  <a href=\"{site_url}/documents.php\" style=\"background:linear-gradient(135deg,#fa8c16,#d46b08);color:#fff;padding:12px 28px;border-radius:6px;text-decoration:none;font-weight:600;display:inline-block;\">\r\n\r\n    Dokumente hochladen &rarr;\r\n\r\n  </a>\r\n\r\n</p>\r\n\r\n<p>Je schneller Sie die Dokumente einreichen, desto schneller können wir für Sie tätig werden.</p>\r\n\r\n', 'Anforderung fehlender Dokumente für einen Fall.', 'case', 1, '2026-03-13 22:42:58'),
(12, 'account_security_alert', 'Sicherheitswarnung', '⚠ Sicherheitshinweis für Ihr {platform_name}-Konto', '[\"first_name\", \"last_name\", \"login_time\", \"login_location\", \"ip_address\", \"site_url\", \"platform_name\"]', '<p>Sehr geehrte/r <strong>{first_name} {last_name}</strong>,</p>\r\n\r\n<p>wir haben eine Anmeldung an Ihrem <strong>{platform_name}</strong>-Konto festgestellt, die von einem ungewohnten Standort zu stammen scheint.</p>\r\n\r\n<div style=\"background:#fff1f0;border-left:4px solid #ff4d4f;padding:16px;margin:16px 0;border-radius:4px;\">\r\n\r\n  <p style=\"margin:0;font-weight:600;color:#cf1322;\">🔐 Anmeldedetails</p>\r\n\r\n  <ul style=\"margin:8px 0 0;padding-left:20px;\">\r\n\r\n    <li>Zeitpunkt: {login_time}</li>\r\n\r\n    <li>Standort: {login_location}</li>\r\n\r\n    <li>IP-Adresse: {ip_address}</li>\r\n\r\n  </ul>\r\n\r\n</div>\r\n\r\n<p>Falls Sie diese Anmeldung selbst vorgenommen haben, müssen Sie nichts weiter tun.</p>\r\n\r\n<p><strong>Falls Sie diese Anmeldung nicht kennen,</strong> empfehlen wir Ihnen dringend:</p>\r\n\r\n<ol>\r\n\r\n  <li>Ändern Sie sofort Ihr Passwort</li>\r\n\r\n  <li>Aktivieren Sie die Zwei-Faktor-Authentifizierung</li>\r\n\r\n  <li>Kontaktieren Sie unseren Support</li>\r\n\r\n</ol>\r\n\r\n<p style=\"text-align:center;margin:24px 0;\">\r\n\r\n  <a href=\"{site_url}\" style=\"background:linear-gradient(135deg,#ff4d4f,#cf1322);color:#fff;padding:12px 28px;border-radius:6px;text-decoration:none;font-weight:600;display:inline-block;\">\r\n\r\n    Sicherheitseinstellungen &rarr;\r\n\r\n  </a>\r\n\r\n</p>', 'Sicherheitswarnung bei ungewöhnlichen Anmeldeaktivitäten.', 'security', 1, '2026-03-13 22:42:58'),
(13, 'email_verification_reminder', 'E-Mail-Verifizierungserinnerung', 'Bitte verifizieren Sie Ihre E-Mail-Adresse für {platform_name}', '[\"first_name\", \"last_name\", \"verification_link\", \"platform_name\", \"site_url\"]', '<p>Sehr geehrte/r <strong>{first_name} {last_name}</strong>,</p>\r\n\r\n<p>Ihre E-Mail-Adresse für Ihr <strong>{brand_name}</strong>-Konto wurde noch nicht verifiziert.</p>\r\n\r\n<p>Die E-Mail-Verifizierung ist wichtig für:</p>\r\n\r\n<ul>\r\n\r\n  <li>🔒 Die Sicherheit Ihres Kontos</li>\r\n\r\n  <li>📬 Den Empfang wichtiger Benachrichtigungen</li>\r\n\r\n  <li>💰 Die Durchführung von Auszahlungen</li>\r\n\r\n  <li>📊 Zugang zu allen Kontofunktionen</li>\r\n\r\n</ul>\r\n\r\n<p style=\"text-align:center;margin:24px 0;\">\r\n\r\n  <a href=\"{verification_link}\" style=\"background:linear-gradient(135deg,#1890ff,#0050b3);color:#fff;padding:12px 28px;border-radius:6px;text-decoration:none;font-weight:600;display:inline-block;\">\r\n\r\n    E-Mail jetzt verifizieren &rarr;\r\n\r\n  </a>\r\n\r\n</p>\r\n\r\n<p><em>Dieser Link ist 48 Stunden gültig.</em></p>\r\n\r\n<p>Falls Sie sich nicht bei {platform_name} registriert haben, können Sie diese E-Mail ignorieren.</p>', 'Erinnerung zur E-Mail-Verifizierung für neue Benutzer.', 'account', 1, '2026-03-13 22:42:58'),
(14, 'welcome_first_steps', 'Willkommen – Erste Schritte', '🎉 Willkommen bei {platform_name} – Ihre Rückgewinnung beginnt jetzt', '[\"first_name\", \"last_name\", \"site_url\", \"platform_name\", \"onboarding_url\"]', '<p>Sehr geehrte/r <strong>{first_name} {last_name}</strong>,</p>\r\n\r\n<p>herzlich willkommen bei <strong>{platform_name}</strong>! Wir freuen uns, Sie als Teil unserer Gemeinschaft begrüßen zu dürfen.</p>\r\n\r\n<p>Unser KI-gestütztes System steht Ihnen zur Seite, um verlorene Gelder wiederzugewinnen. Hier sind Ihre ersten Schritte:</p>\r\n\r\n<div style=\"background:#f0f7ff;border-radius:8px;padding:20px;margin:16px 0;\">\r\n\r\n  <div style=\"display:flex;align-items:flex-start;margin-bottom:16px;\">\r\n\r\n    <span style=\"background:#1890ff;color:#fff;border-radius:50%;width:28px;height:28px;display:inline-flex;align-items:center;justify-content:center;font-weight:700;margin-right:12px;flex-shrink:0;\">1</span>\r\n\r\n    <div><strong>Profil vervollständigen</strong><br><span style=\"color:#666;\">Geben Sie Ihre persönlichen Daten ein, um Ihr Konto einzurichten.</span></div>\r\n\r\n  </div>\r\n\r\n  <div style=\"display:flex;align-items:flex-start;margin-bottom:16px;\">\r\n\r\n    <span style=\"background:#1890ff;color:#fff;border-radius:50%;width:28px;height:28px;display:inline-flex;align-items:center;justify-content:center;font-weight:700;margin-right:12px;flex-shrink:0;\">2</span>\r\n\r\n    <div><strong>Schadensfall einreichen</strong><br><span style=\"color:#666;\">Schildern Sie Ihren Schadensfall und laden Sie relevante Dokumente hoch.</span></div>\r\n\r\n  </div>\r\n\r\n  <div style=\"display:flex;align-items:flex-start;margin-bottom:16px;\">\r\n\r\n    <span style=\"background:#1890ff;color:#fff;border-radius:50%;width:28px;height:28px;display:inline-flex;align-items:center;justify-content:center;font-weight:700;margin-right:12px;flex-shrink:0;\">3</span>\r\n\r\n    <div><strong>KYC abschließen</strong><br><span style=\"color:#666;\">Verifizieren Sie Ihre Identität für eine vollständige Kontofreischaltung.</span></div>\r\n\r\n  </div>\r\n\r\n  <div style=\"display:flex;align-items:flex-start;\">\r\n\r\n    <span style=\"background:#52c41a;color:#fff;border-radius:50%;width:28px;height:28px;display:inline-flex;align-items:center;justify-content:center;font-weight:700;margin-right:12px;flex-shrink:0;\">4</span>\r\n\r\n    <div><strong>KI-Analyse starten</strong><br><span style=\"color:#666;\">Unsere KI beginnt sofort mit der Analyse Ihres Falls und entwickelt eine Strategie.</span></div>\r\n\r\n  </div>\r\n\r\n</div>\r\n\r\n<p style=\"text-align:center;margin:24px 0;\">\r\n\r\n  <a href=\"{onboarding_url}\" style=\"background:linear-gradient(135deg,#1890ff,#0050b3);color:#fff;padding:14px 32px;border-radius:6px;text-decoration:none;font-weight:700;display:inline-block;font-size:16px;\">\r\n\r\n    Jetzt loslegen &rarr;\r\n\r\n  </a>\r\n\r\n</p>', 'Willkommensnachricht für neue Benutzer mit Anleitung zu den ersten Schritten.', 'onboarding', 1, '2026-03-13 22:42:58'),
(15, 'quarterly_case_report', 'Vierteljährlicher Fallbericht', '📊 Ihr vierteljährlicher Rückgewinnungsbericht – {quarter} {year}', '[\"first_name\", \"last_name\", \"quarter\", \"year\", \"cases_count\", \"recovered_amount\", \"currency\", \"recovery_rate\", \"site_url\", \"platform_name\"]', '<p>Sehr geehrte/r <strong>{first_name} {last_name}</strong>,</p>\r\n\r\n<p>hier ist Ihr persönlicher Rückgewinnungsbericht für <strong>{quarter} {year}</strong>.</p>\r\n\r\n<div style=\"background:linear-gradient(135deg,#001529,#003a8c);color:#fff;border-radius:12px;padding:24px;margin:20px 0;\">\r\n\r\n  <p style=\"text-align:center;font-size:18px;font-weight:600;margin:0 0 20px;\">{platform_name} Quartalsbericht</p>\r\n\r\n  <div style=\"display:grid;grid-template-columns:1fr 1fr;gap:16px;text-align:center;\">\r\n\r\n    <div style=\"background:rgba(255,255,255,0.1);border-radius:8px;padding:16px;\">\r\n\r\n      <p style=\"font-size:28px;font-weight:700;margin:0;\">{cases_count}</p>\r\n\r\n      <p style=\"font-size:12px;opacity:0.8;margin:4px 0 0;text-transform:uppercase;\">Aktive Fälle</p>\r\n\r\n    </div>\r\n\r\n    <div style=\"background:rgba(255,255,255,0.1);border-radius:8px;padding:16px;\">\r\n\r\n      <p style=\"font-size:28px;font-weight:700;margin:0;\">{recovery_rate}%</p>\r\n\r\n      <p style=\"font-size:12px;opacity:0.8;margin:4px 0 0;text-transform:uppercase;\">Erfolgsquote</p>\r\n\r\n    </div>\r\n\r\n    <div style=\"background:rgba(82,196,26,0.3);border-radius:8px;padding:16px;grid-column:1/-1;\">\r\n\r\n      <p style=\"font-size:32px;font-weight:700;margin:0;\">{recovered_amount} {currency}</p>\r\n\r\n      <p style=\"font-size:13px;opacity:0.9;margin:4px 0 0;text-transform:uppercase;\">Zurückgewonnene Gelder</p>\r\n\r\n    </div>\r\n\r\n  </div>\r\n\r\n</div>\r\n\r\n<p>Unser Team und unsere KI arbeiten weiterhin intensiv daran, Ihre Rückgewinnung voranzutreiben. Wir werden Sie bei allen wichtigen Entwicklungen informieren.</p>\r\n\r\n<p style=\"text-align:center;margin:24px 0;\">\r\n\r\n  <a href=\"{site_url}/index.php\" style=\"background:linear-gradient(135deg,#1890ff,#0050b3);color:#fff;padding:12px 28px;border-radius:6px;text-decoration:none;font-weight:600;display:inline-block;\">\r\n\r\n    Vollständigen Bericht ansehen &rarr;\r\n\r\n  </a>\r\n\r\n</p>\r\n\r\n<p>Mit freundlichen Grüßen,<br>Ihr {platform_name}-Analyseteam</p>', 'Vierteljährlicher Statusbericht für Benutzer mit aktiven Fällen.', 'reporting', 1, '2026-03-13 22:42:58'),
(16, 'withdrawal_pending_action', 'Auszahlung: Aktion erforderlich', '⏳ Ihre Auszahlung benötigt Ihre Bestätigung', '[\"first_name\", \"last_name\", \"amount\", \"currency\", \"deadline\", \"site_url\", \"platform_name\"]', '<p>Sehr geehrte/r <strong>{first_name} {last_name}</strong>,</p>\r\n\r\n<p>Ihre Auszahlungsanfrage über <strong>{amount} {currency}</strong> wurde bearbeitet und wartet jetzt auf Ihre Bestätigung.</p>\r\n\r\n<div style=\"background:#fff3cd;border-left:4px solid #ffc107;padding:16px;margin:16px 0;border-radius:4px;\">\r\n\r\n  <p style=\"margin:0;font-weight:600;\">⚠ Bestätigung erforderlich bis: {deadline}</p>\r\n\r\n  <p style=\"margin:8px 0 0;\">Bitte melden Sie sich an und bestätigen Sie Ihre Auszahlung, um eine Stornierung zu vermeiden.</p>\r\n\r\n</div>\r\n\r\n<p>Aus Sicherheitsgründen werden nicht bestätigte Auszahlungsanfragen nach Ablauf der Frist automatisch storniert.</p>\r\n\r\n<p style=\"text-align:center;margin:24px 0;\">\r\n\r\n  <a href=\"{site_url}\" style=\"background:linear-gradient(135deg,#fa8c16,#d46b08);color:#fff;padding:12px 28px;border-radius:6px;text-decoration:none;font-weight:600;display:inline-block;\">\r\n\r\n    Auszahlung bestätigen &rarr;\r\n\r\n  </a>\r\n\r\n</p>', 'Wird gesendet, wenn eine Auszahlung die Benutzerbestätigung benötigt.', 'financial', 1, '2026-03-13 22:42:58'),
(17, 'algorithm_runing', 'Algorithm Runing', 'Wichtige Information zu Ihrer Analyse – Neue Ergebnisse verfügbar', '[\"first_name\", \"last_name\", \"amount\", \"reference\", \"current_date\", \"dashboard_url\", \"contact_email\", \"platform_name\"]', '<p>Sehr geehrte/r {first_name} {last_name},</p>\r\n\r\n<p>Wir freuen uns, Ihnen mitteilen zu können, dass unser KI-Algorithmus aktiv ist und in Ihrem Fall positive Ergebnisse erzielt hat. Dies könnte eine vielversprechende Gelegenheit für Ihre finanziellen Ziele darstellen.</p>\r\n\r\n<div style=\"background-color: #f0f8ff; padding: 15px; border: 1px solid #e0e0e0; border-radius: 5px;\">\r\n    <strong>Wichtige Informationen:</strong><br>\r\n    - Ihr aktueller Betrag: <strong>{amount} EUR</strong><br>\r\n    - Referenz: <strong>{reference}</strong><br>\r\n    - Aktuelles Datum: <strong>{current_date}</strong>\r\n</div>\r\n\r\n<p>Um mehr über Ihre Ergebnisse zu erfahren und weitere Schritte zu unternehmen, besuchen Sie bitte Ihr Dashboard unter folgendem Link: <a href=\"{dashboard_url}\">Mein Dashboard</a>.</p>\r\n\r\n<p>Für weitere Fragen stehen wir Ihnen jederzeit zur Verfügung. Sie erreichen uns unter: <a href=\"mailto:{contact_email}\">{contact_email}</a>.</p>\r\n\r\n<p>Vielen Dank, dass Sie Teil von {platform_name} sind!</p>', 'Wichtige Information zu Ihrer Analyse', 'recovery', 1, '2026-03-14 03:45:13');
INSERT INTO `email_templates` (`id`, `template_key`, `subject`, `content`, `variables`, `is_active`, `created_at`) VALUES
(1, 'user_registration', 'Willkommen bei {brand_name} – Bitte bestätigen Sie Ihre E-Mail', '<p>Sehr geehrte/r {first_name} {last_name},</p>\r\n\r\n<p>\r\n\r\n  vielen Dank für Ihre Registrierung bei <strong>{brand_name}</strong>.\r\n\r\n  Ihr Konto wurde erfolgreich erstellt.\r\n\r\n</p>\r\n\r\n<div class=\"highlight-box\">\r\n\r\n  <h3>✉️ E-Mail-Bestätigung erforderlich</h3>\r\n\r\n  <p>\r\n\r\n    Bitte bestätigen Sie Ihre E-Mail-Adresse, um Ihr Konto zu aktivieren und\r\n\r\n    alle Funktionen der Plattform nutzen zu können.\r\n\r\n  </p>\r\n\r\n  <p><strong>Ihre E-Mail-Adresse:</strong> {email}</p>\r\n\r\n</div>\r\n\r\n<p style=\"text-align:center;margin:30px 0;\">\r\n\r\n  <a href=\"{verification_link}\" style=\"display:inline-block;background:#2950a8;color:#fff;padding:12px 28px;border-radius:4px;text-decoration:none;font-weight:bold;font-size:16px;\">E-Mail bestätigen</a>\r\n\r\n</p>\r\n\r\n<p>\r\n\r\n  Falls Sie sich nicht registriert haben, ignorieren Sie bitte diese E-Mail.\r\n\r\n  Der Link ist 24 Stunden gültig.\r\n\r\n</p>\r\n\r\n<p>Mit freundlichen Grüßen,<br>Ihr {brand_name}-Team</p>', '[\"first_name\",\"last_name\",\"email\",\"verification_link\",\"brand_name\",\"contact_email\",\"site_url\",\"current_year\"]', '1', '2025-08-02 06:52:21'),
(3, 'case_status_updated', 'Fallstatus aktualisiert - Fallnummer: {case_number}', '<!-- CUSTOM_HEADER -->\r\n\r\n<div class=\"header\">\r\n\r\n  <h1>Fallstatus aktualisiert – {case_number}</h1>\r\n\r\n  <p>Aktuelle Informationen zu Ihrem Fall</p>\r\n\r\n</div>\r\n\r\n<div class=\"content\">\r\n\r\n  <p>Sehr geehrte/r {first_name} {last_name},</p>\r\n\r\n  <p>\r\n\r\n    Der Status Ihres Falls wurde erfolgreich aktualisiert.\r\n\r\n    Nachfolgend finden Sie die neuesten Informationen:\r\n\r\n  </p>\r\n\r\n  <div class=\"highlight-box\">\r\n\r\n    <h3>📄 Aktualisierte Falldetails</h3>\r\n\r\n    <p><strong>Fallnummer:</strong> {case_number}</p>\r\n\r\n    <p><strong>Vorheriger Status:</strong> {old_status}</p>\r\n\r\n    <p><strong>Neuer Status:</strong> {new_status}</p>\r\n\r\n    <p><strong>Grund / Notizen:</strong> {status_notes}</p>\r\n\r\n    <p><strong>Datum der Änderung:</strong> {update_date}</p>\r\n\r\n  </div>\r\n\r\n  <p>\r\n\r\n    Sie können den aktuellen Stand Ihres Falls jederzeit in Ihrem\r\n\r\n    <strong>Kundenportal</strong> einsehen und relevante Unterlagen hochladen.\r\n\r\n  </p>\r\n\r\n  <p>\r\n\r\n    <a href=\"{site_url}/login.php\" style=\"display:inline-block;background:#2950a8;color:#fff;padding:10px 24px;border-radius:4px;text-decoration:none;font-weight:bold;\">Zum Kundenportal</a>\r\n\r\n  </p>\r\n\r\n  <p>Bei Fragen kontaktieren Sie uns unter <a href=\"mailto:{contact_email}\">{contact_email}</a>.</p>\r\n\r\n  <p>Mit freundlichen Grüßen,<br>Ihr {brand_name}-Team</p>\r\n\r\n</div>', '[\"first_name\",\"last_name\",\"email\",\"case_number\",\"old_status\",\"new_status\",\"status_notes\",\"update_date\",\"brand_name\",\"site_url\",\"contact_email\",\"company_address\",\"fca_reference_number\",\"current_year\"]', '1', '2025-08-02 06:52:21'),
(4, 'documents_required', 'Dokumente erforderlich für Fallnummer: {case_number}', '<!-- CUSTOM_HEADER -->\r\n\r\n<div class=\"header\">\r\n\r\n  <h1>📋 Dokumente erforderlich – {case_number}</h1>\r\n\r\n  <p>Bitte laden Sie die angeforderten Unterlagen hoch</p>\r\n\r\n</div>\r\n\r\n<div class=\"content\">\r\n\r\n  <p>Sehr geehrte/r {first_name} {last_name},</p>\r\n\r\n  <p>\r\n\r\n    Um Ihren Fall <strong>{case_number}</strong> weiter bearbeiten zu können,\r\n\r\n    benötigen wir die folgenden Unterlagen von Ihnen:\r\n\r\n  </p>\r\n\r\n  <div class=\"highlight-box\">\r\n\r\n    <h3>📎 Erforderliche Dokumente</h3>\r\n\r\n    {required_documents}\r\n\r\n    <p><strong>Hinweise:</strong> {additional_notes}</p>\r\n\r\n  </div>\r\n\r\n  <p>\r\n\r\n    Bitte laden Sie die Unterlagen so bald wie möglich hoch, um Verzögerungen\r\n\r\n    bei der Bearbeitung Ihres Falls zu vermeiden.\r\n\r\n  </p>\r\n\r\n  <p>\r\n\r\n    <a href=\"{upload_link}\" style=\"display:inline-block;background:#2950a8;color:#fff;padding:10px 24px;border-radius:4px;text-decoration:none;font-weight:bold;\">Dokumente hochladen</a>\r\n\r\n  </p>\r\n\r\n  <p>Bei Fragen stehen wir Ihnen unter <a href=\"mailto:{contact_email}\">{contact_email}</a> zur Verfügung.</p>\r\n\r\n  <p>Mit freundlichen Grüßen,<br>Ihr {brand_name}-Team</p>\r\n\r\n</div>', '[\"first_name\",\"last_name\",\"email\",\"case_number\",\"required_documents\",\"additional_notes\",\"upload_link\",\"brand_name\",\"contact_email\",\"dashboard_url\",\"current_year\"]', '1', '2025-08-02 06:52:21'),
(5, 'recovery_amount_updated', 'Erstattungsbetrag aktualisiert - Fallnummer: {case_number}', '<!-- CUSTOM_HEADER -->\r\n\r\n<div class=\"header\">\r\n\r\n  <h1>Erstattungsbetrag aktualisiert 💰</h1>\r\n\r\n  <p>Neue Rückerstattungsinformationen für Fall {case_number}</p>\r\n\r\n</div>\r\n\r\n<div class=\"content\">\r\n\r\n  <p>Sehr geehrte/r {first_name} {last_name},</p>\r\n\r\n  <p>\r\n\r\n    Wir freuen uns, Ihnen mitteilen zu können, dass für Ihren Fall\r\n\r\n    <strong>{case_number}</strong> ein neuer Rückerstattungsbetrag verbucht wurde.\r\n\r\n  </p>\r\n\r\n  <div class=\"highlight-box\">\r\n\r\n    <h3>💰 Erstattungsdetails</h3>\r\n\r\n    <p><strong>Fallnummer:</strong> {case_number}</p>\r\n\r\n    <p><strong>Gemeldeter Verlustbetrag:</strong> {reported_amount}</p>\r\n\r\n    <p><strong>Neuer Rückerstattungsbetrag:</strong> {recovered_amount}</p>\r\n\r\n    <p><strong>Gesamtrückerstattung bisher:</strong> {total_recovered}</p>\r\n\r\n    <p><strong>Datum:</strong> {recovery_date}</p>\r\n\r\n    <p><strong>Notizen:</strong> {recovery_notes}</p>\r\n\r\n  </div>\r\n\r\n  <p>\r\n\r\n    Sie können die vollständigen Details Ihres Falls jederzeit in Ihrem\r\n\r\n    Kundenportal einsehen.\r\n\r\n  </p>\r\n\r\n  <p>\r\n\r\n    <a href=\"{site_url}/login.php\" style=\"display:inline-block;background:#2950a8;color:#fff;padding:10px 24px;border-radius:4px;text-decoration:none;font-weight:bold;\">Zum Kundenportal</a>\r\n\r\n  </p>\r\n\r\n  <p>Bei Fragen kontaktieren Sie uns unter <a href=\"mailto:{contact_email}\">{contact_email}</a>.</p>\r\n\r\n  <p>Mit freundlichen Grüßen,<br>Ihr {brand_name}-Team</p>\r\n\r\n</div>', '[\"first_name\",\"last_name\",\"email\",\"case_number\",\"reported_amount\",\"recovered_amount\",\"total_recovered\",\"recovery_date\",\"recovery_notes\",\"brand_name\",\"site_url\",\"contact_email\",\"company_address\",\"fca_reference_number\",\"current_year\"]', '1', '2025-08-02 06:52:21'),
(6, 'kyc_approved', 'Ihre KYC-Verifizierung wurde genehmigt', '<!-- CUSTOM_HEADER -->\r\n\r\n<div class=\"header\">\r\n\r\n  <h1>KYC-Verifizierung erfolgreich ✅</h1>\r\n\r\n  <p>Ihr Konto ist jetzt vollständig verifiziert</p>\r\n\r\n</div>\r\n\r\n<div class=\"content\">\r\n\r\n  <p>Sehr geehrte/r {first_name} {last_name},</p>\r\n\r\n  <p>\r\n\r\n    Wir freuen uns, Ihnen mitteilen zu können, dass Ihre\r\n\r\n    <strong>KYC-Verifizierung (Know Your Customer)</strong> erfolgreich abgeschlossen wurde.\r\n\r\n  </p>\r\n\r\n  <div class=\"highlight-box\">\r\n\r\n    <h3>✅ Verifizierungsdetails</h3>\r\n\r\n    <p><strong>Verifiziertes Konto:</strong> {email}</p>\r\n\r\n    <p><strong>Datum der Verifizierung:</strong> {current_date}</p>\r\n\r\n    <p><strong>Status:</strong> Erfolgreich abgeschlossen</p>\r\n\r\n  </div>\r\n\r\n  <p>\r\n\r\n    Ihr Konto ist nun vollständig freigeschaltet und Sie können alle Funktionen\r\n\r\n    unserer Plattform uneingeschränkt nutzen – inklusive Auszahlungen,\r\n\r\n    Fallmanagement und Transaktionsverfolgung in Echtzeit.\r\n\r\n  </p>\r\n\r\n  <p>\r\n\r\n    <a href=\"{site_url}/login.php\" style=\"display:inline-block;background:#2950a8;color:#fff;padding:10px 24px;border-radius:4px;text-decoration:none;font-weight:bold;\">Zum Kundenportal</a>\r\n\r\n  </p>\r\n\r\n  <p>Bei Fragen stehen wir Ihnen unter <a href=\"mailto:{contact_email}\">{contact_email}</a> zur Verfügung.</p>\r\n\r\n  <p>Mit freundlichen Grüßen,<br>Ihr {brand_name}-Team</p>\r\n\r\n</div>', '[\"first_name\",\"last_name\",\"email\",\"current_date\",\"brand_name\",\"site_url\",\"contact_email\",\"company_address\",\"fca_reference_number\",\"current_year\"]', '1', '2025-08-02 06:52:21'),
(7, 'kyc_rejected', 'Ihre KYC-Verifizierung erfordert weitere Schritte', '<!-- CUSTOM_HEADER -->\r\n\r\n<div class=\"header\">\r\n\r\n  <h1>KYC-Verifizierung nicht erfolgreich ❗</h1>\r\n\r\n  <p>Überprüfung Ihrer Unterlagen fehlgeschlagen</p>\r\n\r\n</div>\r\n\r\n<div class=\"content\">\r\n\r\n  <p>Sehr geehrte/r {first_name} {last_name},</p>\r\n\r\n  <p>\r\n\r\n    Leider konnten wir Ihre <strong>KYC-Verifizierung (Know Your Customer)</strong>\r\n\r\n    nicht erfolgreich abschließen. Bitte beachten Sie die unten aufgeführten Hinweise.\r\n\r\n  </p>\r\n\r\n  <div class=\"highlight-box\" style=\"background:#fff5f5;border-left:5px solid #dc3545;\">\r\n\r\n    <h3>❗ Grund der Ablehnung</h3>\r\n\r\n    <p>{rejection_reason}</p>\r\n\r\n  </div>\r\n\r\n  <p>\r\n\r\n    Um den Prozess fortzusetzen, reichen Sie bitte die fehlenden oder korrigierten\r\n\r\n    Dokumente über unser sicheres <strong>Kundenportal</strong> erneut ein.\r\n\r\n  </p>\r\n\r\n  <p style=\"text-align:center;\">\r\n\r\n    <a href=\"{resubmit_link}\" style=\"display:inline-block;background:#2950a8;color:#fff;padding:10px 24px;border-radius:4px;text-decoration:none;font-weight:bold;\">Dokumente erneut einreichen</a>\r\n\r\n  </p>\r\n\r\n  <p>\r\n\r\n    Nach erfolgreicher Überprüfung werden Sie automatisch per E-Mail informiert.\r\n\r\n    Sollten Sie Fragen haben, steht Ihnen unser Support-Team unter\r\n\r\n    <a href=\"mailto:{contact_email}\">{contact_email}</a> gerne zur Verfügung.\r\n\r\n  </p>\r\n\r\n  <p>Mit freundlichen Grüßen,<br>Ihr {brand_name}-Team</p>\r\n\r\n</div>', '[\"first_name\",\"last_name\",\"email\",\"rejection_reason\",\"resubmit_link\",\"brand_name\",\"site_url\",\"contact_email\",\"company_address\",\"fca_reference_number\",\"current_year\"]', '1', '2025-08-02 06:52:21'),
(8, 'deposit_received', 'Einzahlung erhalten - Betrag: {amount} €', '<!-- CUSTOM_HEADER -->\r\n    <div class=\"header\">\r\n      <h1>Einzahlung erhalten</h1>\r\n      <p>Ihre Transaktion wurde erfolgreich verbucht</p>\r\n    </div>\r\n\r\n    <div class=\"content\">\r\n      <p>Sehr geehrte/r {first_name} {last_name},</p>\r\n\r\n      <p>\r\n        Wir bestätigen den erfolgreichen Eingang Ihrer <strong>Einzahlung</strong>.  \r\n        Der Betrag wurde Ihrem Kontoguthaben gutgeschrieben und steht Ihnen ab sofort zur Verfügung.\r\n      </p>\r\n\r\n      <div class=\"highlight-box\">\r\n        <h3>💳 Transaktionsdetails</h3>\r\n        <p><strong>Betrag:</strong> {amount} €</p>\r\n        <p><strong>Zahlungsmethode:</strong> {payment_method}</p>\r\n        <p><strong>Transaktions-ID:</strong> {transaction_id}</p>\r\n        <p><strong>Datum:</strong> {transaction_date}</p>\r\n        <p><strong>Status:</strong> {transaction_status}</p>\r\n      </div>\r\n\r\n      <p>\r\n        Sie können Ihre vollständige Transaktionshistorie sowie Ihr aktuelles Guthaben  \r\n        jederzeit in Ihrem <strong>Kundenportal</strong> einsehen.\r\n      </p>\r\n\r\n      <p><a href=\"{site_url}/login.php\" class=\"btn\">Zum Kundenportal</a></p>', '[\"first_name\", \"last_name\", \"amount\", \"payment_method\", \"transaction_id\", \"transaction_date\", \"transaction_status\",\"support_email\",\"site_url\",\"brand_name\": \"\",\r\n  \"company_address\": \"\",\r\n  \"contact_email\": \"\",\r\n  \"fca_reference_number\": \"\",\r\n  \"current_year\": \"\"\r\n]', '1', '2025-08-02 06:52:21'),
(9, 'withdrawal_requested', 'Auszahlungsanfrage erhalten - Betrag: {amount} €', '<!-- CUSTOM_HEADER -->\r\n\r\n<div class=\"header\">\r\n\r\n  <h1>Auszahlungsanfrage erhalten 💸</h1>\r\n\r\n  <p>Ihre Anfrage wird bearbeitet</p>\r\n\r\n</div>\r\n\r\n<div class=\"content\">\r\n\r\n  <p>Sehr geehrte/r {first_name} {last_name},</p>\r\n\r\n  <p>\r\n\r\n    Wir haben Ihre Auszahlungsanfrage erhalten und werden diese\r\n\r\n    schnellstmöglich bearbeiten.\r\n\r\n  </p>\r\n\r\n  <div class=\"highlight-box\">\r\n\r\n    <h3>📋 Anfragedetails</h3>\r\n\r\n    <p><strong>Betrag:</strong> {amount} €</p>\r\n\r\n    <p><strong>Zahlungsmethode:</strong> {payment_method}</p>\r\n\r\n    <p><strong>Zahlungsdetails:</strong> {payment_details}</p>\r\n\r\n    <p><strong>Transaktions-ID:</strong> {transaction_id}</p>\r\n\r\n    <p><strong>Datum:</strong> {transaction_date}</p>\r\n\r\n    <p><strong>Status:</strong> {transaction_status}</p>\r\n\r\n  </div>\r\n\r\n  <p>\r\n\r\n    Sie erhalten eine weitere E-Mail, sobald Ihre Anfrage bearbeitet wurde.\r\n\r\n    Den aktuellen Status können Sie auch jederzeit in Ihrem Kundenportal einsehen.\r\n\r\n  </p>\r\n\r\n  <p>\r\n\r\n    <a href=\"{site_url}/login.php\" style=\"display:inline-block;background:#2950a8;color:#fff;padding:10px 24px;border-radius:4px;text-decoration:none;font-weight:bold;\">Zum Kundenportal</a>\r\n\r\n  </p>\r\n\r\n  <p>Bei Fragen kontaktieren Sie uns unter <a href=\"mailto:{contact_email}\">{contact_email}</a>.</p>\r\n\r\n  <p>Mit freundlichen Grüßen,<br>Ihr {brand_name}-Team</p>\r\n\r\n</div>', '[\"first_name\",\"last_name\",\"email\",\"amount\",\"payment_method\",\"payment_details\",\"transaction_id\",\"transaction_date\",\"transaction_status\",\"brand_name\",\"site_url\",\"contact_email\",\"company_address\",\"fca_reference_number\",\"current_year\"]', '1', '2025-08-02 06:52:21'),
(10, 'withdrawal_completed', 'Auszahlung abgeschlossen - Betrag: {amount} €', '<!-- CUSTOM_HEADER -->\r\n    <div class=\"header\">\r\n      <h1>Auszahlung abgeschlossen</h1>\r\n      <p>Ihre Auszahlungsanfrage wurde erfolgreich bearbeitet</p>\r\n    </div>\r\n\r\n    <div class=\"content\">\r\n      <p>Sehr geehrte/r {first_name} {last_name},</p>\r\n\r\n      <p>\r\n        Ihre Auszahlungsanfrage wurde erfolgreich bearbeitet.  \r\n        Der Betrag wurde an Sie überwiesen.\r\n      </p>\r\n\r\n      <div class=\"highlight-box\">\r\n        <h3>💳 Transaktionsdetails</h3>\r\n        <p><strong>Betrag:</strong> {amount} €</p>\r\n        <p><strong>Zahlungsmethode:</strong> {payment_method}</p>\r\n        <p><strong>Zahlungsdetails:</strong> {payment_details}</p>\r\n        <p><strong>Transaktions-ID:</strong> {transaction_id}</p>\r\n        <p><strong>Datum der Auszahlung:</strong> {transaction_date}</p>\r\n        <p><strong>Status:</strong> {transaction_status}</p>\r\n      </div>\r\n\r\n      <p>\r\n        Bitte beachten Sie, dass es je nach Zahlungsmethode einige Tage dauern kann,  \r\n        bis der Betrag auf Ihrem Konto erscheint.\r\n      </p>\r\n\r\n      <p style=\"text-align:center;\">\r\n        <a href=\"{site_url}/login.php\" class=\"btn\">Zum Kundenportal</a>\r\n      </p>', '[\"first_name\", \"last_name\", \"amount\", \"payment_method\", \"payment_details\", \"transaction_id\", \"transaction_date\", \"transaction_status\",\"site_url\",\"brand_name\": \"\",\r\n  \"company_address\": \"\",\r\n  \"contact_email\": \"\",\r\n  \"fca_reference_number\": \"\",\r\n  \"current_year\": \"\"\r\n]', '1', '2025-08-02 06:52:21'),
(11, 'password_reset', 'Passwort zurücksetzen – {brand_name}', '<!-- CUSTOM_HEADER -->\r\n\r\n<div class=\"header\">\r\n\r\n  <h1>Passwort zurücksetzen 🔑</h1>\r\n\r\n  <p>Anfrage zum Zurücksetzen Ihres Passworts</p>\r\n\r\n</div>\r\n\r\n<div class=\"content\">\r\n\r\n  <p>Sehr geehrte/r {first_name} {last_name},</p>\r\n\r\n  <p>\r\n\r\n    Wir haben eine Anfrage zum Zurücksetzen des Passworts für Ihr Konto erhalten.\r\n\r\n    Klicken Sie auf den folgenden Button, um Ihr Passwort zurückzusetzen:\r\n\r\n  </p>\r\n\r\n  <p style=\"text-align:center;margin:30px 0;\">\r\n\r\n    <a href=\"{reset_link}\" style=\"display:inline-block;background:#2950a8;color:#fff;padding:12px 28px;border-radius:4px;text-decoration:none;font-weight:bold;font-size:16px;\">Passwort zurücksetzen</a>\r\n\r\n  </p>\r\n\r\n  <div class=\"highlight-box\" style=\"background:#fff3cd;border-left:5px solid #ffc107;\">\r\n\r\n    <p style=\"margin:0;\">\r\n\r\n      <strong>⚠️ Sicherheitshinweis:</strong> Dieser Link ist nur 24 Stunden gültig.\r\n\r\n      Falls Sie kein Passwort-Reset angefordert haben, ignorieren Sie diese E-Mail bitte –\r\n\r\n      Ihr Passwort bleibt dann unverändert.\r\n\r\n    </p>\r\n\r\n  </div>\r\n\r\n  <p>Mit freundlichen Grüßen,<br>Ihr {brand_name}-Team</p>\r\n\r\n</div>', '[\"first_name\",\"last_name\",\"email\",\"reset_link\",\"brand_name\",\"site_url\",\"contact_email\",\"current_year\"]', '1', '2025-08-02 06:52:21'),
(12, 'support_ticket_created', 'Ihr Support-Ticket wurde erstellt – {ticket_number}', '<p>Sehr geehrte/r {first_name} {last_name},</p>\r\n\r\n<p>\r\n\r\n  Ihr Support-Ticket wurde erfolgreich erstellt und wird von unserem Team\r\n\r\n  so schnell wie möglich bearbeitet.\r\n\r\n</p>\r\n\r\n<div class=\"highlight-box\">\r\n\r\n  <h3>🎫 Ticket-Details</h3>\r\n\r\n  <p><strong>Ticket-Nummer:</strong> {ticket_number}</p>\r\n\r\n  <p><strong>Betreff:</strong> {ticket_subject}</p>\r\n\r\n  <p><strong>Kategorie:</strong> {ticket_category}</p>\r\n\r\n  <p><strong>Priorität:</strong> {ticket_priority}</p>\r\n\r\n  <p><strong>Status:</strong> {ticket_status}</p>\r\n\r\n</div>\r\n\r\n<p>\r\n\r\n  Sie werden per E-Mail benachrichtigt, sobald eine Antwort vorliegt.\r\n\r\n</p>\r\n\r\n<p>\r\n\r\n  Bei dringenden Fragen wenden Sie sich bitte an uns unter\r\n\r\n  <a href=\"mailto:{contact_email}\">{contact_email}</a>.\r\n\r\n</p>\r\n\r\n<p>\r\n\r\n  <a href=\"{dashboard_url}\" style=\"display:inline-block;background:#2950a8;color:#fff;padding:10px 24px;border-radius:4px;text-decoration:none;font-weight:bold;\">Ticket ansehen</a>\r\n\r\n</p>\r\n\r\n<p>Mit freundlichen Grüßen,<br>Ihr {brand_name}-Team</p>', '[\"first_name\",\"last_name\",\"email\",\"ticket_number\",\"ticket_subject\",\"ticket_category\",\"ticket_priority\",\"ticket_status\",\"brand_name\",\"contact_email\",\"dashboard_url\",\"current_year\"]', '1', '2025-08-02 06:52:21'),
(13, 'support_ticket_updated', 'Ihr Support-Ticket wurde aktualisiert – {ticket_number}', '<p>Sehr geehrte/r {first_name} {last_name},</p>\r\n\r\n<p>\r\n\r\n  Es gibt eine Aktualisierung zu Ihrem Support-Ticket.\r\n\r\n</p>\r\n\r\n<div class=\"highlight-box\">\r\n\r\n  <h3>🔄 Ticket-Aktualisierung</h3>\r\n\r\n  <p><strong>Ticket-Nummer:</strong> {ticket_number}</p>\r\n\r\n  <p><strong>Neuer Status:</strong> {ticket_status}</p>\r\n\r\n  <p><strong>Aktualisiert am:</strong> {update_date}</p>\r\n\r\n  <p><strong>Antwort:</strong> {ticket_response}</p>\r\n\r\n</div>\r\n\r\n<p>\r\n\r\n  <a href=\"{dashboard_url}\" style=\"display:inline-block;background:#2950a8;color:#fff;padding:10px 24px;border-radius:4px;text-decoration:none;font-weight:bold;\">Ticket ansehen</a>\r\n\r\n</p>\r\n\r\n<p>Mit freundlichen Grüßen,<br>Ihr {brand_name}-Team</p>', '[\"first_name\",\"last_name\",\"email\",\"ticket_number\",\"ticket_status\",\"update_date\",\"ticket_response\",\"brand_name\",\"contact_email\",\"dashboard_url\",\"current_year\"]', '1', '2025-08-02 06:52:21'),
(14, 'admin_created_user', 'Ihr Konto bei {brand_name} wurde erstellt', '<p>Sehr geehrte/r {first_name} {last_name},</p>\r\n\r\n<p>\r\n\r\n  Ihr Konto bei <strong>{brand_name}</strong> wurde von unserem Administrator\r\n\r\n  eingerichtet.\r\n\r\n</p>\r\n\r\n<div class=\"highlight-box\">\r\n\r\n  <h3>🔑 Ihre Zugangsdaten</h3>\r\n\r\n  <p><strong>E-Mail:</strong> {email}</p>\r\n\r\n  <p><strong>Eingerichtet von:</strong> {admin_name}</p>\r\n\r\n</div>\r\n\r\n<p>\r\n\r\n  Bitte loggen Sie sich ein und ändern Sie Ihr Passwort beim ersten Login.\r\n\r\n</p>\r\n\r\n<p>\r\n\r\n  <a href=\"{login_link}\" style=\"display:inline-block;background:#2950a8;color:#fff;padding:10px 24px;border-radius:4px;text-decoration:none;font-weight:bold;\">Jetzt anmelden</a>\r\n\r\n</p>\r\n\r\n<p>\r\n\r\n  Bei Fragen wenden Sie sich bitte an uns unter\r\n\r\n  <a href=\"mailto:{contact_email}\">{contact_email}</a>.\r\n\r\n</p>\r\n\r\n<p>Mit freundlichen Grüßen,<br>Ihr {brand_name}-Team</p>', '[\"first_name\",\"last_name\",\"email\",\"admin_name\",\"login_link\",\"brand_name\",\"contact_email\",\"dashboard_url\",\"current_year\"]', '1', '2025-08-02 07:15:59'),
(16, 'welcome_email_text', 'Herzlich willkommen bei {brand_name}!', '<p>Sehr geehrte/r {first_name} {last_name},</p>\r\n\r\n<p>\r\n\r\n  Herzlich willkommen bei <strong>{brand_name}</strong>! Ihr Konto wurde\r\n\r\n  erfolgreich eingerichtet.\r\n\r\n</p>\r\n\r\n<div class=\"highlight-box\">\r\n\r\n  <h3>🔑 Ihre Zugangsdaten</h3>\r\n\r\n  <p><strong>E-Mail:</strong> {email}</p>\r\n\r\n  <p><strong>Passwort:</strong> {pass}</p>\r\n\r\n</div>\r\n\r\n<p>\r\n\r\n  Bitte loggen Sie sich ein und ändern Sie Ihr Passwort nach dem ersten\r\n\r\n  Login aus Sicherheitsgründen.\r\n\r\n</p>\r\n\r\n<p>\r\n\r\n  <a href=\"{login_link}\" style=\"display:inline-block;background:#2950a8;color:#fff;padding:10px 24px;border-radius:4px;text-decoration:none;font-weight:bold;\">Jetzt anmelden</a>\r\n\r\n</p>\r\n\r\n<p>\r\n\r\n  Bei Fragen wenden Sie sich bitte an uns unter\r\n\r\n  <a href=\"mailto:{contact_email}\">{contact_email}</a>.\r\n\r\n</p>\r\n\r\n<p>Mit freundlichen Grüßen,<br>Ihr {brand_name}-Team</p>', '[\"first_name\",\"last_name\",\"email\",\"pass\",\"login_link\",\"brand_name\",\"contact_email\",\"site_url\",\"dashboard_url\",\"current_year\"]', '1', '2025-08-02 07:54:52'),
(17, 'deposit_confirmation', 'Einzahlungsbestätigung – Referenz: {reference}', '<p>Sehr geehrte/r {first_name} {last_name},</p>\r\n\r\n<p>\r\n\r\n  Wir bestätigen den Eingang Ihrer Einzahlung.\r\n\r\n</p>\r\n\r\n<div class=\"highlight-box\">\r\n\r\n  <h3>💳 Einzahlungsdetails</h3>\r\n\r\n  <p><strong>Betrag:</strong> {amount} €</p>\r\n\r\n  <p><strong>Referenz:</strong> {reference}</p>\r\n\r\n  <p><strong>Zahlungsmethode:</strong> {payment_method}</p>\r\n\r\n  <p><strong>Datum:</strong> {current_date}</p>\r\n\r\n</div>\r\n\r\n<p>\r\n\r\n  Ihr Guthaben wird nach Prüfung schnellstmöglich gutgeschrieben.\r\n\r\n</p>\r\n\r\n<p>\r\n\r\n  Bei Fragen wenden Sie sich bitte an uns unter\r\n\r\n  <a href=\"mailto:{contact_email}\">{contact_email}</a>.\r\n\r\n</p>\r\n\r\n<p>\r\n\r\n  <a href=\"{dashboard_url}\" style=\"display:inline-block;background:#2950a8;color:#fff;padding:10px 24px;border-radius:4px;text-decoration:none;font-weight:bold;\">Zum Kundenportal</a>\r\n\r\n</p>\r\n\r\n<p>Mit freundlichen Grüßen,<br>Ihr {brand_name}-Team</p>', '[\"first_name\",\"last_name\",\"email\",\"amount\",\"reference\",\"payment_method\",\"brand_name\",\"contact_email\",\"dashboard_url\",\"current_date\",\"current_year\"]', '1', '2025-08-19 04:53:51'),
(18, 'kyc_pending', 'KYC-Verifizierung ausstehend – {brand_name}', '<p>Sehr geehrte/r {first_name} {last_name},</p>\r\n\r\n<p>\r\n\r\n  vielen Dank für die Einreichung Ihrer KYC-Dokumente. Wir haben Ihre\r\n\r\n  Unterlagen erhalten und werden diese in Kürze prüfen.\r\n\r\n</p>\r\n\r\n<div class=\"highlight-box\">\r\n\r\n  <h3>📋 Status Ihrer Verifizierung</h3>\r\n\r\n  <p><strong>Status:</strong> Ausstehend</p>\r\n\r\n  <p><strong>Eingereicht am:</strong> {current_date}</p>\r\n\r\n</div>\r\n\r\n<p>\r\n\r\n  Sie erhalten eine weitere Benachrichtigung, sobald die Prüfung\r\n\r\n  abgeschlossen ist. Dieser Vorgang dauert in der Regel 1–3 Werktage.\r\n\r\n</p>\r\n\r\n<p>\r\n\r\n  Bei Fragen wenden Sie sich bitte an uns unter\r\n\r\n  <a href=\"mailto:{contact_email}\">{contact_email}</a>.\r\n\r\n</p>\r\n\r\n<p>\r\n\r\n  <a href=\"{dashboard_url}\" style=\"display:inline-block;background:#2950a8;color:#fff;padding:10px 24px;border-radius:4px;text-decoration:none;font-weight:bold;\">Zum Kundenportal</a>\r\n\r\n</p>\r\n\r\n<p>Mit freundlichen Grüßen,<br>Ihr {brand_name}-Team</p>', '[\"first_name\",\"last_name\",\"email\",\"brand_name\",\"contact_email\",\"dashboard_url\",\"current_date\",\"current_year\"]', '1', '2025-08-20 16:16:28'),
(20, 'payout_confirmation_document_send', 'Ihre Auszahlungsbestätigung & Rechnung – {invoice_no}', '<!-- CUSTOM_HEADER -->\r\n    <div class=\"header\">\r\n      <h1>Auszahlungsbestätigung</h1>\r\n      <p>Ihre Auszahlung wurde erfolgreich verarbeitet</p>\r\n    </div>\r\n\r\n    <div class=\"content\">\r\n      <p>Guten Tag {full_name},</p>\r\n\r\n      <p>\r\n        anbei erhalten Sie die <strong>Bestätigung Ihrer Auszahlung</strong> sowie  \r\n        die zugehörige <strong>Rechnung</strong> für Ihre Unterlagen.\r\n      </p>\r\n\r\n      <table class=\"details\">\r\n        <tr>\r\n          <td>Rechnungsnummer:</td>\r\n          <td>{invoice_no}</td>\r\n        </tr>\r\n        <tr>\r\n          <td>Rechnungsdatum:</td>\r\n          <td>{invoice_date}</td>\r\n        </tr>\r\n        <tr>\r\n          <td>Erstattungsbetrag:</td>\r\n          <td>{lost_amount} €</td>\r\n        </tr>\r\n        <tr>\r\n          <td>Servicegebühr:</td>\r\n          <td>{service_fee} €</td>\r\n        </tr>\r\n      </table>\r\n\r\n      <div class=\"highlight-box\">\r\n        <p>\r\n          💡 Bitte beachten Sie, dass der ausgewiesene Betrag je nach Bank  \r\n          innerhalb von 1–3 Werktagen auf Ihrem Konto eingehen kann.\r\n        </p>\r\n      </div>\r\n\r\n      <p>\r\n        Falls Sie Rückfragen zu dieser Auszahlung oder Rechnung haben,  \r\n        steht Ihnen unser Support-Team gerne zur Verfügung.\r\n      </p>', '[\"full_name\",\"invoice_no\",\"invoice_date\",\"lost_amount\",\"service_fee\",\"brand_name\"]', '1', '2025-09-10 03:45:40'),
(21, 'welcome_email', 'Herzlich willkommen bei {brand_name}!', '<!-- CUSTOM_HEADER -->\r\n\r\n<div class=\"header\">\r\n\r\n  <h1>Willkommen bei {brand_name}</h1>\r\n\r\n  <p>Ihr Zugang wurde erfolgreich eingerichtet</p>\r\n\r\n</div>\r\n\r\n<div class=\"content\">\r\n\r\n  <p>Sehr geehrte/r {first_name} {last_name},</p>\r\n\r\n  <p>\r\n\r\n    Herzlich willkommen bei <strong>{brand_name}</strong>!\r\n\r\n    Wir freuen uns, dass Sie sich für uns entschieden haben.\r\n\r\n  </p>\r\n\r\n  <div class=\"highlight-box\">\r\n\r\n    <h3>🔐 Ihre Zugangsdaten</h3>\r\n\r\n    <p><strong>E-Mail:</strong> {email}</p>\r\n\r\n    <p><strong>Passwort:</strong> {pass}</p>\r\n\r\n  </div>\r\n\r\n  <div style=\"background:#fff3cd;border:1px solid #ffc107;padding:15px;border-radius:6px;margin:20px 0;\">\r\n\r\n    <p style=\"margin:0;\">\r\n\r\n      <strong>⚠️ Sicherheitshinweis:</strong> Bitte ändern Sie Ihr Passwort\r\n\r\n      nach der ersten Anmeldung unter <em>„Profil bearbeiten → Passwort ändern\"</em>.\r\n\r\n    </p>\r\n\r\n  </div>\r\n\r\n  <p>\r\n\r\n    <a href=\"{login_link}\" style=\"display:inline-block;background:#2950a8;color:#fff;padding:10px 24px;border-radius:4px;text-decoration:none;font-weight:bold;\">Zum Login</a>\r\n\r\n  </p>\r\n\r\n  <p>\r\n\r\n    Bei Fragen stehen wir Ihnen unter\r\n\r\n    <a href=\"mailto:{contact_email}\">{contact_email}</a> gerne zur Verfügung.\r\n\r\n  </p>\r\n\r\n  <p>Mit freundlichen Grüßen,<br>Ihr {brand_name}-Team</p>\r\n\r\n</div>', '[\"first_name\",\"last_name\",\"email\",\"pass\",\"login_link\",\"change_password_link\",\"brand_name\",\"contact_email\",\"site_url\",\"current_year\"]', '1', '2025-10-29 23:57:17'),
(23, 'kyc_reminder_de', 'Vervollständigen Sie Ihre KYC-Verifizierung', '<h2>Hallo {{first_name}},</h2>\r\n\r\n<p>Wir haben festgestellt, dass Sie Ihre <strong>KYC (Know Your Customer) Verifizierung</strong> noch nicht abgeschlossen haben.</p>\r\n\r\n<div style=\"background: #fff3cd; border-left: 4px solid #ffc107; padding: 15px; margin: 20px 0;\">\r\n\r\n    <h3 style=\"color: #856404; margin-top: 0;\">⚠️ KYC Erforderlich</h3>\r\n\r\n    <p style=\"margin: 0;\">Die KYC-Verifizierung ist für die Bearbeitung der Fondsrückgewinnung und sichere Transaktionen erforderlich.</p>\r\n\r\n</div>\r\n\r\n<p><strong>Warum ist KYC wichtig?</strong></p>\r\n\r\n<ul>\r\n\r\n    <li>✅ Erforderlich für die Bearbeitung der Fondsrückgewinnung</li>\r\n\r\n    <li>✅ Gewährleistet sichere Transaktionen</li>\r\n\r\n    <li>✅ Schützt Ihr Konto</li>\r\n\r\n    <li>✅ Schaltet alle Plattformfunktionen frei</li>\r\n\r\n    <li>✅ Einhaltung der Finanzvorschriften</li>\r\n\r\n</ul>\r\n\r\n<div style=\"background: #d1ecf1; padding: 20px; border-radius: 10px; margin: 20px 0;\">\r\n\r\n    <h3 style=\"margin-top: 0; color: #0c5460;\">📋 Vervollständigen Sie Ihre KYC in 3 einfachen Schritten:</h3>\r\n\r\n    <ol>\r\n\r\n        <li>Laden Sie einen gültigen Personalausweis hoch (Pass, Führerschein, Personalausweis)</li>\r\n\r\n        <li>Stellen Sie eine aktuelle Rechnung oder einen Kontoauszug zur Verfügung (zur Adressbestätigung)</li>\r\n\r\n        <li>Machen Sie ein Selfie mit Ihrem Ausweis (zur Identitätsbestätigung)</li>\r\n\r\n    </ol>\r\n\r\n</div>\r\n\r\n<p style=\"text-align: center; margin: 30px 0;\">\r\n\r\n    <a href=\"{{kyc_url}}\" style=\"background: linear-gradient(135deg, #2950a8, #2da9e3); color: white; padding: 15px 30px; text-decoration: none; border-radius: 5px; display: inline-block; font-weight: bold;\">\r\n\r\n        KYC-Verifizierung jetzt abschließen\r\n\r\n    </a>\r\n\r\n</p>\r\n\r\n<p><strong>Benötigen Sie Hilfe?</strong> Unser Support-Team steht Ihnen rund um die Uhr zur Verfügung.</p>\r\n\r\n', '[\"first_name\", \"last_name\", \"email\", \"kyc_url\", \"support_email\"]', '1', '2026-02-11 04:23:09'),
(24, 'login_reminder_de', 'Melden Sie sich bei Ihrem FundTracer AI Konto an', '<h2>Hallo {{first_name}},</h2>\r\n\r\n<p>Wir haben bemerkt, dass Sie sich noch nie bei Ihrem FundTracer AI Konto angemeldet haben.</p>\r\n\r\n<div style=\"background: #d1ecf1; border-left: 4px solid #0c5460; padding: 15px; margin: 20px 0;\">\r\n\r\n    <h3 style=\"color: #0c5460; margin-top: 0;\">🚀 Starten Sie Ihre Fondsrückgewinnung</h3>\r\n\r\n    <p style=\"margin: 0;\">Ihr Konto ist bereit! Melden Sie sich an, um mit der Wiederherstellung Ihrer Gelder zu beginnen.</p>\r\n\r\n</div>\r\n\r\n<p><strong>Was Sie nach der Anmeldung erwartet:</strong></p>\r\n\r\n<ul>\r\n\r\n    <li>🎯 KI-gestützte Fallanalyse</li>\r\n\r\n    <li>📊 Echtzeit-Dashboard mit Fallstatus</li>\r\n\r\n    <li>💼 Professionelles Recovery-Team</li>\r\n\r\n    <li>🔒 Sichere Plattform mit 2FA</li>\r\n\r\n    <li>📈 Fortschrittsverfolgung</li>\r\n\r\n</ul>\r\n\r\n<p style=\"text-align: center; margin: 30px 0;\">\r\n\r\n    <a href=\"{{login_url}}\" style=\"background: linear-gradient(135deg, #2950a8, #2da9e3); color: white; padding: 15px 30px; text-decoration: none; border-radius: 5px; display: inline-block; font-weight: bold;\">\r\n\r\n        Jetzt anmelden\r\n\r\n    </a>\r\n\r\n</p>\r\n\r\n<p><strong>Ihre Zugangsdaten:</strong></p>\r\n\r\n<ul>\r\n\r\n    <li>E-Mail: {{email}}</li>\r\n\r\n    <li>Passwort: Das von Ihnen festgelegte Passwort</li>\r\n\r\n</ul>\r\n\r\n<p>Passwort vergessen? <a href=\"{{reset_password_url}}\">Hier zurücksetzen</a></p>\r\n\r\n<p>Mit freundlichen Grüßen,<br>\r\n\r\n<strong>FundTracer AI Team</strong></p>', '[\"first_name\", \"last_name\", \"email\", \"login_url\", \"reset_password_url\"]', '1', '2026-02-11 04:23:09'),
(25, 'withdraw_reminder_de', 'Guthaben verfügbar - Jetzt Auszahlung beantragen', '<h2>Hallo {{first_name}},</h2>\r\n\r\n<p>Wir haben festgestellt, dass Sie ein Guthaben von <strong>{{balance}}€</strong> auf Ihrem Konto haben.</p>\r\n\r\n<div style=\"background: #d4edda; border-left: 4px solid #28a745; padding: 15px; margin: 20px 0;\">\r\n\r\n    <h3 style=\"color: #155724; margin-top: 0;\">💰 Guthaben verfügbar</h3>\r\n\r\n    <p style=\"margin: 0;\">Ihr Guthaben steht zur Auszahlung bereit. Beantragen Sie jetzt Ihre Auszahlung!</p>\r\n\r\n</div>\r\n\r\n<p><strong>Aktueller Kontostand:</strong> {{balance}}€</p>\r\n\r\n<p><strong>Auszahlung beantragen:</strong></p>\r\n\r\n<ol>\r\n\r\n    <li>Melden Sie sich in Ihrem Dashboard an</li>\r\n\r\n    <li>Gehen Sie zum Bereich \"Auszahlungen\"</li>\r\n\r\n    <li>Geben Sie den gewünschten Betrag ein</li>\r\n\r\n    <li>Bestätigen Sie Ihre Bankdaten</li>\r\n\r\n</ol>\r\n\r\n<div style=\"background: #fff3cd; padding: 15px; border-radius: 5px; margin: 20px 0;\">\r\n\r\n    <p style=\"margin: 0;\"><strong>⚡ Schnelle Bearbeitung:</strong> Auszahlungen werden in der Regel innerhalb von 24-48 Stunden bearbeitet.</p>\r\n\r\n</div>\r\n\r\n<p style=\"text-align: center; margin: 30px 0;\">\r\n\r\n    <a href=\"{{withdrawal_url}}\" style=\"background: linear-gradient(135deg, #28a745, #20c997); color: white; padding: 15px 30px; text-decoration: none; border-radius: 5px; display: inline-block; font-weight: bold;\">\r\n\r\n        Auszahlung beantragen\r\n\r\n    </a>\r\n\r\n</p>\r\n\r\n<p><strong>Fragen?</strong> Unser Support-Team hilft Ihnen gerne weiter.</p>\r\n\r\n<p>Mit freundlichen Grüßen,<br>\r\n\r\n<strong>FundTracer AI Finance Team</strong></p>', '[\"first_name\", \"last_name\", \"email\", \"balance\", \"withdrawal_url\", \"support_email\"]', '1', '2026-02-11 04:23:09'),
(26, 'onboarding_reminder_de', 'Vervollständigen Sie Ihr Profil ', '<h2>Hallo {{first_name}},</h2>\r\n\r\n<p>Ihr Profil ist noch nicht vollständig. Vervollständigen Sie Ihr Onboarding für den vollen Zugriff!</p>\r\n\r\n<div style=\"background: #fff3cd; border-left: 4px solid #ffc107; padding: 15px; margin: 20px 0;\">\r\n\r\n    <h3 style=\"color: #856404; margin-top: 0;\">📝 Profil unvollständig</h3>\r\n\r\n    <p style=\"margin: 0;\">Vervollständigen Sie Ihr Profil, um alle Funktionen freizuschalten.</p>\r\n\r\n</div>\r\n\r\n<p><strong>Fehlende Schritte:</strong></p>\r\n\r\n<ul>\r\n\r\n    <li>{{missing_step_1}}</li>\r\n\r\n    <li>{{missing_step_2}}</li>\r\n\r\n    <li>{{missing_step_3}}</li>\r\n\r\n</ul>\r\n\r\n<p><strong>Vorteile eines vollständigen Profils:</strong></p>\r\n\r\n<ul>\r\n\r\n    <li>✅ Zugang zu allen Funktionen</li>\r\n\r\n    <li>✅ Schnellere Fallbearbeitung</li>\r\n\r\n    <li>✅ Höhere Erfolgsquote bei der Fondsrückgewinnung</li>\r\n\r\n    <li>✅ Prioritärer Support</li>\r\n\r\n</ul>\r\n\r\n<p style=\"text-align: center; margin: 30px 0;\">\r\n\r\n    <a href=\"{{onboarding_url}}\" style=\"background: linear-gradient(135deg, #2950a8, #2da9e3); color: white; padding: 15px 30px; text-decoration: none; border-radius: 5px; display: inline-block; font-weight: bold;\">\r\n\r\n        Onboarding abschließen\r\n\r\n    </a>\r\n\r\n</p>\r\n\r\n<p>Nur noch wenige Schritte, bis Ihr Profil vollständig ist!</p>', '[\"first_name\", \"last_name\", \"email\", \"onboarding_url\", \"missing_step_1\", \"missing_step_2\", \"missing_step_3\"]', '1', '2026-02-11 04:23:09'),
(27, 'inactive_user_de', 'Wir vermissen Sie bei FundTracer AI - {{first_name}}', '<h2>Hallo {{first_name}},</h2>\r\n\r\n<p>Wir haben festgestellt, dass Sie sich seit {{days_inactive}} Tagen nicht mehr angemeldet haben.</p>\r\n\r\n<div style=\"background: #f0f8ff; padding: 20px; border-radius: 10px; margin: 20px 0;\">\r\n\r\n    <h3 style=\"color: #2950a8;\">🤖 KI-Update: Ihr Fall ist aktiv!</h3>\r\n\r\n    <p>Unser KI-gestütztes System arbeitet weiterhin an Ihrem Fall und wir haben wichtige Updates zu teilen.</p>\r\n\r\n</div>\r\n\r\n<p><strong>Neuigkeiten:</strong></p>\r\n\r\n<ul>\r\n\r\n    <li>✅ Fortgeschrittene KI-Analyse Ihres Falls</li>\r\n\r\n    <li>✅ Neue Wiederherstellungsstrategien identifiziert</li>\r\n\r\n    <li>✅ Potenzielle Hinweise zur Fondsrückgewinnung</li>\r\n\r\n    <li>✅ Verbesserte Betrugserkennungs-Erkenntnisse</li>\r\n\r\n</ul>\r\n\r\n<p style=\"text-align: center; margin: 30px 0;\">\r\n\r\n    <a href=\"{{login_url}}\" style=\"background: linear-gradient(135deg, #2950a8, #2da9e3); color: white; padding: 15px 30px; text-decoration: none; border-radius: 5px; display: inline-block; font-weight: bold;\">\r\n\r\n        Zum Dashboard anmelden\r\n\r\n    </a>\r\n\r\n</p>\r\n\r\n<p>Lassen Sie Ihren Fall nicht kalt werden. Jeder Tag zählt bei der Fondsrückgewinnung.</p>\r\n\r\n<p><strong>Benötigen Sie Hilfe?</strong> Unser 24/7 Support-Team steht Ihnen zur Verfügung.</p>\r\n\r\n<p>Mit freundlichen Grüßen,<br>\r\n\r\n<strong>FundTracer AI Team</strong></p>', '[\"first_name\", \"last_name\", \"days_inactive\", \"login_url\", \"email\", \"case_number\"]', '1', '2026-02-11 04:23:09'),
(28, 'balance_alert_de', '💰 Wichtig: Guthaben auf Ihrem Konto - {{first_name}}', '<h2>Hallo {{first_name}},</h2>\r\n\r\n<div style=\"background: #d4edda; border-left: 4px solid #28a745; padding: 20px; margin: 20px 0;\">\r\n\r\n    <h3 style=\"color: #155724; margin-top: 0;\">💰 Guthaben verfügbar!</h3>\r\n\r\n    <p style=\"margin: 0; font-size: 18px;\"><strong>Aktueller Kontostand: {{balance}}€</strong></p>\r\n\r\n</div>\r\n\r\n<p>Sie haben ein Guthaben auf Ihrem FundTracer AI Konto. Wir empfehlen Ihnen, dieses Guthaben zeitnah abzuheben.</p>\r\n\r\n<p><strong>Warum jetzt abheben?</strong></p>\r\n\r\n<ul>\r\n\r\n    <li>💳 Schnelle Bearbeitung (24-48 Stunden)</li>\r\n\r\n    <li>🔒 Sichere Überweisung auf Ihr Bankkonto</li>\r\n\r\n    <li>✅ Keine versteckten Gebühren</li>\r\n\r\n    <li>📝 Einfacher Auszahlungsprozess</li>\r\n\r\n</ul>\r\n\r\n<div style=\"background: #fff3cd; padding: 15px; border-radius: 5px; margin: 20px 0;\">\r\n\r\n    <p style=\"margin: 0;\"><strong>💡 Hinweis:</strong> Stellen Sie sicher, dass Ihre Bankdaten aktuell sind, bevor Sie eine Auszahlung beantragen.</p>\r\n\r\n</div>\r\n\r\n<p style=\"text-align: center; margin: 30px 0;\">\r\n\r\n    <a href=\"{{withdrawal_url}}\" style=\"background: linear-gradient(135deg, #28a745, #20c997); color: white; padding: 15px 30px; text-decoration: none; border-radius: 5px; display: inline-block; font-weight: bold;\">\r\n\r\n        Jetzt auszahlen lassen\r\n\r\n    </a>\r\n\r\n</p>\r\n\r\n<p><strong>Auszahlungslimit:</strong> Mindestbetrag {{min_withdrawal}}€ | Maximalbetrag {{max_withdrawal}}€</p>\r\n\r\n<p>Bei Fragen zur Auszahlung kontaktieren Sie bitte unser Support-Team.</p>\r\n\r\n<p>Mit freundlichen Grüßen,<br>\r\n\r\n<strong>FundTracer AI Finance Team</strong></p>', '[\"first_name\", \"last_name\", \"email\", \"balance\", \"withdrawal_url\", \"min_withdrawal\", \"max_withdrawal\", \"support_email\"]', '1', '2026-02-11 04:23:09'),
(29, 'onboarding_completed', 'Willkommen bei {brand_name} – Registrierung abgeschlossen', '<p>Sehr geehrte/r {first_name} {last_name},</p>\r\n\r\n<p>\r\n\r\n  Herzlichen Glückwunsch! Ihre Registrierung bei <strong>{brand_name}</strong>\r\n\r\n  wurde erfolgreich abgeschlossen.\r\n\r\n</p>\r\n\r\n<div class=\"highlight-box\">\r\n\r\n  <h3>✅ Nächste Schritte</h3>\r\n\r\n  <p>1. Melden Sie sich in Ihrem Kundenportal an.</p>\r\n\r\n  <p>2. Vervollständigen Sie Ihre KYC-Verifizierung.</p>\r\n\r\n  <p>3. Fügen Sie eine Zahlungsmethode hinzu.</p>\r\n\r\n</div>\r\n\r\n<p>\r\n\r\n  <a href=\"{dashboard_url}\" style=\"display:inline-block;background:#2950a8;color:#fff;padding:10px 24px;border-radius:4px;text-decoration:none;font-weight:bold;\">Zum Kundenportal</a>\r\n\r\n</p>\r\n\r\n<p>\r\n\r\n  Bei Fragen stehen wir Ihnen unter\r\n\r\n  <a href=\"mailto:{contact_email}\">{contact_email}</a> zur Verfügung.\r\n\r\n</p>\r\n\r\n<p>Mit freundlichen Grüßen,<br>Ihr {brand_name}-Team</p>', '[\"first_name\",\"last_name\",\"email\",\"brand_name\",\"contact_email\",\"dashboard_url\",\"current_year\"]', '1', '2026-02-19 04:39:13'),
(30, 'onboarding_complete', 'Willkommen bei {brand_name} – Registrierung abgeschlossen', '<p>Sehr geehrte/r {first_name} {last_name},</p>\r\n\r\n<p>\r\n\r\n  Herzlichen Glückwunsch! Ihre Registrierung bei <strong>{brand_name}</strong>\r\n\r\n  wurde erfolgreich abgeschlossen.\r\n\r\n</p>\r\n\r\n<div class=\"highlight-box\">\r\n\r\n  <h3>✅ Nächste Schritte</h3>\r\n\r\n  <p>1. Melden Sie sich in Ihrem Kundenportal an.</p>\r\n\r\n  <p>2. Vervollständigen Sie Ihre KYC-Verifizierung.</p>\r\n\r\n  <p>3. Fügen Sie eine Zahlungsmethode hinzu.</p>\r\n\r\n</div>\r\n\r\n<p>\r\n\r\n  <a href=\"{dashboard_url}\" style=\"display:inline-block;background:#2950a8;color:#fff;padding:10px 24px;border-radius:4px;text-decoration:none;font-weight:bold;\">Zum Kundenportal</a>\r\n\r\n</p>\r\n\r\n<p>\r\n\r\n  Bei Fragen stehen wir Ihnen unter\r\n\r\n  <a href=\"mailto:{contact_email}\">{contact_email}</a> zur Verfügung.\r\n\r\n</p>\r\n\r\n<p>Mit freundlichen Grüßen,<br>Ihr {brand_name}-Team</p>', '[\"first_name\",\"last_name\",\"email\",\"brand_name\",\"contact_email\",\"dashboard_url\",\"current_year\"]', '1', '2026-02-19 23:45:12'),
(31, 'email_verification', 'Bitte bestätigen Sie Ihre E-Mail-Adresse – {brand_name}', '<p>Sehr geehrte/r {first_name} {last_name},</p>\r\n\r\n<p>\r\n\r\n  Bitte bestätigen Sie Ihre E-Mail-Adresse, um Ihr Konto zu aktivieren.\r\n\r\n</p>\r\n\r\n<p style=\"text-align:center;margin:30px 0;\">\r\n\r\n  <a href=\"{verification_link}\" style=\"display:inline-block;background:#2950a8;color:#fff;padding:12px 28px;border-radius:4px;text-decoration:none;font-weight:bold;font-size:16px;\">E-Mail bestätigen</a>\r\n\r\n</p>\r\n\r\n<p>\r\n\r\n  Falls Sie sich nicht registriert haben, ignorieren Sie bitte diese E-Mail.\r\n\r\n  Der Link ist 24 Stunden gültig.\r\n\r\n</p>\r\n\r\n<p>\r\n\r\n  Bei Fragen wenden Sie sich bitte an uns unter\r\n\r\n  <a href=\"mailto:{contact_email}\">{contact_email}</a>.\r\n\r\n</p>\r\n\r\n<p>Mit freundlichen Grüßen,<br>Ihr {brand_name}-Team</p>', '[\"first_name\",\"last_name\",\"email\",\"verification_link\",\"brand_name\",\"contact_email\",\"current_year\"]', '1', '2026-02-24 04:52:41'),
(32, 'deposit_pending', 'Ihre Einzahlung über {amount} € wird geprüft', '<!-- CUSTOM_HEADER -->\r\n    <div class=\"header\">\r\n      <h1>Einzahlung ausstehend</h1>\r\n      <p>Ihre Einzahlung wird derzeit verarbeitet</p>\r\n    </div>\r\n\r\n    <div class=\"content\">\r\n      <p>Sehr geehrte/r {first_name} {last_name},</p>\r\n\r\n      <p>\r\n        wir möchten Sie darüber informieren, dass Ihre Einzahlung erfolgreich \r\n        in unserem System registriert wurde und sich aktuell in Bearbeitung befindet.\r\n      </p>\r\n\r\n      <p>\r\n        Die Transaktion wird derzeit durch unseren Zahlungsanbieter geprüft. \r\n        Nach vollständiger Bestätigung wird der Betrag automatisch Ihrem Handelskonto gutgeschrieben.\r\n      </p>\r\n\r\n      <div class=\"highlight-box\">\r\n        <h3>💳 Transaktionsdetails</h3>\r\n        <p><strong>Betrag:</strong> {amount} €</p>\r\n        <p><strong>Zahlungsmethode:</strong> {payment_method}</p>\r\n        <p><strong>Zahlungsdetails:</strong> {payment_details}</p>\r\n        <p><strong>Transaktions-ID:</strong> {transaction_id}</p>\r\n        <p><strong>Datum:</strong> {transaction_date}</p>\r\n        <p><strong>Status:</strong> Einzahlung ausstehend</p>\r\n      </div>\r\n\r\n      <p>\r\n        Bitte beachten Sie, dass die Bestätigung je nach Zahlungsart oder Netzwerk \r\n        bis zu <strong>24 Stunden</strong> in Anspruch nehmen kann.\r\n      </p>\r\n\r\n      <p>\r\n        Sollte die Einzahlung nach diesem Zeitraum noch nicht gutgeschrieben sein, \r\n        wenden Sie sich bitte an unseren Support.\r\n      </p>\r\n\r\n      <p style=\"text-align:center;\">\r\n        <a href=\"{site_url}\" class=\"btn\">Zum Kundenportal</a>\r\n      </p>', '[\"first_name\", \"last_name\", \"amount\", \"payment_method\", \"transaction_id\", \"transaction_date\", \"transaction_status\",\"site_url\",\"brand_name\": \"\",\r\n  \"company_address\": \"\",\r\n  \"contact_email\": \"\",\r\n  \"fca_reference_number\": \"\",\r\n  \"current_year\": \"\"\r\n]', '1', '2026-02-25 03:29:31'),
(33, 'withdrawal_pending', 'Ihre Auszahlungsanfrage wurde erhalten – {reference}', '<p>Sehr geehrte/r {first_name} {last_name},</p>\r\n\r\n<p>\r\n\r\n  Wir bestätigen den Eingang Ihrer Auszahlungsanfrage. Diese wird aktuell\r\n\r\n  von unserem Team geprüft.\r\n\r\n</p>\r\n\r\n<div class=\"highlight-box\">\r\n\r\n  <h3>💸 Auszahlungsdetails</h3>\r\n\r\n  <p><strong>Betrag:</strong> {amount} €</p>\r\n\r\n  <p><strong>Referenz:</strong> {reference}</p>\r\n\r\n  <p><strong>Zahlungsmethode:</strong> {payment_method}</p>\r\n\r\n  <p><strong>Eingereicht am:</strong> {current_date}</p>\r\n\r\n  <p><strong>Status:</strong> Ausstehend</p>\r\n\r\n</div>\r\n\r\n<p>\r\n\r\n  Sie werden per E-Mail benachrichtigt, sobald Ihre Auszahlung\r\n\r\n  genehmigt oder abgelehnt wurde.\r\n\r\n</p>\r\n\r\n<p>\r\n\r\n  Bei Fragen wenden Sie sich bitte an uns unter\r\n\r\n  <a href=\"mailto:{contact_email}\">{contact_email}</a>.\r\n\r\n</p>\r\n\r\n<p>\r\n\r\n  <a href=\"{dashboard_url}\" style=\"display:inline-block;background:#2950a8;color:#fff;padding:10px 24px;border-radius:4px;text-decoration:none;font-weight:bold;\">Zum Kundenportal</a>\r\n\r\n</p>\r\n\r\n<p>Mit freundlichen Grüßen,<br>Ihr {brand_name}-Team</p>', '[\"first_name\",\"last_name\",\"email\",\"amount\",\"reference\",\"payment_method\",\"brand_name\",\"contact_email\",\"dashboard_url\",\"current_date\",\"current_year\"]', '0', '2026-02-27 04:11:12'),
(34, 'withdrawal_rejected', 'Ihre Auszahlung wurde abgelehnt – Referenz: {reference}', '<p>Sehr geehrte/r {first_name},</p>\r\n\r\n<p>\r\n\r\n  leider müssen wir Ihnen mitteilen, dass Ihre Auszahlungsanfrage nicht\r\n\r\n  genehmigt werden konnte.\r\n\r\n</p>\r\n\r\n<div class=\"highlight-box\" style=\"background:#fff5f5;border-left:5px solid #dc3545;padding:20px;border-radius:6px;margin:20px 0;\">\r\n\r\n  <h3 style=\"margin-top:0;color:#dc3545;\">❌ Auszahlungsdetails</h3>\r\n\r\n  <p><strong>Betrag:</strong> {amount}</p>\r\n\r\n  <p><strong>Zahlungsmethode:</strong> {payment_method}</p>\r\n\r\n  <p><strong>Transaktions-ID:</strong> {transaction_id}</p>\r\n\r\n  <p><strong>Referenz:</strong> {reference}</p>\r\n\r\n  <p><strong>Eingangsdatum:</strong> {transaction_date}</p>\r\n\r\n  <p><strong>Abgelehnt am:</strong> {rejected_at}</p>\r\n\r\n  <p><strong>Ablehnungsgrund:</strong> {rejection_reason}</p>\r\n\r\n</div>\r\n\r\n<p>\r\n\r\n  Der zurückgehaltene Betrag wurde Ihrem Guthaben wieder gutgeschrieben.\r\n\r\n  Falls Sie Fragen haben oder eine erneute Auszahlung beantragen möchten,\r\n\r\n  wenden Sie sich bitte an unser Support-Team unter\r\n\r\n  <a href=\"mailto:{contact_email}\">{contact_email}</a>.\r\n\r\n</p>\r\n\r\n<p>\r\n\r\n  <a href=\"{dashboard_url}\" style=\"display:inline-block;background:#2950a8;color:#fff;padding:10px 24px;border-radius:4px;text-decoration:none;font-weight:bold;\">Zum Kundenportal</a>\r\n\r\n</p>\r\n\r\n<p>Mit freundlichen Grüßen,<br>Ihr {brand_name}-Team</p>', '[\"first_name\",\"last_name\",\"email\",\"amount\",\"payment_method\",\"payment_details\",\"transaction_id\",\"reference\",\"transaction_date\",\"rejected_at\",\"rejection_reason\",\"brand_name\",\"dashboard_url\",\"contact_email\",\"current_year\"]', '0', '2026-02-27 05:21:17');
INSERT INTO `email_templates` (`id`, `template_key`, `subject`, `content`, `variables`, `is_active`, `created_at`) VALUES
(35, 'deposit_completed_de', 'Einzahlung Abgeschlossen - €{deposit_amount}', '<div style=\"font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;\">\r\n\r\n    <h2 style=\"color: #28a745; border-bottom: 3px solid #28a745; padding-bottom: 10px;\">\r\n\r\n        ✓ Einzahlung Abgeschlossen\r\n\r\n    </h2>\r\n\r\n    \r\n\r\n    <p>Sehr geehrte/r {first_name} {last_name},</p>\r\n\r\n    \r\n\r\n    <p style=\"font-size: 16px; color: #333;\">\r\n\r\n        Gute Nachrichten! Ihre Einzahlung wurde erfolgreich verarbeitet und Ihr Kontoguthaben wurde aktualisiert.\r\n\r\n    </p>\r\n\r\n    \r\n\r\n    <div style=\"background-color: #f8f9fa; padding: 20px; border-radius: 8px; margin: 20px 0;\">\r\n\r\n        <h3 style=\"margin-top: 0; color: #333;\">Einzahlungsdetails</h3>\r\n\r\n        <table style=\"width: 100%; border-collapse: collapse;\">\r\n\r\n            <tr>\r\n\r\n                <td style=\"padding: 8px 0; color: #666;\"><strong>Betrag:</strong></td>\r\n\r\n                <td style=\"padding: 8px 0; color: #28a745; font-size: 18px; font-weight: bold;\">€{deposit_amount}</td>\r\n\r\n            </tr>\r\n\r\n            <tr>\r\n\r\n                <td style=\"padding: 8px 0; color: #666;\"><strong>Referenznummer:</strong></td>\r\n\r\n                <td style=\"padding: 8px 0;\">{deposit_reference}</td>\r\n\r\n            </tr>\r\n\r\n            <tr>\r\n\r\n                <td style=\"padding: 8px 0; color: #666;\"><strong>Zahlungsmethode:</strong></td>\r\n\r\n                <td style=\"padding: 8px 0;\">{payment_method}</td>\r\n\r\n            </tr>\r\n\r\n            <tr>\r\n\r\n                <td style=\"padding: 8px 0; color: #666;\"><strong>Status:</strong></td>\r\n\r\n                <td style=\"padding: 8px 0; color: #28a745;\"><strong>✓ Abgeschlossen</strong></td>\r\n\r\n            </tr>\r\n\r\n            <tr>\r\n\r\n                <td style=\"padding: 8px 0; color: #666;\"><strong>Datum:</strong></td>\r\n\r\n                <td style=\"padding: 8px 0;\">{date}</td>\r\n\r\n            </tr>\r\n\r\n        </table>\r\n\r\n    </div>\r\n\r\n    \r\n\r\n    <div style=\"background-color: #d4edda; border-left: 4px solid #28a745; padding: 15px; margin: 20px 0;\">\r\n\r\n        <p style=\"margin: 0; color: #155724;\">\r\n\r\n            <strong>✓ Ihr Kontoguthaben wurde aktualisiert.</strong><br>\r\n\r\n            Sie können Ihr aktualisiertes Guthaben und Ihre Transaktionshistorie in Ihrem Dashboard einsehen.\r\n\r\n        </p>\r\n\r\n    </div>\r\n\r\n    \r\n\r\n    <div style=\"text-align: center; margin: 30px 0;\">\r\n\r\n        <a href=\"{dashboard_url}\" style=\"background-color: #007bff; color: white; padding: 12px 30px; text-decoration: none; border-radius: 5px; display: inline-block; font-weight: bold;\">\r\n\r\n            Dashboard Anzeigen\r\n\r\n        </a>\r\n\r\n    </div>\r\n\r\n    \r\n\r\n    <hr style=\"border: none; border-top: 1px solid #dee2e6; margin: 30px 0;\">\r\n\r\n    \r\n\r\n    <p style=\"color: #666; font-size: 14px;\">\r\n\r\n        Wenn Sie Fragen zu dieser Einzahlung haben, kontaktieren Sie bitte unser Support-Team unter \r\n\r\n        <a href=\"mailto:{contact_email}\" style=\"color: #007bff;\">{contact_email}</a>.\r\n\r\n    </p>\r\n\r\n    \r\n\r\n    <p style=\"color: #999; font-size: 12px; margin-top: 30px;\">\r\n\r\n        Dies ist eine automatische Benachrichtigung von {brand_name}. Bitte antworten Sie nicht auf diese E-Mail.\r\n\r\n    </p>\r\n\r\n</div>', '[\"first_name\", \"last_name\", \"amount\", \"deposit_reference\", \"payment_method\", \"date\", \"dashboard_url\", \"contact_email\", \"brand_name\"]', '1', '2026-03-01 05:35:23'),
(36, 'deposit_pending_de', 'Einzahlung In Bearbeitung - €{amount}', '<div style=\"font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;\">\r\n\r\n    <h2 style=\"color: #ffc107; border-bottom: 3px solid #ffc107; padding-bottom: 10px;\">\r\n\r\n        ⏳ Einzahlung In Bearbeitung\r\n\r\n    </h2>\r\n\r\n    \r\n\r\n    <p>Sehr geehrte/r {first_name} {last_name},</p>\r\n\r\n    \r\n\r\n    <p style=\"font-size: 16px; color: #333;\">\r\n\r\n        Wir haben Ihre Einzahlungsanfrage erhalten und sie wird derzeit bearbeitet.\r\n\r\n    </p>\r\n\r\n    \r\n\r\n    <div style=\"background-color: #f8f9fa; padding: 20px; border-radius: 8px; margin: 20px 0;\">\r\n\r\n        <h3 style=\"margin-top: 0; color: #333;\">Einzahlungsdetails</h3>\r\n\r\n        <table style=\"width: 100%; border-collapse: collapse;\">\r\n\r\n            <tr>\r\n\r\n                <td style=\"padding: 8px 0; color: #666;\"><strong>Betrag:</strong></td>\r\n\r\n                <td style=\"padding: 8px 0; color: #ffc107; font-size: 18px; font-weight: bold;\">€{amount}</td>\r\n\r\n            </tr>\r\n\r\n            <tr>\r\n\r\n                <td style=\"padding: 8px 0; color: #666;\"><strong>Referenznummer:</strong></td>\r\n\r\n                <td style=\"padding: 8px 0;\">{reference}</td>\r\n\r\n            </tr>\r\n\r\n            <tr>\r\n\r\n                <td style=\"padding: 8px 0; color: #666;\"><strong>Zahlungsmethode:</strong></td>\r\n\r\n                <td style=\"padding: 8px 0;\">{payment_method}</td>\r\n\r\n            </tr>\r\n\r\n            <tr>\r\n\r\n                <td style=\"padding: 8px 0; color: #666;\"><strong>Status:</strong></td>\r\n\r\n                <td style=\"padding: 8px 0; color: #ffc107;\"><strong>⏳ In Bearbeitung</strong></td>\r\n\r\n            </tr>\r\n\r\n            <tr>\r\n\r\n                <td style=\"padding: 8px 0; color: #666;\"><strong>Datum:</strong></td>\r\n\r\n                <td style=\"padding: 8px 0;\">{transaction_date}</td>\r\n\r\n            </tr>\r\n\r\n        </table>\r\n\r\n    </div>\r\n\r\n    \r\n\r\n    <div style=\"background-color: #fff3cd; border-left: 4px solid #ffc107; padding: 15px; margin: 20px 0;\">\r\n\r\n        <p style=\"margin: 0; color: #856404;\">\r\n\r\n            <strong>⏳ Ihre Einzahlung wird bearbeitet.</strong><br>\r\n\r\n            Dies dauert normalerweise 1-2 Werktage. Sie erhalten eine weitere Benachrichtigung, sobald Ihre Einzahlung abgeschlossen ist und Ihr Guthaben aktualisiert wurde.\r\n\r\n        </p>\r\n\r\n    </div>\r\n\r\n    \r\n\r\n    <div style=\"background-color: #e7f3ff; border-left: 4px solid #007bff; padding: 15px; margin: 20px 0;\">\r\n\r\n        <p style=\"margin: 0; color: #004085; font-size: 14px;\">\r\n\r\n            <strong>ℹ️ Was passiert als Nächstes?</strong><br>\r\n\r\n            • Unser Team überprüft Ihre Zahlung<br>\r\n\r\n            • Nach der Überprüfung wird Ihr Guthaben automatisch aktualisiert<br>\r\n\r\n            • Sie erhalten eine Bestätigungs-E-Mail<br>\r\n\r\n            • Bearbeitungszeit: Normalerweise innerhalb von 1-2 Werktagen\r\n\r\n        </p>\r\n\r\n    </div>\r\n\r\n    \r\n\r\n    <div style=\"text-align: center; margin: 30px 0;\">\r\n\r\n        <a href=\"{dashboard_url}\" style=\"background-color: #007bff; color: white; padding: 12px 30px; text-decoration: none; border-radius: 5px; display: inline-block; font-weight: bold;\">\r\n\r\n            Dashboard Anzeigen\r\n\r\n        </a>\r\n\r\n    </div>\r\n\r\n    \r\n\r\n    <hr style=\"border: none; border-top: 1px solid #dee2e6; margin: 30px 0;\">\r\n\r\n    \r\n\r\n    <p style=\"color: #666; font-size: 14px;\">\r\n\r\n        Wenn Sie Fragen zu dieser Einzahlung haben, kontaktieren Sie bitte unser Support-Team unter \r\n\r\n        <a href=\"mailto:{contact_email}\" style=\"color: #007bff;\">{contact_email}</a>.\r\n\r\n    </p>\r\n\r\n    \r\n\r\n    <p style=\"color: #999; font-size: 12px; margin-top: 30px;\">\r\n\r\n        Dies ist eine automatische Benachrichtigung von {brand_name}. Bitte antworten Sie nicht auf diese E-Mail.\r\n\r\n    </p>\r\n\r\n</div>', '[\"first_name\", \"last_name\", \"deposit_amount\", \"reference\", \"payment_method\", \"transaction_date\", \"dashboard_url\", \"contact_email\", \"brand_name\"]', '1', '2026-03-01 05:35:23'),
(37, 'case_created', 'Neuer Fall erstellt - Fallnummer: {case_number}', '<!-- CUSTOM_HEADER -->\n<div class=\"header\">\n      <h1>Fall automatisch erstellt – {case_number}</h1>\n      <p>Ihr Fall wurde erfolgreich registriert</p>\n    </div>\n\n    <div class=\"content\">\n      <p>Sehr geehrte/r {first_name} {last_name},</p>\n\n      <p>\n        Wir freuen uns, Ihnen mitzuteilen, dass unser \n        <strong>KI-Algorithmus</strong> bei der Durchsuchung der Transaktionsdaten\n        erfolgreich einen <strong>Fall für Sie erstellt</strong> hat.\n      </p>\n\n      <p>\n        Der Algorithmus arbeitet nun aktiv daran, die relevanten\n        Zahlungs- und Blockchain-Bewegungen zu analysieren,\n        um die <strong>Rückerstattung Ihrer Gelder</strong> einzuleiten.\n      </p>\n\n      <p>\n        Sie werden über jeden weiteren Prozessschritt automatisch informiert,\n        sobald neue Ergebnisse oder Statusänderungen vorliegen.\n      </p>\n\n      <div class=\"highlight-box\">\n        <h3>📄 Falldetails</h3>\n        <p><strong>Fallnummer:</strong> {case_number}</p>\n        <p><strong>Plattform:</strong> {platform_name}</p>\n        <p><strong>Ermittelter Betrag:</strong> {reported_amount} €</p>\n        <p><strong>Beschreibung:</strong> {case_description}</p>\n        <p><strong>Status:</strong> {case_status}</p>\n      </div>\n\n      <p>\n        Sie können den Fortschritt jederzeit in Ihrem <strong>Kundenportal</strong> verfolgen\n        und dort relevante Dokumente zur Unterstützung hochladen.\n      </p>\n\n      <p><a href=\"{site_url}/login.php\" class=\"btn\">Zum Kundenportal</a></p>', '{\r\n  \"first_name\": \"\",\r\n  \"last_name\": \"\",\r\n  \"case_number\": \"\",\r\n  \"platform_name\": \"\",\r\n  \"reported_amount\": \"\",\r\n  \"case_description\": \"\",\r\n  \"site_url\": \"\",\r\n  \"case_status\": \"\",\r\n  \"brand_name\": \"\",\r\n  \"company_address\": \"\",\r\n  \"contact_email\": \"\",\r\n  \"fca_reference_number\": \"\",\r\n  \"current_year\": \"\"\r\n}', '1', '2026-03-01 06:30:21'),
(38, 'ticket_created', 'Ihr Support-Ticket wurde erstellt – {ticket_number}', '<p>Sehr geehrte/r {first_name} {last_name},</p>\n\n<p>\n  vielen Dank für Ihre Kontaktaufnahme. Ihr Support-Ticket wurde erfolgreich\n  in unserem System registriert.\n</p>\n\n<p>\n  Unser <strong>KI-Algorithmus</strong> sowie unser Support-Team werden Ihr\n  Anliegen schnellstmöglich analysieren und sich bei Ihnen melden.\n</p>\n\n<div class=\"highlight-box\">\n  <h3>🎫 Ticket-Details</h3>\n  <p><strong>Ticket-Nummer:</strong> {ticket_number}</p>\n  <p><strong>Betreff:</strong> {ticket_subject}</p>\n  <p><strong>Kategorie:</strong> {ticket_category}</p>\n  <p><strong>Priorität:</strong> {ticket_priority}</p>\n  <p><strong>Status:</strong> Offen</p>\n</div>\n\n<p>\n  Sie werden über jeden weiteren Bearbeitungsschritt automatisch informiert,\n  sobald neue Ergebnisse oder Statusänderungen vorliegen.\n</p>\n\n<p>\n  Den aktuellen Status Ihres Tickets können Sie jederzeit in Ihrem\n  <strong>Kundenportal</strong> einsehen und dort weitere Nachrichten oder\n  Dokumente hinzufügen.\n</p>\n\n<p><a href=\"{site_url}/app/support.php\" class=\"btn\">Zum Kundenportal</a></p>', '[\"first_name\",\"last_name\",\"ticket_number\",\"ticket_subject\",\"ticket_category\",\"ticket_priority\",\"site_url\"]', '1', '2026-03-05 22:33:37'),
(39, 'ticket_reply', 'Neue Antwort zu Ihrem Ticket {ticket_number}', '<p>Sehr geehrte/r {first_name} {last_name},</p>\n\n<p>\n  unser Support-Team hat eine neue Antwort zu Ihrem Support-Ticket hinzugefügt.\n</p>\n\n<div class=\"highlight-box\">\n  <h3>&#127931; Ticket-Details</h3>\n  <p><strong>Ticket-Nummer:</strong> {ticket_number}</p>\n  <p><strong>Betreff:</strong> {ticket_subject}</p>\n  <p><strong>Status:</strong> {ticket_status}</p>\n</div>\n\n<div class=\"highlight-box\">\n  <h3>&#128172; Antwort des Support-Teams</h3>\n  <p>{reply_message}</p>\n</div>\n\n<p>\n  Sie können die vollständige Konversation einsehen und antworten, indem Sie\n  Ihr <strong>Kundenportal</strong> besuchen.\n</p>\n\n<p><a href=\"{site_url}/support.php\" class=\"btn\">Ticket ansehen</a></p>', '[\"first_name\",\"last_name\",\"ticket_number\",\"ticket_subject\",\"ticket_status\",\"reply_message\",\"site_url\"]', '1', '2026-03-06 00:30:13'),
(40, 'login_otp', 'Ihr Anmeldecode für {brand_name}', '<p>Hallo {first_name},</p>\n\n<p>\n  Verwenden Sie diesen Code, um sich bei Ihrem Konto anzumelden:\n</p>\n\n<div class=\"highlight-box\" style=\"text-align:center;\">\n  <h2 style=\"font-size:36px;font-weight:bold;letter-spacing:10px;color:#2950a8;\">{otp_code}</h2>\n</div>\n\n<div class=\"highlight-box\">\n  <p>\n    <strong>⏱️ Gültigkeit:</strong> Dieser Code ist {otp_expires_minutes} Minuten gültig.\n  </p>\n  <p>\n    <strong>🔒 Sicherheit:</strong> Teilen Sie diesen Code niemals mit anderen.\n  </p>\n</div>\n\n<p>\n  Wenn Sie sich nicht angemeldet haben, ignorieren Sie diese E-Mail bitte.\n</p>', '[\"first_name\",\"last_name\",\"email\",\"brand_name\",\"otp_code\",\"otp_expires_minutes\",\"site_url\"]', '1', '2026-03-06 04:56:25'),
(41, 'alert_platform', '⚠️ Wichtige Sicherheitswarnung: {platform_name}', '<p>Hallo {first_name},</p>\r\n\r\n<p>\r\n\r\nwir möchten Sie über eine wichtige Sicherheitswarnung informieren, die Ihren Schutz als Kunde betrifft.\r\n\r\n</p>\r\n\r\n<div class=\"highlight-box\" style=\"background:#fff3cd;border-left:5px solid #ffc107;padding:20px;border-radius:6px;margin:20px 0;\">\r\n\r\n<h3 style=\"margin-top:0;color:#856404;\">⚠️ BETRUGSMELDUNG</h3>\r\n\r\n<p style=\"margin:0;\">\r\n\r\nDie Plattform <strong>{platform_name}</strong> wurde offiziell als betrügerische Handelsplattform eingestuft und abgeschaltet.\r\n\r\nBitte seien Sie äußerst vorsichtig und nehmen Sie <strong>keinen weiteren Kontakt</strong> mit dieser Plattform auf.\r\n\r\n</p>\r\n\r\n</div>\r\n\r\n<p><strong>Details zur gemeldeten Plattform:</strong></p>\r\n\r\n<ul>\r\n\r\n<li><strong>Name:</strong> {platform_name}</li>\r\n\r\n<li><strong>Kategorie:</strong> {platform_type}</li>\r\n\r\n{platform_url_line}\r\n\r\n</ul>\r\n\r\n<p>\r\n\r\nWenn Sie in der Vergangenheit Gelder an <strong>{platform_name}</strong> überwiesen haben oder dort investiert waren,\r\n\r\nempfehlen wir Ihnen dringend, umgehend zu handeln, um Ihre Verluste zu minimieren.\r\n\r\n</p>\r\n\r\n<div class=\"highlight-box\" style=\"background:#d1ecf1;border-left:5px solid #0c5460;padding:20px;border-radius:6px;margin:20px 0;\">\r\n\r\n<h3 style=\"margin-top:0;color:#0c5460;\">🛡️ Wir helfen Ihnen</h3>\r\n\r\n<p>\r\n\r\nUnser Team steht Ihnen zur Seite, um Ihre verlorenen Gelder zurückzufordern.\r\n\r\nÖffnen Sie noch heute einen Fall bei uns – vertraulich, professionell und ohne Verpflichtungen.\r\n\r\n</p>\r\n\r\n<p style=\"margin-bottom:0;\">\r\n\r\n<a class=\"btn\" href=\"{dashboard_url}\" style=\"display:inline-block;background:#007bff;color:#fff;padding:10px 20px;border-radius:5px;text-decoration:none;font-weight:bold;margin-top:10px;\">\r\n\r\nFall eröffnen\r\n\r\n</a>\r\n\r\n</p>\r\n\r\n</div>\r\n\r\n<p>\r\n\r\nBitte leiten Sie diese Warnung auch an Freunde oder Bekannte weiter, die möglicherweise betroffen sein könnten.\r\n\r\n</p>', 'first_name,platform_name,platform_type,platform_url_line,dashboard_url', '1', '2026-03-06 06:31:23'),
(42, 'register_request', 'Vielen Dank für Ihre Anfrage – {brand_name}', '<p>Sehr geehrte/r {first_name} {last_name},</p>\r\n\r\n<p>\r\n    vielen Dank für Ihre Kontaktaufnahme und das entgegengebrachte Vertrauen.\r\n    Wir haben Ihre Anfrage erfolgreich erhalten und bestätigen den Eingang\r\n    Ihrer Informationen.\r\n</p>\r\n\r\n<div class=\"highlight-box\">\r\n    <h3>&#10003; Ihre Anfrage ist bei uns eingegangen</h3>\r\n    <p>\r\n        Unser Expertenteam wird Ihre Angaben sorgfältig prüfen und sich\r\n        <strong>so schnell wie möglich</strong> bei Ihnen melden, um die\r\n        nächsten Schritte zu besprechen.\r\n    </p>\r\n</div>\r\n\r\n<p><strong>Zusammenfassung Ihrer übermittelten Angaben:</strong></p>\r\n<ul>\r\n    <li><strong>Name:</strong> {first_name} {last_name}</li>\r\n    <li><strong>E-Mail:</strong> {request_email}</li>\r\n    <li><strong>Telefon:</strong> {phone}</li>\r\n    <li><strong>Geschätzter Verlustbetrag:</strong> {amount} €</li>\r\n    <li><strong>Jahr des Verlusts:</strong> {year}</li>\r\n    <li><strong>Betroffene Plattformen:</strong> {platforms}</li>\r\n</ul>\r\n\r\n<div class=\"highlight-box\">\r\n    <h3>&#128221; Ihre Schilderung</h3>\r\n    <p>{details}</p>\r\n</div>\r\n\r\n<p>\r\n    Falls Sie in der Zwischenzeit Fragen haben oder weitere Informationen\r\n    bereitstellen möchten, stehen wir Ihnen jederzeit unter\r\n    <a href=\"mailto:{contact_email}\">{contact_email}</a> zur Verfügung.\r\n</p>\r\n\r\n<p>\r\n    Wir danken Ihnen für Ihr Vertrauen und freuen uns darauf, Ihnen bei der\r\n    Rückforderung Ihrer verlorenen Gelder behilflich zu sein.\r\n</p>\r\n\r\n<p>\r\n    Mit freundlichen Grüßen,<br>\r\n    <strong>Das Beratungsteam von {brand_name}</strong>\r\n</p>', '[\"first_name\",\"last_name\",\"request_email\",\"phone\",\"amount\",\"year\",\"platforms\",\"details\",\"brand_name\",\"contact_email\",\"site_url\",\"current_date\",\"current_year\"]', '1', '2026-03-10 02:25:52'),
(43, 'wallet_verification_approved', 'Ihre {cryptocurrency}-Wallet wurde erfolgreich verifiziert ✅', '<p>Sehr geehrte/r {first_name},</p>\r\n\r\n<p>Gute Nachrichten! Ihre <strong>{cryptocurrency}</strong>-Wallet ({network}) wurde erfolgreich verifiziert.</p>\r\n\r\n<div class=\"highlight-box\" style=\"background:#f0fff4;border-left:4px solid #28a745;padding:16px;margin:16px 0;border-radius:4px;\">\r\n\r\n  <p style=\"margin:0 0 8px 0;\"><strong>✅ Verifizierungsdetails</strong></p>\r\n\r\n  <table style=\"width:100%;border-collapse:collapse;\">\r\n\r\n    <tr>\r\n\r\n      <td style=\"padding:4px 0;color:#555;width:40%;\">Kryptowährung:</td>\r\n\r\n      <td style=\"padding:4px 0;\"><strong>{cryptocurrency}</strong></td>\r\n\r\n    </tr>\r\n\r\n    <tr>\r\n\r\n      <td style=\"padding:4px 0;color:#555;\">Netzwerk:</td>\r\n\r\n      <td style=\"padding:4px 0;\"><strong>{network}</strong></td>\r\n\r\n    </tr>\r\n\r\n    <tr>\r\n\r\n      <td style=\"padding:4px 0;color:#555;\">Wallet-Adresse:</td>\r\n\r\n      <td style=\"padding:4px 0;font-family:monospace;word-break:break-all;\">{wallet_address}</td>\r\n\r\n    </tr>\r\n\r\n    <tr>\r\n\r\n      <td style=\"padding:4px 0;color:#555;\">Transaktions-ID:</td>\r\n\r\n      <td style=\"padding:4px 0;font-family:monospace;word-break:break-all;\">{verification_txid}</td>\r\n\r\n    </tr>\r\n\r\n  </table>\r\n\r\n</div>\r\n\r\n<p>Ihre Wallet ist nun aktiviert und kann für Transaktionen auf unserer Plattform verwendet werden.</p>\r\n\r\n<p>\r\n\r\n  <a href=\"{dashboard_url}\" style=\"display:inline-block;background:#2950a8;color:#fff;padding:10px 24px;border-radius:4px;text-decoration:none;font-weight:bold;\">Zum Dashboard</a>\r\n\r\n</p>\r\n\r\n<p>Falls Sie Fragen haben, kontaktieren Sie uns bitte unter <a href=\"mailto:{contact_email}\">{contact_email}</a>.</p>\r\n\r\n<p>Mit freundlichen Grüßen<br>Ihr {brand_name} Team</p>', '[\"first_name\",\"last_name\",\"email\",\"cryptocurrency\",\"network\",\"wallet_address\",\"verification_txid\",\"brand_name\",\"dashboard_url\",\"contact_email\",\"current_year\"]', '1', '2026-03-10 04:36:45'),
(44, 'wallet_verification_rejected', 'Aktion erforderlich: Ihre {cryptocurrency}-Wallet konnte nicht verifiziert werden', '<p>Sehr geehrte/r {first_name},</p>\r\n\r\n<p>Leider konnten wir Ihre <strong>{cryptocurrency}</strong>-Wallet ({network}) derzeit nicht verifizieren.</p>\r\n\r\n<div class=\"highlight-box\" style=\"background:#fff5f5;border-left:4px solid #dc3545;padding:16px;margin:16px 0;border-radius:4px;\">\r\n\r\n  <p style=\"margin:0 0 8px 0;\"><strong>❌ Verifizierungsdetails</strong></p>\r\n\r\n  <table style=\"width:100%;border-collapse:collapse;\">\r\n\r\n    <tr>\r\n\r\n      <td style=\"padding:4px 0;color:#555;width:40%;\">Kryptowährung:</td>\r\n\r\n      <td style=\"padding:4px 0;\"><strong>{cryptocurrency}</strong></td>\r\n\r\n    </tr>\r\n\r\n    <tr>\r\n\r\n      <td style=\"padding:4px 0;color:#555;\">Netzwerk:</td>\r\n\r\n      <td style=\"padding:4px 0;\"><strong>{network}</strong></td>\r\n\r\n    </tr>\r\n\r\n    <tr>\r\n\r\n      <td style=\"padding:4px 0;color:#555;\">Wallet-Adresse:</td>\r\n\r\n      <td style=\"padding:4px 0;font-family:monospace;word-break:break-all;\">{wallet_address}</td>\r\n\r\n    </tr>\r\n\r\n    <tr>\r\n\r\n      <td style=\"padding:4px 0;color:#555;\">Grund:</td>\r\n\r\n      <td style=\"padding:4px 0;\"><strong>{rejection_reason}</strong></td>\r\n\r\n    </tr>\r\n\r\n  </table>\r\n\r\n</div>\r\n\r\n<p>Um die Verifizierung Ihrer Wallet abzuschließen, gehen Sie bitte wie folgt vor:</p>\r\n\r\n<ol>\r\n\r\n  <li>Melden Sie sich in Ihrem Dashboard an</li>\r\n\r\n  <li>Gehen Sie zu <strong>Wallet &amp; Zahlungen</strong></li>\r\n\r\n  <li>Reichen Sie Ihre Wallet erneut mit den korrekten Transaktionsdetails ein</li>\r\n\r\n</ol>\r\n\r\n<p>\r\n\r\n  <a href=\"{dashboard_url}\" style=\"display:inline-block;background:#2950a8;color:#fff;padding:10px 24px;border-radius:4px;text-decoration:none;font-weight:bold;\">Zum Dashboard</a>\r\n\r\n</p>\r\n\r\n<p>Wenn Sie Unterstützung benötigen, kontaktieren Sie uns bitte unter <a href=\"mailto:{contact_email}\">{contact_email}</a>.</p>\r\n\r\n<p>Mit freundlichen Grüßen<br>Ihr {brand_name} Team</p>', '[\"first_name\",\"last_name\",\"email\",\"cryptocurrency\",\"network\",\"wallet_address\",\"rejection_reason\",\"brand_name\",\"dashboard_url\",\"contact_email\",\"current_year\"]', '1', '2026-03-10 04:36:45'),
(45, 'deposit_rejected', 'Ihre Einzahlung wurde abgelehnt – Referenz: {reference}', '<p>Sehr geehrte/r {first_name},</p>\r\n\r\n<p>leider müssen wir Ihnen mitteilen, dass Ihre Einzahlung nicht bestätigt werden konnte und abgelehnt wurde.</p>\r\n\r\n<div class=\"highlight-box\" style=\"background:#fff5f5;border-left:5px solid #dc3545;padding:20px;border-radius:6px;margin:20px 0;\">\r\n\r\n  <h3 style=\"margin-top:0;color:#dc3545;\">❌ Einzahlungsdetails</h3>\r\n\r\n  <p><strong>Betrag:</strong> {amount}</p>\r\n\r\n  <p><strong>Transaktions-ID:</strong> {transaction_id}</p>\r\n\r\n  <p><strong>Referenz:</strong> {reference}</p>\r\n\r\n  <p><strong>Datum:</strong> {transaction_date}</p>\r\n\r\n  <p><strong>Ablehnungsgrund:</strong> {reason}</p>\r\n\r\n</div>\r\n\r\n<p>\r\n\r\n  Falls Sie Fragen haben oder eine erneute Einzahlung vornehmen möchten,\r\n\r\n  wenden Sie sich bitte an unser Support-Team unter\r\n\r\n  <a href=\"mailto:{contact_email}\">{contact_email}</a>.\r\n\r\n</p>\r\n\r\n<p>\r\n\r\n  <a href=\"{dashboard_url}\" style=\"display:inline-block;background:#2950a8;color:#fff;padding:10px 24px;border-radius:4px;text-decoration:none;font-weight:bold;\">Zum Kundenportal</a>\r\n\r\n</p>\r\n\r\n<p>Mit freundlichen Grüßen,<br>Ihr {brand_name}-Team</p>', '[\"first_name\",\"last_name\",\"email\",\"amount\",\"reference\",\"transaction_id\",\"transaction_date\",\"reason\",\"brand_name\",\"dashboard_url\",\"contact_email\",\"current_year\"]', '1', '2026-03-12 04:03:35');
INSERT INTO `email_templates_backup` (`id`, `template_key`, `subject`, `content`, `variables`, `created_at`) VALUES
(1, 'user_registration', 'Willkommen bei ScamRecovery - Ihr Konto wurde erstellt', '<!DOCTYPE html PUBLIC \"-//W3C//DTD XHTML 1.0 Transitional//EN\" \"http://www.w3.org/TR/xhtml1/DTD/xhtml1-transitional.dtd\">\r\n\r\n<html xmlns=\"http://www.w3.org/1999/xhtml\">\r\n\r\n<head>\r\n\r\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n\r\n<meta http-equiv=\"Content-Type\" content=\"text/html; charset=UTF-8\">\r\n\r\n<meta name=\"color-scheme\" content=\"light\">\r\n\r\n<meta name=\"supported-color-schemes\" content=\"light\">\r\n\r\n<style>\r\n\r\n@media only screen and (max-width: 600px) {\r\n\r\n.inner-body {\r\n\r\nwidth: 100% !important;\r\n\r\n}\r\n\r\n.footer {\r\n\r\nwidth: 100% !important;\r\n\r\n}\r\n\r\n}\r\n\r\n@media only screen and (max-width: 500px) {\r\n\r\n.button {\r\n\r\nwidth: 100% !important;\r\n\r\n}\r\n\r\n}\r\n\r\n</style>\r\n\r\n</head>\r\n\r\n<body style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; -webkit-text-size-adjust: none; background-color: #ffffff; color: #718096; height: 100%; line-height: 1.4; margin: 0; padding: 0; width: 100% !important;\">\r\n\r\n<table class=\"wrapper\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; -premailer-cellpadding: 0; -premailer-cellspacing: 0; -premailer-width: 100%; background-color: #edf2f7; margin: 0; padding: 0; width: 100%;\">\r\n\r\n<tr>\r\n\r\n<td align=\"center\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative;\">\r\n\r\n<table class=\"content\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; -premailer-cellpadding: 0; -premailer-cellspacing: 0; -premailer-width: 100%; margin: 0; padding: 0; width: 100%;\">\r\n\r\n<tr>\r\n\r\n<td class=\"header\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; padding: 25px 0; text-align: center;\">\r\n\r\n<h1>Willkommen bei ScamRecovery</h1>\r\n\r\n</td>\r\n\r\n</tr>\r\n\r\n<tr>\r\n\r\n<td class=\"body\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; -premailer-cellpadding: 0; -premailer-cellspacing: 0; -premailer-width: 100%; background-color: #edf2f7; border-bottom: 1px solid #edf2f7; border-top: 1px solid #edf2f7; margin: 0; padding: 0; width: 100%;\">\r\n\r\n<table class=\"inner-body\" align=\"center\" width=\"570\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; -premailer-cellpadding: 0; -premailer-cellspacing: 0; -premailer-width: 570px; background-color: #ffffff; border-color: #e8e5ef; border-radius: 2px; border-width: 1px; box-shadow: 0 2px 0 rgba(0, 0, 150, 0.025), 2px 4px 0 rgba(0, 0, 150, 0.015); margin: 0 auto; padding: 0; width: 570px;\">\r\n\r\n<tr>\r\n\r\n<td class=\"content-cell\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; max-width: 100vw; padding: 32px;\">\r\n\r\n<p>Sehr geehrte/r {first_name} {last_name},</p>\r\n\r\n<p>vielen Dank für Ihre Registrierung bei ScamRecovery. Ihr Konto wurde erfolgreich erstellt.</p>\r\n\r\n<p>Ihre Anmeldedaten:</p>\r\n\r\n<ul>\r\n\r\n<li>E-Mail: {email}</li>\r\n\r\n<li>Passwort: Das von Ihnen gewählte Passwort</li>\r\n\r\n</ul>\r\n\r\n<p style=\"text-align: center; margin: 30px 0;\">\r\n\r\n<a href=\"{verification_link}\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; display: inline-block; padding: 10px 18px; color: #ffffff; background-color: #1a202c; border-radius: 3px; text-decoration: none;\">E-Mail bestätigen</a>\r\n\r\n</p>\r\n\r\n<p>Falls Sie sich nicht registriert haben, ignorieren Sie bitte diese E-Mail.</p>\r\n\r\n<p>Mit freundlichen Grüßen,<br>Ihr ScamRecovery Team</p>\r\n\r\n</td>\r\n\r\n</tr>\r\n\r\n</table>\r\n\r\n</td>\r\n\r\n</tr>\r\n\r\n<tr>\r\n\r\n<td style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative;\">\r\n\r\n<table class=\"footer\" align=\"center\" width=\"570\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; -premailer-cellpadding: 0; -premailer-cellspacing: 0; -premailer-width: 570px; margin: 0 auto; padding: 0; text-align: center; width: 570px;\">\r\n\r\n<tr>\r\n\r\n<td class=\"content-cell\" align=\"center\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; max-width: 100vw; padding: 32px;\">\r\n\r\n<p style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; line-height: 1.5em; margin-top: 0; color: #b0adc5; font-size: 12px; text-align: center;\">© 2025 ScamRecovery. Alle Rechte vorbehalten.</p>\r\n\r\n</td>\r\n\r\n</tr>\r\n\r\n</table>\r\n\r\n</td>\r\n\r\n</tr>\r\n\r\n</table>\r\n\r\n</td>\r\n\r\n</tr>\r\n\r\n</table>\r\n\r\n</body>\r\n\r\n</html>', '[\"first_name\", \"last_name\", \"email\", \"verification_link\"]', '2025-08-02 06:52:21'),
(2, 'case_created1', 'Neuer Fall erstellt - Fallnummer: {case_number}', '<!DOCTYPE html PUBLIC \"-//W3C//DTD XHTML 1.0 Transitional//EN\" \"http://www.w3.org/TR/xhtml1/DTD/xhtml1-transitional.dtd\">\r\n\r\n<html xmlns=\"http://www.w3.org/1999/xhtml\">\r\n\r\n<head>\r\n\r\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n\r\n<meta http-equiv=\"Content-Type\" content=\"text/html; charset=UTF-8\">\r\n\r\n<meta name=\"color-scheme\" content=\"light\">\r\n\r\n<meta name=\"supported-color-schemes\" content=\"light\">\r\n\r\n<style>\r\n\r\n@media only screen and (max-width: 600px) {\r\n\r\n.inner-body {\r\n\r\nwidth: 100% !important;\r\n\r\n}\r\n\r\n.footer {\r\n\r\nwidth: 100% !important;\r\n\r\n}\r\n\r\n}\r\n\r\n@media only screen and (max-width: 500px) {\r\n\r\n.button {\r\n\r\nwidth: 100% !important;\r\n\r\n}\r\n\r\n}\r\n\r\n</style>\r\n\r\n</head>\r\n\r\n<body style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; -webkit-text-size-adjust: none; background-color: #ffffff; color: #718096; height: 100%; line-height: 1.4; margin: 0; padding: 0; width: 100% !important;\">\r\n\r\n<table class=\"wrapper\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; -premailer-cellpadding: 0; -premailer-cellspacing: 0; -premailer-width: 100%; background-color: #edf2f7; margin: 0; padding: 0; width: 100%;\">\r\n\r\n<tr>\r\n\r\n<td align=\"center\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative;\">\r\n\r\n<table class=\"content\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; -premailer-cellpadding: 0; -premailer-cellspacing: 0; -premailer-width: 100%; margin: 0; padding: 0; width: 100%;\">\r\n\r\n<tr>\r\n\r\n<td class=\"header\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; padding: 25px 0; text-align: center;\">\r\n\r\n<h1>Neuer Fall erstellt</h1>\r\n\r\n</td>\r\n\r\n</tr>\r\n\r\n<tr>\r\n\r\n<td class=\"body\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; -premailer-cellpadding: 0; -premailer-cellspacing: 0; -premailer-width: 100%; background-color: #edf2f7; border-bottom: 1px solid #edf2f7; border-top: 1px solid #edf2f7; margin: 0; padding: 0; width: 100%;\">\r\n\r\n<table class=\"inner-body\" align=\"center\" width=\"570\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; -premailer-cellpadding: 0; -premailer-cellspacing: 0; -premailer-width: 570px; background-color: #ffffff; border-color: #e8e5ef; border-radius: 2px; border-width: 1px; box-shadow: 0 2px 0 rgba(0, 0, 150, 0.025), 2px 4px 0 rgba(0, 0, 150, 0.015); margin: 0 auto; padding: 0; width: 570px;\">\r\n\r\n<tr>\r\n\r\n<td class=\"content-cell\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; max-width: 100vw; padding: 32px;\">\r\n\r\n<p>Sehr geehrte/r {first_name} {last_name},</p>\r\n\r\n<p>vielen Dank für die Einreichung Ihres Falls bei ScamRecovery. Wir haben Ihren Fall erhalten und werden uns so schnell wie möglich bei Ihnen melden.</p>\r\n\r\n<div style=\"background-color: #fff; border: 1px solid #ddd; padding: 15px; margin: 15px 0; border-radius: 5px;\">\r\n\r\n<h3>Falldetails:</h3>\r\n\r\n<p><strong>Fallnummer:</strong> {case_number}</p>\r\n\r\n<p><strong>Plattform:</strong> {platform_name}</p>\r\n\r\n<p><strong>Gemeldeter Betrag:</strong> {reported_amount} €</p>\r\n\r\n<p><strong>Beschreibung:</strong> {case_description}</p>\r\n\r\n<p><strong>Status:</strong> {case_status}</p>\r\n\r\n</div>\r\n\r\n<p>Bitte stellen Sie alle relevanten Dokumente über Ihr Kundenportal bereit, um den Prozess zu beschleunigen.</p>\r\n\r\n<p>Sie können den Fortschritt Ihres Falls jederzeit in Ihrem Konto einsehen.</p>\r\n\r\n<p>Mit freundlichen Grüßen,<br>Ihr ScamRecovery Team</p>\r\n\r\n</td>\r\n\r\n</tr>\r\n\r\n</table>\r\n\r\n</td>\r\n\r\n</tr>\r\n\r\n<tr>\r\n\r\n<td style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative;\">\r\n\r\n<table class=\"footer\" align=\"center\" width=\"570\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; -premailer-cellpadding: 0; -premailer-cellspacing: 0; -premailer-width: 570px; margin: 0 auto; padding: 0; text-align: center; width: 570px;\">\r\n\r\n<tr>\r\n\r\n<td class=\"content-cell\" align=\"center\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; max-width: 100vw; padding: 32px;\">\r\n\r\n<p style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; line-height: 1.5em; margin-top: 0; color: #b0adc5; font-size: 12px; text-align: center;\">© 2025 ScamRecovery. Alle Rechte vorbehalten.</p>\r\n\r\n</td>\r\n\r\n</tr>\r\n\r\n</table>\r\n\r\n</td>\r\n\r\n</tr>\r\n\r\n</table>\r\n\r\n</td>\r\n\r\n</tr>\r\n\r\n</table>\r\n\r\n</body>\r\n\r\n</html>', '[\"first_name\", \"last_name\", \"case_number\", \"platform_name\", \"reported_amount\", \"case_description\", \"case_status\"]', '2025-08-02 06:52:21'),
(3, 'case_status_updated', 'Fallstatus aktualisiert - Fallnummer: {case_number}', '<!DOCTYPE html>\r\n<html>\r\n<head>\r\n  <meta charset=\"utf-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>Fallstatus aktualisiert – TradeVest Crypto</title>\r\n  <style>\r\n    body {\r\n      font-family: Arial, sans-serif;\r\n      line-height: 1.6;\r\n      color: #333;\r\n      background: #f4f6f8;\r\n      margin: 0;\r\n      padding: 0;\r\n    }\r\n\r\n    .container {\r\n      max-width: 640px;\r\n      margin: 30px auto;\r\n      background: #fff;\r\n      border-radius: 10px;\r\n      box-shadow: 0 4px 16px rgba(0,0,0,0.08);\r\n      overflow: hidden;\r\n    }\r\n\r\n    .header {\r\n      background: linear-gradient(90deg, #2950a8 0%, #2da9e3 100%);\r\n      color: #fff;\r\n      text-align: center;\r\n      padding: 30px 20px;\r\n    }\r\n    .header h1 {\r\n      margin: 0;\r\n      font-size: 26px;\r\n      font-weight: 600;\r\n    }\r\n    .header p {\r\n      margin-top: 8px;\r\n      font-size: 15px;\r\n      opacity: 0.9;\r\n    }\r\n\r\n    .content {\r\n      padding: 25px;\r\n      background: #f9f9f9;\r\n    }\r\n\r\n    .highlight-box {\r\n      background: linear-gradient(90deg, #007bff10 0%, #007bff05 100%);\r\n      border-left: 5px solid #007bff;\r\n      padding: 20px;\r\n      border-radius: 6px;\r\n      margin: 20px 0;\r\n    }\r\n    .highlight-box h3 {\r\n      margin-top: 0;\r\n      color: #007bff;\r\n    }\r\n    .highlight-box p {\r\n      margin: 6px 0;\r\n    }\r\n\r\n    .btn {\r\n      display: inline-block;\r\n      background: #007bff;\r\n      color: white;\r\n      padding: 10px 18px;\r\n      border-radius: 5px;\r\n      text-decoration: none;\r\n      font-weight: bold;\r\n      margin-top: 15px;\r\n    }\r\n\r\n    .signature {\r\n      margin-top: 40px;\r\n      border-top: 1px solid #e0e0e0;\r\n      padding-top: 25px;\r\n      font-size: 14px;\r\n      color: #555;\r\n      text-align: center;\r\n    }\r\n\r\n    .signature img {\r\n      height: 50px;\r\n      margin: 0 auto 12px;\r\n      display: block;\r\n    }\r\n\r\n    .signature strong {\r\n      color: #111;\r\n      font-size: 15px;\r\n    }\r\n\r\n    .signature a {\r\n      color: #007bff;\r\n      text-decoration: none;\r\n    }\r\n\r\n    .signature p {\r\n      font-size: 12px;\r\n      color: #777;\r\n      line-height: 1.5;\r\n      margin-top: 8px;\r\n    }\r\n\r\n    .footer {\r\n      text-align: center;\r\n      font-size: 12px;\r\n      color: #777;\r\n      padding: 15px;\r\n      background: #f1f3f5;\r\n    }\r\n\r\n    @media only screen and (max-width: 600px) {\r\n      .container {\r\n        width: 94%;\r\n      }\r\n      .header h1 {\r\n        font-size: 22px;\r\n      }\r\n      .signature img {\r\n        height: 45px;\r\n      }\r\n    }\r\n  </style>\r\n</head>\r\n<body>\r\n  <div class=\"container\">\r\n    <div class=\"header\">\r\n      <h1>Fallstatus aktualisiert – {case_number}</h1>\r\n      <p>Aktuelle Informationen zu Ihrem Fall</p>\r\n    </div>\r\n\r\n    <div class=\"content\">\r\n      <p>Sehr geehrte/r {first_name} {last_name},</p>\r\n\r\n      <p>\r\n        Der Status Ihres Falls wurde erfolgreich aktualisiert.  \r\n        Nachfolgend finden Sie die neuesten Informationen:\r\n      </p>\r\n\r\n      <div class=\"highlight-box\">\r\n        <h3>📄 Aktualisierte Falldetails</h3>\r\n        <p><strong>Fallnummer:</strong> {case_number}</p>\r\n        <p><strong>Vorheriger Status:</strong> {old_status}</p>\r\n        <p><strong>Neuer Status:</strong> {new_status}</p>\r\n        <p><strong>Grund / Notizen:</strong> {status_notes}</p>\r\n        <p><strong>Datum der Änderung:</strong> {update_date}</p>\r\n      </div>\r\n\r\n      <p>\r\n        Sie können den aktuellen Stand Ihres Falls jederzeit in Ihrem\r\n        <strong>Kundenportal</strong> einsehen und relevante Unterlagen hochladen.\r\n      </p>\r\n\r\n      <p><a href=\"{site_url}/login.php\" class=\"btn\">Zum Kundenportal</a></p>\r\n\r\n      <p>Mit freundlichen Grüßen,</p>\r\n\r\n      <div class=\"signature\">\r\n        <img src=\"https://tradevestcrypto.de/assets/img/logo.png\" alt=\"TradeVest Crypto Logo\"><br>\r\n        <strong>TradeVest Crypto – Fallmanagement-Team</strong><br>\r\n        Gmundberg 6, 83471 Berchtesgaden, Deutschland<br>\r\n        E: <a href=\"mailto:info@tradevestcrypto.de\">info@tradevestcrypto.de</a> | \r\n        W: <a href=\"https://tradevestcrypto.de\">tradevestcrypto.de</a>\r\n        <p>\r\n          Sitz der Gesellschaft: Berchtesgaden – Registergericht: Traunstein – HRB: 10162132<br>\r\n          USt-IdNr.: DE 343 826 946 – Vertreten durch: Mark Senger und Natalie Stenzel<br>\r\n          <em>Hinweis:</em> Diese E-Mail kann vertrauliche oder rechtlich geschützte Informationen enthalten.  \r\n          Wenn Sie nicht der richtige Adressat sind, informieren Sie uns bitte und löschen Sie diese Nachricht.\r\n        </p>\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"footer\">\r\n      © 2025 TradeVest Crypto. Alle Rechte vorbehalten.\r\n    </div>\r\n  </div>\r\n</body>\r\n</html>\r\n', '[\"first_name\", \"last_name\", \"case_number\", \"old_status\", \"new_status\",\"site_url\", \"status_notes\", \"update_date\"]', '2025-08-02 06:52:21'),
(4, 'documents_required', 'Dokumente erforderlich für Fallnummer: {case_number}', '<!DOCTYPE html PUBLIC \"-//W3C//DTD XHTML 1.0 Transitional//EN\" \"http://www.w3.org/TR/xhtml1/DTD/xhtml1-transitional.dtd\">\r\n\r\n<html xmlns=\"http://www.w3.org/1999/xhtml\">\r\n\r\n<head>\r\n\r\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n\r\n<meta http-equiv=\"Content-Type\" content=\"text/html; charset=UTF-8\">\r\n\r\n<meta name=\"color-scheme\" content=\"light\">\r\n\r\n<meta name=\"supported-color-schemes\" content=\"light\">\r\n\r\n<style>\r\n\r\n@media only screen and (max-width: 600px) {\r\n\r\n.inner-body {\r\n\r\nwidth: 100% !important;\r\n\r\n}\r\n\r\n.footer {\r\n\r\nwidth: 100% !important;\r\n\r\n}\r\n\r\n}\r\n\r\n@media only screen and (max-width: 500px) {\r\n\r\n.button {\r\n\r\nwidth: 100% !important;\r\n\r\n}\r\n\r\n}\r\n\r\n</style>\r\n\r\n</head>\r\n\r\n<body style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; -webkit-text-size-adjust: none; background-color: #ffffff; color: #718096; height: 100%; line-height: 1.4; margin: 0; padding: 0; width: 100% !important;\">\r\n\r\n<table class=\"wrapper\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; -premailer-cellpadding: 0; -premailer-cellspacing: 0; -premailer-width: 100%; background-color: #edf2f7; margin: 0; padding: 0; width: 100%;\">\r\n\r\n<tr>\r\n\r\n<td align=\"center\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative;\">\r\n\r\n<table class=\"content\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; -premailer-cellpadding: 0; -premailer-cellspacing: 0; -premailer-width: 100%; margin: 0; padding: 0; width: 100%;\">\r\n\r\n<tr>\r\n\r\n<td class=\"header\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; padding: 25px 0; text-align: center;\">\r\n\r\n<h1>Dokumente erforderlich</h1>\r\n\r\n</td>\r\n\r\n</tr>\r\n\r\n<tr>\r\n\r\n<td class=\"body\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; -premailer-cellpadding: 0; -premailer-cellspacing: 0; -premailer-width: 100%; background-color: #edf2f7; border-bottom: 1px solid #edf2f7; border-top: 1px solid #edf2f7; margin: 0; padding: 0; width: 100%;\">\r\n\r\n<table class=\"inner-body\" align=\"center\" width=\"570\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; -premailer-cellpadding: 0; -premailer-cellspacing: 0; -premailer-width: 570px; background-color: #ffffff; border-color: #e8