n=\"center\" width=\"570\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; -premailer-cellpadding: 0; -premailer-cellspacing: 0; -premailer-width: 570px; margin: 0 auto; padding: 0; text-align: center; width: 570px;\">\r\n\r\n<tr>\r\n\r\n<td class=\"content-cell\" align=\"center\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; max-width: 100vw; padding: 32px;\">\r\n\r\n<p style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; line-height: 1.5em; margin-top: 0; color: #b0adc5; font-size: 12px; text-align: center;\">© 2025 {{sbrand}}. Alle Rechte vorbehalten.</p>\r\n\r\n</td>\r\n\r\n</tr>\r\n\r\n</table>\r\n\r\n</td>\r\n\r\n</tr>\r\n\r\n</table>\r\n\r\n</td>\r\n\r\n</tr>\r\n\r\n</table>\r\n\r\n</body>\r\n\r\n</html>', '[\"name\",\"email\",\"pass\",\"sbrand\",\"surl\",\"sphone\",\"semail\"]', '2025-08-02 07:54:52'),
(17, 'deposit_confirmation', 'Einzahlungsbestätigung - Referenz: {reference}', '<!DOCTYPE html>\r\n<html>\r\n<head>\r\n  <meta charset=\"utf-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>Auszahlung abgeschlossen – TradeVest Crypto</title>\r\n  <style>\r\n    body {\r\n      font-family: Arial, sans-serif;\r\n      line-height: 1.6;\r\n      color: #333;\r\n      background: #f4f6f8;\r\n      margin: 0;\r\n      padding: 0;\r\n    }\r\n\r\n    .container {\r\n      max-width: 640px;\r\n      margin: 30px auto;\r\n      background: #fff;\r\n      border-radius: 10px;\r\n      box-shadow: 0 4px 16px rgba(0,0,0,0.08);\r\n      overflow: hidden;\r\n    }\r\n\r\n    .header {\r\n      background: linear-gradient(90deg, #2950a8 0%, #2da9e3 100%);\r\n      color: #fff;\r\n      text-align: center;\r\n      padding: 30px 20px;\r\n    }\r\n\r\n    .header h1 {\r\n      margin: 0;\r\n      font-size: 26px;\r\n      font-weight: 600;\r\n    }\r\n\r\n    .header p {\r\n      margin-top: 8px;\r\n      font-size: 15px;\r\n      opacity: 0.9;\r\n    }\r\n\r\n    .content {\r\n      padding: 25px;\r\n      background: #f9f9f9;\r\n    }\r\n\r\n    .highlight-box {\r\n      background: linear-gradient(90deg, #007bff10 0%, #007bff05 100%);\r\n      border-left: 5px solid #007bff;\r\n      padding: 20px;\r\n      border-radius: 6px;\r\n      margin: 20px 0;\r\n    }\r\n\r\n    .btn {\r\n      display: inline-block;\r\n      background: #007bff;\r\n      color: white;\r\n      padding: 12px 20px;\r\n      border-radius: 5px;\r\n      text-decoration: none;\r\n      font-weight: bold;\r\n      margin: 20px 0;\r\n    }\r\n\r\n    .btn:hover {\r\n      background: #005dc1;\r\n    }\r\n\r\n    .signature {\r\n      margin-top: 40px;\r\n      border-top: 1px solid #e0e0e0;\r\n      padding-top: 25px;\r\n      font-size: 14px;\r\n      color: #555;\r\n      text-align: center;\r\n    }\r\n\r\n    .signature img {\r\n      height: 50px;\r\n      margin: 0 auto 12px;\r\n      display: block;\r\n    }\r\n\r\n    .signature strong {\r\n      color: #111;\r\n      font-size: 15px;\r\n    }\r\n\r\n    .signature a {\r\n      color: #007bff;\r\n      text-decoration: none;\r\n    }\r\n\r\n    .signature p {\r\n      font-size: 12px;\r\n      color: #777;\r\n      line-height: 1.5;\r\n      margin-top: 8px;\r\n    }\r\n\r\n    .footer {\r\n      text-align: center;\r\n      font-size: 12px;\r\n      color: #777;\r\n      padding: 15px;\r\n      background: #f1f3f5;\r\n    }\r\n\r\n    @media only screen and (max-width: 600px) {\r\n      .container {\r\n        width: 94%;\r\n      }\r\n      .header h1 {\r\n        font-size: 22px;\r\n      }\r\n      .signature img {\r\n        height: 45px;\r\n      }\r\n    }\r\n  </style>\r\n</head>\r\n<body>\r\n  <div class=\"container\">\r\n    <div class=\"header\">\r\n      <h1>Auszahlung abgeschlossen</h1>\r\n      <p>Ihre Auszahlungsanfrage wurde erfolgreich bearbeitet</p>\r\n    </div>\r\n\r\n    <div class=\"content\">\r\n      <p>Sehr geehrte/r {first_name} {last_name},</p>\r\n\r\n      <p>\r\n        Wir freuen uns, Ihnen mitzuteilen, dass Ihre Auszahlungsanfrage  \r\n        erfolgreich abgeschlossen wurde. Der Betrag wurde an Ihr angegebenes  \r\n        Konto überwiesen.\r\n      </p>\r\n\r\n      <div class=\"highlight-box\">\r\n        <h3>💳 Transaktionsdetails</h3>\r\n        <p><strong>Betrag:</strong> {amount} €</p>\r\n        <p><strong>Zahlungsmethode:</strong> {payment_method}</p>\r\n        <p><strong>Zahlungsdetails:</strong> {payment_details}</p>\r\n        <p><strong>Transaktions-ID:</strong> {transaction_id}</p>\r\n        <p><strong>Datum der Auszahlung:</strong> {transaction_date}</p>\r\n        <p><strong>Status:</strong> {transaction_status}</p>\r\n      </div>\r\n\r\n      <p>\r\n        Bitte beachten Sie, dass es je nach Zahlungsanbieter bis zu  \r\n        <strong>3 Werktage</strong> dauern kann, bis der Betrag auf Ihrem  \r\n        Konto erscheint.\r\n      </p>\r\n\r\n      <p style=\"text-align:center;\">\r\n        <a href=\"{site_url}/login.php\" class=\"btn\">Zum Kundenportal</a>\r\n      </p>\r\n\r\n      <p>Mit freundlichen Grüßen,</p>\r\n\r\n      <div class=\"signature\">\r\n        <img src=\"https://tradevestcrypto.de/assets/img/logo.png\" alt=\"TradeVest Crypto Logo\"><br>\r\n        <strong>TradeVest Crypto – Finanzabteilung</strong><br>\r\n        Gmundberg 6, 83471 Berchtesgaden, Deutschland<br>\r\n        E: <a href=\"mailto:info@tradevestcrypto.de\">info@tradevestcrypto.de</a> | \r\n        W: <a href=\"https://tradevestcrypto.de\">tradevestcrypto.de</a>\r\n        <p>\r\n          Sitz der Gesellschaft: Berchtesgaden – Registergericht: Traunstein – HRB: 10162132<br>\r\n          USt-IdNr.: DE 343 826 946 – Vertreten durch: Mark Senger und Natalie Stenzel<br>\r\n          <em>Hinweis:</em> Diese E-Mail kann vertrauliche oder rechtlich geschützte Informationen enthalten.  \r\n          Wenn Sie nicht der richtige Adressat sind, informieren Sie uns bitte und löschen Sie diese Nachricht.\r\n        </p>\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"footer\">\r\n      © 2025 TradeVest Crypto. Alle Rechte vorbehalten.\r\n    </div>\r\n  </div>\r\n</body>\r\n</html>\r\n', '[\"first_name\", \"last_name\", \"username\", \"amount\", \"reference\", \"payment_method\", \"date\", \"current_year\", \"site_name\", \"site_url\", \"support_email\",\"site_url\"]', '2025-08-19 04:53:51'),
