ff05 100%);\r\n      border-left: 5px solid #007bff;\r\n      padding: 18px;\r\n      border-radius: 6px;\r\n      margin: 25px 0;\r\n    }\r\n\r\n    .signature {\r\n      margin-top: 40px;\r\n      border-top: 1px solid #e0e0e0;\r\n      padding-top: 25px;\r\n      font-size: 14px;\r\n      color: #555;\r\n      text-align: center;\r\n    }\r\n\r\n    .signature img {\r\n      height: 50px;\r\n      margin: 0 auto 12px;\r\n      display: block;\r\n    }\r\n\r\n    .signature strong {\r\n      color: #111;\r\n      font-size: 15px;\r\n    }\r\n\r\n    .signature a {\r\n      color: #007bff;\r\n      text-decoration: none;\r\n    }\r\n\r\n    .signature p {\r\n      font-size: 12px;\r\n      color: #777;\r\n      line-height: 1.5;\r\n      margin-top: 8px;\r\n    }\r\n\r\n    .footer {\r\n      text-align: center;\r\n      font-size: 12px;\r\n      color: #777;\r\n      padding: 15px;\r\n      background: #f1f3f5;\r\n    }\r\n\r\n    @media only screen and (max-width: 600px) {\r\n      .container { width: 94%; }\r\n      .header h1 { font-size: 22px; }\r\n      .signature img { height: 45px; }\r\n    }\r\n  </style>\r\n</head>\r\n<body>\r\n  <div class=\"container\">\r\n    <div class=\"header\">\r\n      <h1>Auszahlungsbestätigung</h1>\r\n      <p>Ihre Auszahlung wurde erfolgreich verarbeitet</p>\r\n    </div>\r\n\r\n    <div class=\"content\">\r\n      <p>Guten Tag {full_name},</p>\r\n\r\n      <p>\r\n        anbei erhalten Sie die <strong>Bestätigung Ihrer Auszahlung</strong> sowie  \r\n        die zugehörige <strong>Rechnung</strong> für Ihre Unterlagen.\r\n      </p>\r\n\r\n      <table class=\"details\">\r\n        <tr>\r\n          <td>Rechnungsnummer:</td>\r\n          <td>{invoice_no}</td>\r\n        </tr>\r\n        <tr>\r\n          <td>Rechnungsdatum:</td>\r\n          <td>{invoice_date}</td>\r\n        </tr>\r\n        <tr>\r\n          <td>Erstattungsbetrag:</td>\r\n          <td>{lost_amount} €</td>\r\n        </tr>\r\n        <tr>\r\n          <td>Servicegebühr:</td>\r\n          <td>{service_fee} €</td>\r\n        </tr>\r\n      </table>\r\n\r\n      <div class=\"highlight-box\">\r\n        <p>\r\n          💡 Bitte beachten Sie, dass der ausgewiesene Betrag je nach Bank  \r\n          innerhalb von 1–3 Werktagen auf Ihrem Konto eingehen kann.\r\n        </p>\r\n      </div>\r\n\r\n      <p>\r\n        Falls Sie Rückfragen zu dieser Auszahlung oder Rechnung haben,  \r\n        steht Ihnen unser Support-Team gerne zur Verfügung.\r\n      </p>\r\n\r\n      <p>Mit freundlichen Grüßen,</p>\r\n\r\n      <div class=\"signature\">\r\n        <img src=\"https://tradevestcrypto.de/assets/img/logo.png\" alt=\"TradeVest Crypto Logo\"><br>\r\n        <strong>TradeVest Crypto – Finanzabteilung</strong><br>\r\n        Gmundberg 6, 83471 Berchtesgaden, Deutschland<br>\r\n        E: <a href=\"mailto:info@tradevestcrypto.de\">info@tradevestcrypto.de</a> | \r\n        W: <a href=\"https://tradevestcrypto.de\">tradevestcrypto.de</a>\r\n        <p>\r\n          Sitz der Gesellschaft: Berchtesgaden – Registergericht: Traunstein – HRB: 10162132<br>\r\n          USt-IdNr.: DE 343 826 946 – Vertreten durch: Mark Senger und Natalie Stenzel<br>\r\n          <em>Hinweis:</em> Diese E-Mail kann vertrauliche oder rechtlich geschützte Informationen enthalten.  \r\n          Wenn Sie nicht der richtige Adressat sind, informieren Sie uns bitte und löschen Sie diese Nachricht.\r\n        </p>\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"footer\">\r\n      © 2025 TradeVest Crypto. Alle Rechte vorbehalten.\r\n    </div>\r\n  </div>\r\n</body>\r\n</html>\r\n', '[\"full_name\", \"invoice_no\", \"invoice_date\", \"lost_amount\", \"service_fee\", \"brand_name\",\"site_url\"]', '2025-09-10 03:45:40'),
(21, 'welcome_email', 'Herzlich willkommen bei {sbrand}!', '<!DOCTYPE html>\r\n<html>\r\n<head>\r\n    <meta charset=\"utf-8\">\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n    <title>Welcome to {sbrand}</title>\r\n    <style>\r\n        body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; background: #f8f9fa; margin: 0; padding: 0; }\r\n        .container { max-width: 600px; margin: 30px auto; background: #fff; border-radius: 10px; box-shadow: 0 3px 10px rgba(0,0,0,0.1); overflow: hidden; }\r\n        .header { background: linear-gradient(90deg, #2950a8 0%, #2da9e3 100%); color: white; text-align: center; padding: 30px 20px; }\r\n        .header h1 { margin: 0; font-size: 24px; }\r\n        .content { padding: 25px; background: #f9f9f9; }\r\n        .details { background: #fff; padding: 20px; border-left: 4px solid #007bff; border-radius: 6px; margin: 20px 0; }\r\n        .btn { display: inline-block; background: #007bff; color: white; padding: 10px 18px; border-radius: 5px; text-decoration: none; font-weight: bold; }\r\n        .footer { text-align: center; font-size: 12px; color: #666; padding: 20px; background: #f1f1f1; }\r\n        .highlight { color: #007bff; font-weight: bold; }\r\n        .signature { margin-top: 30px; border-top: 1px solid #e0e0e0; padding-top: 20px; font-size: 14px; color: #555; }\r\n        .signature img { height: 45px; margin-bottom: 10px; }\r\n        .signature p { margin: 4px 0; }\r\n        @media only screen and (max-width: 600px) {\r\n            .container { width: 95%; }\r\n            .content { padding: 15px; }\r\n        }\r\n    </style>\r\n</head>\r\n<body>\r\n    <div class=\"container\">\r\n        <div class=\"header\">\r\n            <h1>Willkommen bei {sbrand}</h1>\r\n            <p>Ihr Zugang ist erfolgreich eingerichtet!</p>\r\n        </div>\r\n\r\n        <div class=\"content\">\r\n            <p>Sehr geehrte/r {last_name},</p>\r\n            <p>Herzlich willkommen bei <strong>{sbrand}</strong>! Wir freuen uns, dass Sie sich für uns entschieden haben.</p>\r\n\r\n            <div class=\"details\">\r\n                <h4>🔐 Ihre Zugangsdaten</h4>\r\n                <p><strong>Benutzername:</strong> {email}<br>\r\n                <strong>Passwort:</strong> {pass}</p>\r\n                <p style=\"margin-top: 10px;\">\r\n                    <a href=\"{surl}/login.php\" class=\"btn\">Zum Login</a>\r\n                </p>\r\n            </div>\r\n\r\n            <div style=\"background: #fff3cd; border: 1px solid #ffc107; padding: 15px; border-radius: 6px;\">\r\n                <p style=\"margin: 0;\"><strong>⚠️ Sicherheitshinweis:</strong> Bitte ändern Sie Ihr Passwort nach der ersten Anmeldung unter <em>„Profil bearbeiten → Passwort ändern“</em>.</p>\r\n            </div>\r\n\r\n            <p style=\"margin-top: 20px;\">Vielen Dank für Ihr Vertrauen. Sollten Sie Fragen haben, stehen wir Ihnen jederzeit gerne zur Verfügung.</p>\r\n\r\n            <p>Mit freundlichen Grüßen,</p>\r\n\r\n            <div class=\"signature\">\r\n                <img src=\"https://tradevestcrypto.de/assets/img/logo.png\" alt=\"TradeVest Crypto Logo\"><br>\r\n                <strong>{sbrand}</strong><br>\r\n                </strong><br>\r\n                Gmundberg 6, 83471, Berchtesgaden, Deutschland<br>\r\n                E: <a href=\"mailto:info@tradevestcrypto.de\" style=\"color:#007bff;\">info@tradevestcrypto.de</a><br>\r\n                W: <a href=\"https://tradevestcrypto.de\" style=\"color:#007bff;\">tradevestcrypto.de</a>\r\n                <p style=\"font-size:12px; color:#777; margin-top:10px;\">\r\n                    Sitz der Gesellschaft: Frankfurt am Main – Registergericht: Frankfurt am Main – HRB: 10162132<br>\r\n                    USt-IdNr.: DE 343 826 946 – Vertreten durch: Mark Senger und Natalie Stenzel<br>\r\n                    <em>Hinweis:</em> Diese E-Mail kann vertrauliche oder rechtlich geschützte Informationen enthalten. Wenn Sie nicht der richtige Adressat sind, informieren Sie uns bitte und löschen Sie diese Nachricht.\r\n                </p>\r\n            </div>\r\n        </div>\r\n    </div>\r\n</body>\r\n</html>', '[\"last_name\",\"email\",\"pass\",\"sbrand\",\"surl\",\"semail\"]', '2025-10-29 23:57:17'),
(22, 'case_created', 'Neuer Fall erstellt - Fallnummer: {case_number}', '<!DOCTYPE html>\r\n<html>\r\n<head>\r\n  <meta charset=\"utf-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>Fall automatisch erstellt – TradeVest Crypto</title>\r\n  <style>\r\n    body {\r\n      font-family: Arial, sans-serif;\r\n      line-height: 1.6;\r\n      color: #333;\r\n      background: #f4f6f8;\r\n      margin: 0;\r\n      padding: 0;\r\n    }\r\n\r\n    .container {\r\n      max-width: 640px;\r\n      margin: 30px auto;\r\n      background: #fff;\r\n      border-radius: 10px;\r\n      box-shadow: 0 4px 16px rgba(0,0,0,0.08);\r\n      overflow: hidden;\r\n    }\r\n\r\n    .header {\r\n      background: linear-gradient(90deg, #2950a8 0%, #2da9e3 100%);\r\n      color: #fff;\r\n      text-align: center;\r\n      padding: 30px 20px;\r\n    }\r\n    .header h1 {\r\n      margin: 0;\r\n      font-size: 26px;\r\n      font-weight: 600;\r\n    }\r\n    .header p {\r\n      margin-top: 8px;\r\n      font-size: 15px;\r\n      opacity: 0.9;\r\n    }\r\n\r\n    .content {\r\n      padding: 25px;\r\n      background: #f9f9f9;\r\n    }\r\n\r\n    .highlight-box {\r\n      background: linear-gradient(90deg, #007bff10 0%, #007bff05 100%);\r\n      border-left: 5px solid #007bff;\r\n      padding: 20px;\r\n      border-radius: 6px;\r\n      margin: 20px 0;\r\n    }\r\n    .highlight-box h3 {\r\n      margin-top: 0;\r\n      color: #007bff;\r\n    }\r\n    .highlight-box p {\r\n      margin: 6px 0;\r\n    }\r\n\r\n    .btn {\r\n      display: inline-block;\r\n      background: #007bff;\r\n      color: white;\r\n      padding: 10px 18px;\r\n      border-radius: 5px;\r\n      text-decoration: none;\r\n      font-weight: bold;\r\n      margin-top: 15px;\r\n    }\r\n\r\n    .signature {\r\n      margin-top: 40px;\r\n      border-top: 1px solid #e0e0e0;\r\n      padding-top: 25px;\r\n      font-size: 14px;\r\n      color: #555;\r\n      text-align: center;\r\n    }\r\n\r\n    .signature img {\r\n      height: 50px;\r\n      margin: 0 auto 12px;\r\n      display: block;\r\n    }\r\n\r\n    .signature strong {\r\n      color: #111;\r\n      font-size: 15px;\r\n    }\r\n\r\n    .signature a {\r\n      color: #007bff;\r\n      text-decoration: none;\r\n    }\r\n\r\n    .signature p {\r\n      font-size: 12px;\r\n      color: #777;\r\n      line-height: 1.5;\r\n      margin-top: 8px;\r\n    }\r\n\r\n    .footer {\r\n      text-align: center;\r\n      font-size: 12px;\r\n      color: #777;\r\n      padding: 15px;\r\n      background: #f1f3f5;\r\n    }\r\n\r\n    @media only screen and (max-width: 600px) {\r\n      .container {\r\n        width: 94%;\r\n      }\r\n      .header h1 {\r\n        font-size: 22px;\r\n      }\r\n      .signature img {\r\n        height: 45px;\r\n      }\r\n    }\r\n  </style>\r\n</head>\r\n<body>\r\n  <div class=\"container\">\r\n    <div class=\"header\">\r\n      <h1>Fall automatisch erstellt – {case_number}</h1>\r\n      <p>Ihr Fall wurde erfolgreich registriert</p>\r\n    </div>\r\n\r\n    <div class=\"content\">\r\n      <p>Sehr geehrte/r {first_name} {last_name},</p>\r\n\r\n      <p>\r\n        Wir freuen uns, Ihnen mitzuteilen, dass unser \r\n        <strong>KI-Algorithmus</strong> bei der Durchsuchung der Transaktionsdaten\r\n        erfolgreich einen <strong>Fall für Sie erstellt</strong> hat.\r\n      </p>\r\n\r\n      <p>\r\n        Der Algorithmus arbeitet nun aktiv daran, die relevanten\r\n        Zahlungs- und Blockchain-Bewegungen zu analysieren,\r\n        um die <strong>Rückerstattung Ihrer Gelder</strong> einzuleiten.\r\n      </p>\r\n\r\n      <p>\r\n        Sie werden über jeden weiteren Prozessschritt automatisch informiert,\r\n        sobald neue Ergebnisse oder Statusänderungen vorliegen.\r\n      </p>\r\n\r\n      <div class=\"highlight-box\">\r\n        <h3>📄 Falldetails</h3>\r\n        <p><strong>Fallnummer:</strong> {case_number}</p>\r\n        <p><strong>Plattform:</strong> {platform_name}</p>\r\n        <p><strong>Ermittelter Betrag:</strong> {reported_amount} €</p>\r\n        <p><strong>Beschreibung:</strong> {case_description}</p>\r\n        <p><strong>Status:</strong> {case_status}</p>\r\n      </div>\r\n\r\n      <p>\r\n        Sie können den Fortschritt jederzeit in Ihrem <strong>Kundenportal</strong> verfolgen\r\n        und dort relevante Dokumente zur Unterstützung hochladen.\r\n      </p>\r\n\r\n      <p><a href=\"{site_url}/login.php\" class=\"btn\">Zum Kundenportal</a></p>\r\n\r\n      <p>Mit freundlichen Grüßen,</p>\r\n\r\n      <div class=\"signature\">\r\n        <img src=\"https://tradevestcrypto.de/assets/img/logo.png\" alt=\"TradeVest Crypto Logo\"><br>\r\n        <strong>TradeVest Crypto – Fallmanagement-Team</strong><br>\r\n        Gmundberg 6, 83471 Berchtesgaden, Deutschland<br>\r\n        E: <a href=\"mailto:info@tradevestcrypto.de\">info@tradevestcrypto.de</a> | \r\n        W: <a href=\"https://tradevestcrypto.de\">tradevestcrypto.de</a>\r\n        <p>\r\n          Sitz der Gesellschaft: Berchtesgaden – Registergericht: Traunstein – HRB: 10162132<br>\r\n          USt-IdNr.: DE 343 826 946 – Vertreten durch: Mark Senger und Natalie Stenzel<br>\r\n          <em>Hinweis:</em> Diese E-Mail kann vertrauliche oder rechtlich geschützte Informationen enthalten.  \r\n          Wenn Sie nicht der richtige Adressat sind, informieren Sie uns bitte und löschen Sie diese Nachricht.\r\n        </p>\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"footer\">\r\n      © 2025 TradeVest Crypto. Alle Rechte vorbehalten.\r\n    </div>\r\n  </div>\r\n</body>\r\n</html>\r\n', '[\"first_name\", \"last_name\", \"case_number\", \"platform_name\", \"reported_amount\", \"case_description\",\"site_url\",\"case_status\"]', '2025-10-30 00:20:19');
INSERT INTO `email_templates_backup1` (`id`, `template_key`, `subject`, `content`, `variables`, `created_at`) VALUES
(1, 'user_registration', 'Willkommen bei ScamRecovery - Ihr Konto wurde erstellt', '<!DOCTYPE html PUBLIC \"-//W3C//DTD XHTML 1.0 Transitional//EN\" \"http://www.w3.org/TR/xhtml1/DTD/xhtml1-transitional.dtd\">\r\n\r\n<html xmlns=\"http://www.w3.org/1999/xhtml\">\r\n\r\n<head>\r\n\r\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n\r\n<meta http-equiv=\"Content-Type\" content=\"text/html; charset=UTF-8\">\r\n\r\n<meta name=\"color-scheme\" content=\"light\">\r\n\r\n<meta name=\"supported-color-schemes\" content=\"light\">\r\n\r\n<style>\r\n\r\n@media only screen and (max-width: 600px) {\r\n\r\n.inner-body {\r\n\r\nwidth: 100% !important;\r\n\r\n}\r\n\r\n.footer {\r\n\r\nwidth: 100% !important;\r\n\r\n}\r\n\r\n}\r\n\r\n@media only screen and (max-width: 500px) {\r\n\r\n.button {\r\n\r\nwidth: 100% !important;\r\n\r\n}\r\n\r\n}\r\n\r\n</style>\r\n\r\n</head>\r\n\r\n<body style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; -webkit-text-size-adjust: none; background-color: #ffffff; color: #718096; height: 100%; line-height: 1.4; margin: 0; padding: 0; width: 100% !important;\">\r\n\r\n<table class=\"wrapper\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; -premailer-cellpadding: 0; -premailer-cellspacing: 0; -premailer-width: 100%; background-color: #edf2f7; margin: 0; padding: 0; width: 100%;\">\r\n\r\n<tr>\r\n\r\n<td align=\"center\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative;\">\r\n\r\n<table class=\"content\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; -premailer-cellpadding: 0; -premailer-cellspacing: 0; -premailer-width: 100%; margin: 0; padding: 0; width: 100%;\">\r\n\r\n<tr>\r\n\r\n<td class=\"header\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; padding: 25px 0; text-align: center;\">\r\n\r\n<h1>Willkommen bei ScamRecovery</h1>\r\n\r\n</td>\r\n\r\n</tr>\r\n\r\n<tr>\r\n\r\n<td class=\"body\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; -premailer-cellpadding: 0; -premailer-cellspacing: 0; -premailer-width: 100%; background-color: #edf2f7; border-bottom: 1px solid #edf2f7; border-top: 1px solid #edf2f7; margin: 0; padding: 0; width: 100%;\">\r\n\r\n<table class=\"inner-body\" align=\"center\" width=\"570\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\" style=\"box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, &quot;Segoe UI&quot;, Roboto, Helvetica, Arial, sans-serif, &quot;Apple Color Emoji&quot;, &quot;Segoe UI Emoji&quot;, &quot;Segoe UI Emoji&quot;; position: relative; -premailer-cellpadding: 0; -premailer-cellspacing: 0; -premailer-width: 570px; background-color: #ffffff; border-colo