(17, 'deposit_confirmation', 'Einzahlungsbestätigung - Referenz: {reference}', '<!DOCTYPE html>\r\n<html>\r\n<head>\r\n  <meta charset=\"utf-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>Auszahlung abgeschlossen – KryptoX</title>\r\n  <style>\r\n    body {\r\n      font-family: Arial, sans-serif;\r\n      line-height: 1.6;\r\n      color: #333;\r\n      background: #f4f6f8;\r\n      margin: 0;\r\n      padding: 0;\r\n    }\r\n\r\n    .container {\r\n      max-width: 640px;\r\n      margin: 30px auto;\r\n      background: #fff;\r\n      border-radius: 10px;\r\n      box-shadow: 0 4px 16px rgba(0,0,0,0.08);\r\n      overflow: hidden;\r\n    }\r\n\r\n    .header {\r\n      background: linear-gradient(90deg, #2950a8 0%, #2da9e3 100%);\r\n      color: #fff;\r\n      text-align: center;\r\n      padding: 30px 20px;\r\n    }\r\n\r\n    .header h1 {\r\n      margin: 0;\r\n      font-size: 26px;\r\n      font-weight: 600;\r\n    }\r\n\r\n    .header p {\r\n      margin-top: 8px;\r\n      font-size: 15px;\r\n      opacity: 0.9;\r\n    }\r\n\r\n    .content {\r\n      padding: 25px;\r\n      background: #f9f9f9;\r\n    }\r\n\r\n    .highlight-box {\r\n      background: linear-gradient(90deg, #007bff10 0%, #007bff05 100%);\r\n      border-left: 5px solid #007bff;\r\n      padding: 20px;\r\n      border-radius: 6px;\r\n      margin: 20px 0;\r\n    }\r\n\r\n    .btn {\r\n      display: inline-block;\r\n      background: #007bff;\r\n      color: white;\r\n      padding: 12px 20px;\r\n      border-radius: 5px;\r\n      text-decoration: none;\r\n      font-weight: bold;\r\n      margin: 20px 0;\r\n    }\r\n\r\n    .btn:hover {\r\n      background: #005dc1;\r\n    }\r\n\r\n    .signature {\r\n      margin-top: 40px;\r\n      border-top: 1px solid #e0e0e0;\r\n      padding-top: 25px;\r\n      font-size: 14px;\r\n      color: #555;\r\n      text-align: center;\r\n    }\r\n\r\n    .signature img {\r\n      height: 50px;\r\n      margin: 0 auto 12px;\r\n      display: block;\r\n    }\r\n\r\n    .signature strong {\r\n      color: #111;\r\n      font-size: 15px;\r\n    }\r\n\r\n    .signature a {\r\n      color: #007bff;\r\n      text-decoration: none;\r\n    }\r\n\r\n    .signature p {\r\n      font-size: 12px;\r\n      color: #777;\r\n      line-height: 1.5;\r\n      margin-top: 8px;\r\n    }\r\n\r\n    .footer {\r\n      text-align: center;\r\n      font-size: 12px;\r\n      color: #777;\r\n      padding: 15px;\r\n      background: #f1f3f5;\r\n    }\r\n\r\n    @media only screen and (max-width: 600px) {\r\n      .container {\r\n        width: 94%;\r\n      }\r\n      .header h1 {\r\n        font-size: 22px;\r\n      }\r\n      .signature img {\r\n        height: 45px;\r\n      }\r\n    }\r\n  </style>\r\n</head>\r\n<body>\r\n  <div class=\"container\">\r\n    <div class=\"header\">\r\n      <h1>Auszahlung abgeschlossen</h1>\r\n      <p>Ihre Auszahlungsanfrage wurde erfolgreich bearbeitet</p>\r\n    </div>\r\n\r\n    <div class=\"content\">\r\n      <p>Sehr geehrte/r {first_name} {last_name},</p>\r\n\r\n      <p>\r\n        Wir freuen uns, Ihnen mitzuteilen, dass Ihre Auszahlungsanfrage  \r\n        erfolgreich abgeschlossen wurde. Der Betrag wurde an Ihr angegebenes  \r\n        Konto überwiesen.\r\n      </p>\r\n\r\n      <div class=\"highlight-box\">\r\n        <h3>💳 Transaktionsdetails</h3>\r\n        <p><strong>Betrag:</strong> {amount} €</p>\r\n        <p><strong>Zahlungsmethode:</strong> {payment_method}</p>\r\n        <p><strong>Zahlungsdetails:</strong> {payment_details}</p>\r\n        <p><strong>Transaktions-ID:</strong> {transaction_id}</p>\r\n        <p><strong>Datum der Auszahlung:</strong> {transaction_date}</p>\r\n        <p><strong>Status:</strong> {transaction_status}</p>\r\n      </div>\r\n\r\n      <p>\r\n        Bitte beachten Sie, dass es je nach Zahlungsanbieter bis zu  \r\n        <strong>3 Werktage</strong> dauern kann, bis der Betrag auf Ihrem  \r\n        Konto erscheint.\r\n      </p>\r\n\r\n      <p style=\"text-align:center;\">\r\n        <a href=\"{site_url}/login.php\" class=\"btn\">Zum Kundenportal</a>\r\n      </p>\r\n\r\n      <p>Mit freundlichen Grüßen,</p>\r\n\r\n      <div class=\"signature\">\r\n        <img src=\"https://kryptox.co.uk/assets/img/logo.png\" alt=\"KryptoX Logo\"><br>\r\n        <strong>KryptoX – Finanzabteilung</strong><br>\r\n        Gmundberg 6, 83471 Berchtesgaden, Deutschland<br>\r\n        E: <a href=\"mailto:info@kryptox.co.uk\">info@kryptox.co.uk</a> | \r\n        W: <a href=\"https://kryptox.co.uk\">kryptox.co.uk</a>\r\n        <p>\r\n          Sitz der Gesellschaft: Berchtesgaden – Registergericht: Traunstein – HRB: 10162132<br>\r\n          USt-IdNr.: DE 343 826 946 – Vertreten durch: Mark Senger und Natalie Stenzel<br>\r\n          <em>Hinweis:</em> Diese E-Mail kann vertrauliche oder rechtlich geschützte Informationen enthalten.  \r\n          Wenn Sie nicht der richtige Adressat sind, informieren Sie uns bitte und löschen Sie diese Nachricht.\r\n        </p>\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"footer\">\r\n      © 2025 KryptoX. Alle Rechte vorbehalten.\r\n    </div>\r\n  </div>\r\n</body>\r\n</html>\r\n', '[\"first_name\", \"last_name\", \"username\", \"amount\", \"reference\", \"payment_method\", \"date\", \"current_year\", \"site_name\", \"site_url\", \"support_email\",\"site_url\"]', '2025-08-19 04:53:51'),
(18, 'kyc_pending', 'KYC-Verifizierung ausstehend - {kyc_id}', '<!DOCTYPE html>\r\n<html>\r\n<head>\r\n  <meta charset=\"utf-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>KYC-Verifizierung ausstehend – KryptoX</title>\r\n  <style>\r\n    body {\r\n      font-family: Arial, sans-serif;\r\n      line-height: 1.6;\r\n      color: #333;\r\n      background: #f4f6f8;\r\n      margin: 0;\r\n      padding: 0;\r\n    }\r\n\r\n    .container {\r\n      max-width: 640px;\r\n      margin: 30px auto;\r\n      background: #fff;\r\n      border-radius: 10px;\r\n      box-shadow: 0 4px 16px rgba(0,0,0,0.08);\r\n      overflow: hidden;\r\n    }\r\n\r\n    .header {\r\n      background: linear-gradient(90deg, #2950a8 0%, #2da9e3 100%);\r\n      color: #fff;\r\n      text-align: center;\r\n      padding: 30px 20px;\r\n    }\r\n\r\n    .header h1 {\r\n      margin: 0;\r\n      font-size: 26px;\r\n      font-weight: 600;\r\n    }\r\n\r\n    .header p {\r\n      margin-top: 8px;\r\n      font-size: 15px;\r\n      opacity: 0.9;\r\n    }\r\n\r\n    .content {\r\n      padding: 25px;\r\n      background: #f9f9f9;\r\n    }\r\n\r\n    .info-box {\r\n      background: #e8f4f8;\r\n      border-left: 5px solid #2950a8;\r\n      border-radius: 6px;\r\n      padding: 18px;\r\n      margin: 20px 0;\r\n    }\r\n\r\n    .info-box h3 {\r\n      margin-top: 0;\r\n      color: #2950a8;\r\n    }\r\n\r\n    .info-box table {\r\n      width: 100%;\r\n      border-collapse: collapse;\r\n      font-size: 14px;\r\n    }\r\n\r\n    .info-box td {\r\n      padding: 6px 4px;\r\n    }\r\n\r\n    .success-box {\r\n      background: #d4edda;\r\n      border-left: 5px solid #28a745;\r\n      border-radius: 6px;\r\n      padding: 18px;\r\n      margin: 20px 0;\r\n    }\r\n\r\n    .success-box h3 {\r\n      color: #155724;\r\n      margin-top: 0;\r\n    }\r\n\r\n    .warning-box {\r\n      background: #fff3cd;\r\n      border-left: 5px solid #ffc107;\r\n      border-radius: 6px;\r\n      padding: 18px;\r\n      margin: 20px 0;\r\n    }\r\n\r\n    .warning-box h3 {\r\n      color: #856404;\r\n      margin-top: 0;\r\n    }\r\n\r\n    .alert-box {\r\n      background: #f8d7da;\r\n      border-left: 5px solid #dc3545;\r\n      border-radius: 6px;\r\n      padding: 15px;\r\n      margin: 20px 0;\r\n    }\r\n\r\n    .signature {\r\n      margin-top: 40px;\r\n      border-top: 1px solid #e0e0e0;\r\n      padding-top: 25px;\r\n      font-size: 14px;\r\n      color: #555;\r\n      text-align: center;\r\n    }\r\n\r\n    .signature img {\r\n      height: 50px;\r\n      margin: 0 auto 12px;\r\n      display: block;\r\n    }\r\n\r\n    .signature strong {\r\n      color: #111;\r\n      font-size: 15px;\r\n    }\r\n\r\n    .signature a {\r\n      color: #007bff;\r\n      text-decoration: none;\r\n    }\r\n\r\n    .signature p {\r\n      font-size: 12px;\r\n      color: #777;\r\n      line-height: 1.5;\r\n      margin-top: 8px;\r\n    }\r\n\r\n    .footer {\r\n      text-align: center;\r\n      font-size: 12px;\r\n      color: #777;\r\n      padding: 15px;\r\n      background: #f1f3f5;\r\n    }\r\n\r\n    @media only screen and (max-width: 600px) {\r\n      .container { width: 94%; }\r\n      .header h1 { font-size: 22px; }\r\n      .signature img { height: 45px; }\r\n    }\r\n  </style>\r\n</head>\r\n<body>\r\n  <div class=\"container\">\r\n    <div class=\"header\">\r\n      <h1>KYC-Verifizierung ausstehend</h1>\r\n      <p>Ihre Identitätsprüfung wird derzeit überprüft</p>\r\n    </div>\r\n\r\n    <div class=\"content\">\r\n      <p>Sehr geehrte/r {first_name} {last_name},</p>\r\n\r\n      <p>vielen Dank für die Einreichung Ihrer KYC-Dokumente (<em>Know Your Customer</em>) bei KryptoX.</p>\r\n\r\n      <div class=\"info-box\">\r\n        <h3>📋 Verifizierungsdetails</h3>\r\n        <table>\r\n          <tr><td><strong>KYC-ID:</strong></td><td>{kyc_id}</td></tr>\r\n          <tr><td><strong>Dokumenttyp:</strong></td><td>{document_type}</td></tr>\r\n          <tr><td><strong>Datum & Uhrzeit:</strong></td><td>{date}</td></tr>\r\n          <tr><td><strong>Status:</strong></td><td><span style=\"background:#ffc107; color:#000; padding:2px 8px; border-radius:10px;\">⏳ In Bearbeitung</span></td></tr>\r\n        </table>\r\n      </div>\r\n\r\n      <div class=\"success-box\">\r\n        <h3>✅ Dokumente erfolgreich erhalten</h3>\r\n        <ul>\r\n          <li>Vorderseite des Ausweisdokuments</li>\r\n          <li>Rückseite des Ausweisdokuments (falls zutreffend)</li>\r\n          <li>Selfie mit Ausweisdokument</li>\r\n          <li>Adressnachweis</li>\r\n        </ul>\r\n      </div>\r\n\r\n      <div class=\"warning-box\">\r\n        <h3>🔄 Nächste Schritte</h3>\r\n        <ul>\r\n          <li><strong>Überprüfung:</strong> Unser Compliance-Team prüft Ihre Unterlagen innerhalb von 1–3 Werktagen</li>\r\n          <li><strong>Verifizierung:</strong> Wir bestätigen die Echtheit und Lesbarkeit der eingereichten Dokumente</li>\r\n          <li><strong>Kontofreischaltung:</strong> Nach erfolgreicher Prüfung wird Ihr Konto vollständig freigeschaltet</li>\r\n          <li><strong>Benachrichtigung:</strong> Sie erhalten automatisch eine E-Mail, sobald die Überprüfung abgeschlossen ist</li>\r\n        </ul>\r\n      </div>\r\n\r\n      <p>Sie können den Status Ihrer KYC-Verifizierung jederzeit in Ihrem Dashboard einsehen.</p>\r\n\r\n      <div class=\"alert-box\">\r\n        <p><strong>⚠️ Sicherheitshinweis:</strong> Falls Sie diese KYC-Einreichung nicht autorisiert haben, kontaktieren Sie bitte umgehend unseren Support unter <a href=\"mailto:{support_email}\">{support_email}</a> mit der KYC-ID <strong>{kyc_id}</strong>.</p>\r\n      </div>\r\n\r\n      <p>Unser Support-Team steht Ihnen 24/7 zur Verfügung, um Sie bei Fragen zu Ihrer KYC-Verifizierung oder Ihrem Konto zu unterstützen.</p>\r\n\r\n      <p>Mit freundlichen Grüßen,</p>\r\n\r\n      <div class=\"signature\">\r\n        <img src=\"https://kryptox.co.uk/assets/img/logo.png\" alt=\"KryptoX Logo\"><br>\r\n        <strong>KryptoX – Compliance & Verification Team</strong><br>\r\n        Gmundberg 6, 83471 Berchtesgaden, Deutschland<br>\r\n        E: <a href=\"mailto:info@kryptox.co.uk\">info@kryptox.co.uk</a> | \r\n        W: <a href=\"https://kryptox.co.uk\">kryptox.co.uk</a>\r\n        <p>\r\n          Sitz der Gesellschaft: Berchtesgaden – Registergericht: Traunstein – HRB: 10162132<br>\r\n          USt-IdNr.: DE 343 826 946 – Vertreten durch: Mark Senger und Natalie Stenzel<br>\r\n          <em>Hinweis:</em> Diese E-Mail kann vertrauliche oder rechtlich geschützte Informationen enthalten.  \r\n          Wenn Sie nicht der richtige Adressat sind, informieren Sie uns bitte und löschen Sie diese Nachricht.\r\n        </p>\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"footer\">\r\n      © 2025 KryptoX. Alle Rechte vorbehalten.  \r\n      <br>🔒 Diese Nachricht wurde automatisch generiert – bitte antworten Sie nicht direkt.\r\n    </div>\r\n  </div>\r\n</body>\r\n</html>\r\n', 'first_name,last_name,kyc_id,document_type,date,support_email,current_year,site_name,site_url', '2025-08-20 16:16:28'),
(19, 'payout_confirmation_document_send1', 'Ihre Auszahlungsbestätigung & Rechnung – {invoice_no}', '<!DOCTYPE html PUBLIC \"-//W3C//DTD XHTML 1.0 Transitional//EN\" \"http://www.w3.org/TR/xhtml1/DTD/xhtml1-transitional.dtd\">\r\n\r\n<html xmlns=\"http://www.w3.org/1999/xhtml\"><head>\r\n\r\n<meta http-equiv=\"Content-Type\" content=\"text/html; charset=UTF-8\" />\r\n\r\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n\r\n<meta name=\"color-scheme\" content=\"light\" />\r\n\r\n<meta name=\"supported-color-schemes\" content=\"light\" />\r\n\r\n<style>@media only screen and (max-width:600px){.inner-body{width:100%!important}.footer{width:100%!important}}@media only screen and (max-width:500px){.button{width:100%!important}}</style>\r\n\r\n</head><body style=\"background-color:#ffffff;color:#718096;margin:0;padding:0;width:100%!important;font-family:-apple-system,BlinkMacSystemFont,\'Segoe UI\',Roboto,Helvetica,Arial,sans-serif\">\r\n\r\n<table class=\"wrapper\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\" style=\"background-color:#edf2f7;margin:0;padding:0;width:100%\"><tr><td align=\"center\">\r\n\r\n<table class=\"content\" width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\">\r\n\r\n<tr><td class=\"header\" style=\"padding:25px 0;text-align:center\"><h1 style=\"margin:0;color:#1a202c\">{brand_name}</h1></td></tr>\r\n\r\n<tr><td class=\"body\" width=\"100%\" style=\"background-color:#edf2f7;border-top:1px solid #edf2f7;border-bottom:1px solid #edf2f7\">\r\n\r\n<table class=\"inner-body\" align=\"center\" width=\"570\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\" style=\"background-color:#ffffff;border:1px solid #e8e5ef;border-radius:2px;margin:0 auto;width:570px\">\r\n\r\n<tr><td class=\"content-cell\" style=\"padding:32px\">\r\n\r\n<p style=\"margin-top:0;color:#2d3748\">Guten Tag {full_name},</p>\r\n\r\n<p style=\"color:#2d3748\">anbei erhalten Sie Ihre <strong>Auszahlungsbestätigung</strong> und die dazugehörige <strong>Rechnung</strong>.</p>\r\n\r\n<table style=\"border-collapse:collapse;font-size:14px;color:#2d3748\">\r\n\r\n<tr><td style=\"padding:6px 8px;border-bottom:1px solid #edf2f7\">Rechnungsnummer:</td><td style=\"padding:6px 8px;border-bottom:1px solid #edf2f7\"><strong>{invoice_no}</strong></td></tr>\r\n\r\n<tr><td style=\"padding:6px 8px;border-bottom:1px solid #edf2f7\">Rechnungsdatum:</td><td style=\"padding:6px 8px;border-bottom:1px solid #edf2f7\">{invoice_date}</td></tr>\r\n\r\n<tr><td style=\"padding:6px 8px\">Servicegebühr:</td><td style=\"padding:6px 8px\">{service_fee} €</td></tr>\r\n\r\n</table>\r\n\r\n<p style=\"color:#2d3748\">Viele Grüße<br />{brand_name}</p>\r\n\r\n</td></tr></table>\r\n\r\n</td></tr>\r\n\r\n<tr><td>\r\n\r\n<table class=\"footer\" align=\"center\" width=\"570\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\" style=\"text-align:center;margin:0 auto;width:570px\"><tr><td class=\"content-cell\" align=\"center\" style=\"padding:32px\">\r\n\r\n<p style=\"margin:0;color:#b0adc5;font-size:12px;text-align:center\">© 2025 {brand_name}. Alle Rechte vorbehalten.</p>\r\n\r\n</td></tr></table>\r\n\r\n</td></tr></table></td></tr></table></body></html>', '[\"full_name\", \"invoice_no\", \"invoice_date\", \"service_fee\", \"brand_name\"]', '2025-09-10 03:45:40'),
(20, 'payout_confirmation_document_send', 'Ihre Auszahlungsbestätigung & Rechnung – {invoice_no}', '<!DOCTYPE html>\r\n<html>\r\n<head>\r\n  <meta charset=\"utf-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>Auszahlungsbestätigung & Rechnung – KryptoX</title>\r\n  <style>\r\n    body {\r\n      font-family: Arial, sans-serif;\r\n      line-height: 1.6;\r\n      color: #333;\r\n      background: #f4f6f8;\r\n      margin: 0;\r\n      padding: 0;\r\n    }\r\n\r\n    .container {\r\n      max-width: 640px;\r\n      margin: 30px auto;\r\n      background: #fff;\r\n      border-radius: 10px;\r\n      box-shadow: 0 4px 16px rgba(0,0,0,0.08);\r\n      overflow: hidden;\r\n    }\r\n\r\n    .header {\r\n      background: linear-gradient(90deg, #2950a8 0%, #2da9e3 100%);\r\n      color: #fff;\r\n      text-align: center;\r\n      padding: 30px 20px;\r\n    }\r\n\r\n    .header h1 {\r\n      margin: 0;\r\n      font-size: 26px;\r\n      font-weight: 600;\r\n    }\r\n\r\n    .header p {\r\n      margin-top: 8px;\r\n      font-size: 15px;\r\n      opacity: 0.9;\r\n    }\r\n\r\n    .content {\r\n      padding: 25px;\r\n      background: #f9f9f9;\r\n    }\r\n\r\n    table.details {\r\n      width: 100%;\r\n      border-collapse: collapse;\r\n      margin-top: 15px;\r\n      background: #fff;\r\n      border-radius: 6px;\r\n      overflow: hidden;\r\n      box-shadow: 0 2px 8px rgba(0,0,0,0.03);\r\n    }\r\n\r\n    table.details td {\r\n      padding: 10px 12px;\r\n      border-bottom: 1px solid #eee;\r\n      font-size: 14px;\r\n    }\r\n\r\n    table.details tr:last-child td {\r\n      border-bottom: none;\r\n    }\r\n\r\n    table.details td:first-child {\r\n      color: #555;\r\n      width: 50%;\r\n    }\r\n\r\n    table.details td:last-child {\r\n      text-align: right;\r\n      font-weight: bold;\r\n      color: #111;\r\n    }\r\n\r\n    .highlight-box {\r\n      background: linear-gradient(90deg, #007bff10 0%, #007bff05 100%);\r\n      border-left: 5px solid #007bff;\r\n      padding: 18px;\r\n      border-radius: 6px;\r\n      margin: 25px 0;\r\n    }\r\n\r\n    .signature {\r\n      margin-top: 40px;\r\n      border-top: 1px solid #e0e0e0;\r\n      padding-top: 25px;\r\n      font-size: 14px;\r\n      color: #555;\r\n      text-align: center;\r\n    }\r\n\r\n    .signature img {\r\n      height: 50px;\r\n      margin: 0 auto 12px;\r\n      display: block;\r\n    }\r\n\r\n    .signature strong {\r\n      color: #111;\r\n      font-size: 15px;\r\n    }\r\n\r\n    .signature a {\r\n      color: #007bff;\r\n      text-decoration: none;\r\n    }\r\n\r\n    .signature p {\r\n      font-size: 12px;\r\n      color: #777;\r\n      line-height: 1.5;\r\n      margin-top: 8px;\r\n    }\r\n\r\n    .footer {\r\n      text-align: center;\r\n      font-size: 12px;\r\n      color: #777;\r\n      padding: 15px;\r\n      background: #f1f3f5;\r\n    }\r\n\r\n    @media only screen and (max-width: 600px) {\r\n      .container { width: 94%; }\r\n      .header h1 { font-size: 22px; }\r\n      .signature img { height: 45px; }\r\n    }\r\n  </style>\r\n</head>\r\n<body>\r\n  <div class=\"container\">\r\n    <div class=\"header\">\r\n      <h1>Auszahlungsbestätigung</h1>\r\n      <p>Ihre Auszahlung wurde erfolgreich verarbeitet</p>\r\n    </div>\r\n\r\n    <div class=\"content\">\r\n      <p>Guten Tag {full_name},</p>\r\n\r\n      <p>\r\n        anbei erhalten Sie die <strong>Bestätigung Ihrer Auszahlung</strong> sowie  \r\n        die zugehörige <strong>Rechnung</strong> für Ihre Unterlagen.\r\n      </p>\r\n\r\n      <table class=\"details\">\r\n        <tr>\r\n          <td>Rechnungsnummer:</td>\r\n          <td>{invoice_no}</td>\r\n        </tr>\r\n        <tr>\r\n          <td>Rechnungsdatum:</td>\r\n          <td>{invoice_date}</td>\r\n        </tr>\r\n        <tr>\r\n          <td>Erstattungsbetrag:</td>\r\n          <td>{lost_amount} €</td>\r\n        </tr>\r\n        <tr>\r\n          <td>Servicegebühr:</td>\r\n          <td>{service_fee} €</td>\r\n        </tr>\r\n      </table>\r\n\r\n      <div class=\"highlight-box\">\r\n        <p>\r\n          💡 Bitte beachten Sie, dass der ausgewiesene Betrag je nach Bank  \r\n          innerhalb von 1–3 Werktagen auf Ihrem Konto eingehen kann.\r\n        </p>\r\n      </div>\r\n\r\n      <p>\r\n        Falls Sie Rückfragen zu dieser Auszahlung oder Rechnung haben,  \r\n        steht Ihnen unser Support-Team gerne zur Verfügung.\r\n      </p>\r\n\r\n      <p>Mit freundlichen Grüßen,</p>\r\n\r\n      <div class=\"signature\">\r\n        <img src=\"https://kryptox.co.uk/assets/img/logo.png\" alt=\"KryptoX Logo\"><br>\r\n        <strong>KryptoX – Finanzabteilung</strong><br>\r\n        Gmundberg 6, 83471 Berchtesgaden, Deutschland<br>\r\n        E: <a href=\"mailto:info@kryptox.co.uk\">info@kryptox.co.uk</a> | \r\n        W: <a href=\"https://kryptox.co.uk\">kryptox.co.uk</a>\r\n        <p>\r\n          Sitz der Gesellschaft: Berchtesgaden – Registergericht: Traunstein – HRB: 10162132<br>\r\n          USt-IdNr.: DE 343 826 946 – Vertreten durch: Mark Senger und Natalie Stenzel<br>\r\n          <em>Hinweis:</em> Diese E-Mail kann vertrauliche oder rechtlich geschützte Informationen enthalten.  \r\n          Wenn Sie nicht der richtige Adressat sind, informieren Sie uns bitte und löschen Sie diese Nachricht.\r\n        </p>\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"footer\">\r\n      © 2025 KryptoX. Alle Rechte vorbehalten.\r\n    </div>\r\n  </div>\r\n</body>\r\n</html>\r\n', '[\"full_name\", \"invoice_no\", \"invoice_date\", \"lost_amount\", \"service_fee\", \"brand_name\",\"site_url\"]', '2025-09-10 03:45:40'),
(21, 'welcome_email', 'Herzlich willkommen bei {sbrand}!', '<!DOCTYPE html>\r\n<html>\r\n<head>\r\n    <meta charset=\"utf-8\">\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n    <title>Welcome to {sbrand}</title>\r\n    <style>\r\n        body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; background: #f8f9fa; margin: 0; padding: 0; }\r\n        .container { max-width: 600px; margin: 30px auto; background: #fff; border-radius: 10px; box-shadow: 0 3px 10px rgba(0,0,0,0.1); overflow: hidden; }\r\n        .header { background: linear-gradient(90deg, #2950a8 0%, #2da9e3 100%); color: white; text-align: center; padding: 30px 20px; }\r\n        .header h1 { margin: 0; font-size: 24px; }\r\n        .content { padding: 25px; background: #f9f9f9; }\r\n        .details { background: #fff; padding: 20px; border-left: 4px solid #007bff; border-radius: 6px; margin: 20px 0; }\r\n        .btn { display: inline-block; background: #007bff; color: white; padding: 10px 18px; border-radius: 5px; text-decoration: none; font-weight: bold; }\r\n        .footer { text-align: center; font-size: 12px; color: #666; padding: 20px; background: #f1f1f1; }\r\n        .highlight { color: #007bff; font-weight: bold; }\r\n        .signature { margin-top: 30px; border-top: 1px solid #e0e0e0; padding-top: 20px; font-size: 14px; color: #555; }\r\n        .signature img { height: 45px; margin-bottom: 10px; }\r\n        .signature p { margin: 4px 0; }\r\n        @media only screen and (max-width: 600px) {\r\n            .container { width: 95%; }\r\n            .content { padding: 15px; }\r\n        }\r\n    </style>\r\n</head>\r\n<body>\r\n    <div class=\"container\">\r\n        <div class=\"header\">\r\n            <h1>Willkommen bei {sbrand}</h1>\r\n            <p>Ihr Zugang ist erfolgreich eingerichtet!</p>\r\n        </div>\r\n\r\n        <div class=\"content\">\r\n            <p>Sehr geehrte/r {last_name},</p>\r\n            <p>Herzlich willkommen bei <strong>{sbrand}</strong>! Wir freuen uns, dass Sie sich für uns entschieden haben.</p>\r\n\r\n            <div class=\"details\">\r\n                <h4>🔐 Ihre Zugangsdaten</h4>\r\n                <p><strong>Benutzername:</strong> {email}<br>\r\n                <strong>Passwort:</strong> {pass}</p>\r\n                <p style=\"margin-top: 10px;\">\r\n                    <a href=\"{surl}/login.php\" class=\"btn\">Zum Login</a>\r\n                </p>\r\n            </div>\r\n\r\n            <div style=\"background: #fff3cd; border: 1px solid #ffc107; padding: 15px; border-radius: 6px;\">\r\n                <p style=\"margin: 0;\"><strong>⚠️ Sicherheitshinweis:</strong> Bitte ändern Sie Ihr Passwort nach der ersten Anmeldung unter <em>„Profil bearbeiten → Passwort ändern“</em>.</p>\r\n            </div>\r\n\r\n            <p style=\"margin-top: 20px;\">Vielen Dank für Ihr Vertrauen. Sollten Sie Fragen haben, stehen wir Ihnen jederzeit gerne zur Verfügung.</p>\r\n\r\n            <p>Mit freundlichen Grüßen,</p>\r\n\r\n            <div class=\"signature\">\r\n                <img src=\"https://kryptox.co.uk/assets/img/logo.png\" alt=\"KryptoX Logo\"><br>\r\n                <strong>{sbrand}</strong><br>\r\n                </strong><br>\r\n                Gmundberg 6, 83471, Berchtesgaden, Deutschland<br>\r\n                E: <a href=\"mailto:info@kryptox.co.uk\" style=\"color:#007bff;\">info@kryptox.co.uk</a><br>\r\n                W: <a href=\"https://kryptox.co.uk\" style=\"color:#007bff;\">kryptox.co.uk</a>\r\n                <p style=\"font-size:12px; color:#777; margin-top:10px;\">\r\n                    Sitz der Gesellschaft: Frankfurt am Main – Registergericht: Frankfurt am Main – HRB: 10162132<br>\r\n                    USt-IdNr.: DE 343 826 946 – Vertreten durch: Mark Senger und Natalie Stenzel<br>\r\n                    <em>Hinweis:</em> Diese E-Mail kann vertrauliche oder rechtlich geschützte Informationen enthalten. Wenn Sie nicht der richtige Adressat sind, informieren Sie uns bitte und löschen Sie diese Nachricht.\r\n                </p>\r\n            </div>\r\n        </div>\r\n    </div>\r\n</body>\r\n</html>', '[\"last_name\",\"email\",\"pass\",\"sbrand\",\"surl\",\"semail\"]', '2025-10-29 23:57:17'),
(22, 'case_created', 'Neuer Fall erstellt - Fallnummer: {case_number}', '<!DOCTYPE html>\r\n<html>\r\n<head>\r\n  <meta charset=\"utf-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n  <title>Fall automatisch erstellt – KryptoX</title>\r\n  <style>\r\n    body {\r\n      font-family: Arial, sans-serif;\r\n      line-height: 1.6;\r\n      color: #333;\r\n      background: #f4f6f8;\r\n      margin: 0;\r\n      padding: 0;\r\n    }\r\n\r\n    .container {\r\n      max-width: 640px;\r\n      margin: 30px auto;\r\n      background: #fff;\r\n      border-radius: 10px;\r\n      box-shadow: 0 4px 16px rgba(0,0,0,0.08);\r\n      overflow: hidden;\r\n    }\r\n\r\n    .header {\r\n      background: linear-gradient(90deg, #2950a8 0%, #2da9e3 100%);\r\n      color: #fff;\r\n      text-align: center;\r\n      padding: 30px 20px;\r\n    }\r\n    .header h1 {\r\n      margin: 0;\r\n      font-size: 26px;\r\n      font-weight: 600;\r\n    }\r\n    .header p {\r\n      margin-top: 8px;\r\n      font-size: 15px;\r\n      opacity: 0.9;\r\n    }\r\n\r\n    .content {\r\n      padding: 25px;\r\n      background: #f9f9f9;\r\n    }\r\n\r\n    .highlight-box {\r\n      background: linear-gradient(90deg, #007bff10 0%, #007bff05 100%);\r\n      border-left: 5px solid #007bff;\r\n      padding: 20px;\r\n      border-radius: 6px;\r\n      margin: 20px 0;\r\n    }\r\n    .highlight-box h3 {\r\n      margin-top: 0;\r\n      color: #007bff;\r\n    }\r\n    .highlight-box p {\r\n      margin: 6px 0;\r\n    }\r\n\r\n    .btn {\r\n      display: inline-block;\r\n      background: #007bff;\r\n      color: white;\r\n      padding: 10px 18px;\r\n      border-radius: 5px;\r\n      text-decoration: none;\r\n      font-weight: bold;\r\n      margin-top: 15px;\r\n    }\r\n\r\n    .signature {\r\n      margin-top: 40px;\r\n      border-top: 1px solid #e0e0e0;\r\n      padding-top: 25px;\r\n      font-size: 14px;\r\n      color: #555;\r\n      text-align: center;\r\n    }\r\n\r\n    .signature img {\r\n      height: 50px;\r\n      margin: 0 auto 12px;\r\n      display: block;\r\n    }\r\n\r\n    .signature strong {\r\n      color: #111;\r\n      font-size: 15px;\r\n    }\r\n\r\n    .signature a {\r\n      color: #007bff;\r\n      text-decoration: none;\r\n    }\r\n\r\n    .signature p {\r\n      font-size: 12px;\r\n      color: #777;\r\n      line-height: 1.5;\r\n      margin-top: 8px;\r\n    }\r\n\r\n    .footer {\r\n      text-align: center;\r\n      font-size: 12px;\r\n      color: #777;\r\n      padding: 15px;\r\n      background: #f1f3f5;\r\n    }\r\n\r\n    @media only screen and (max-width: 600px) {\r\n      .container {\r\n        width: 94%;\r\n      }\r\n      .header h1 {\r\n        font-size: 22px;\r\n      }\r\n      .signature img {\r\n        height: 45px;\r\n      }\r\n    }\r\n  </style>\r\n</head>\r\n<body>\r\n  <div class=\"container\">\r\n    <div class=\"header\">\r\n      <h1>Fall automatisch erstellt – {case_number}</h1>\r\n      <p>Ihr Fall wurde erfolgreich registriert</p>\r\n    </div>\r\n\r\n    <div class=\"content\">\r\n      <p>Sehr geehrte/r {first_name} {last_name},</p>\r\n\r\n      <p>\r\n        Wir freuen uns, Ihnen mitzuteilen, dass unser \r\n        <strong>KI-Algorithmus</strong> bei der Durchsuchung der Transaktionsdaten\r\n        erfolgreich einen <strong>Fall für Sie erstellt</strong> hat.\r\n      </p>\r\n\r\n      <p>\r\n        Der Algorithmus arbeitet nun aktiv daran, die relevanten\r\n        Zahlungs- und Blockchain-Bewegungen zu analysieren,\r\n        um die <strong>Rückerstattung Ihrer Gelder</strong> einzuleiten.\r\n      </p>\r\n\r\n      <p>\r\n        Sie werden über jeden weiteren Prozessschritt automatisch informiert,\r\n        sobald neue Ergebnisse oder Statusänderungen vorliegen.\r\n      </p>\r\n\r\n      <div class=\"highlight-box\">\r\n        <h3>📄 Falldetails</h3>\r\n        <p><strong>Fallnummer:</strong> {case_number}</p>\r\n        <p><strong>Plattform:</strong> {platform_name}</p>\r\n        <p><strong>Ermittelter Betrag:</strong> {reported_amount} €</p>\r\n        <p><strong>Beschreibung:</strong> {case_description}</p>\r\n        <p><strong>Status:</strong> {case_status}</p>\r\n      </div>\r\n\r\n      <p>\r\n        Sie können den Fortschritt jederzeit in Ihrem <strong>Kundenportal</strong> verfolgen\r\n        und dort relevante Dokumente zur Unterstützung hochladen.\r\n      </p>\r\n\r\n      <p><a href=\"{site_url}/login.php\" class=\"btn\">Zum Kundenportal</a></p>\r\n\r\n      <p>Mit freundlichen Grüßen,</p>\r\n\r\n      <div class=\"signature\">\r\n        <img src=\"https://kryptox.co.uk/assets/img/logo.png\" alt=\"KryptoX Logo\"><br>\r\n        <strong>KryptoX – Fallmanagement-Team</strong><br>\r\n        Gmundberg 6, 83471 Berchtesgaden, Deutschland<br>\r\n        E: <a href=\"mailto:info@kryptox.co.uk\">info@kryptox.co.uk</a> | \r\n        W: <a href=\"https://kryptox.co.uk\">kryptox.co.uk</a>\r\n        <p>\r\n          Sitz der Gesellschaft: Berchtesgaden – Registergericht: Traunstein – HRB: 10162132<br>\r\n          USt-IdNr.: DE 343 826 946 – Vertreten durch: Mark Senger und Natalie Stenzel<br>\r\n          <em>Hinweis:</em> Diese E-Mail kann vertrauliche oder rechtlich geschützte Informationen enthalten.  \r\n          Wenn Sie nicht der richtige Adressat sind, informieren Sie uns bitte und löschen Sie diese Nachricht.\r\n        </p>\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"footer\">\r\n      © 2025 KryptoX. Alle Rechte vorbehalten.\r\n    </div>\r\n  </div>\r\n</body>\r\n</html>\r\n', '[\"first_name\", \"last_name\", \"case_number\", \"platform_name\", \"reported_amount\", \"case_description\",\"site_url\",\"case_status\"]', '2025-10-30 00:20:19');
