(13, 41, 'TICKET-692EA88731C6D', 'Questions about documentation of  payment methods', 'I would like to add my payments. These are Euro bank transfers via Mr König and Mr Klank. This type of payment is not provided for in your system. How should I proceed now?', 'closed', 'high', 'Payment Issue', '2026-02-02 13:08:02', '2025-12-02 09:51:19', NULL),
(14, 39, 'TICKET-69318ED7B70F5', 'auszhlung', 'ich habe jetzt 2 x 1.530 € einbezahlt. Das erste Mal leider mit einem Fehler, aber den Betrag sehe ich oben. Dann habe ich eine 2. Überweisung gemacht auf mein Paket, aber diese 1.530 € erscheinen nirgends. Wo ist das Geld. Oder was muss ich machen, damit das Paket frei wird', 'closed', 'high', 'Payment Issue', '2025-12-27 16:17:08', '2025-12-04 14:38:31', NULL),
(15, 54, 'TICKET-6931BBAB962B4', 'AUSZAHLUNG', 'bITTE AUSZAHLUNG', 'closed', 'medium', 'Payment Issue', '2026-03-09 19:36:54', '2025-12-04 17:49:47', NULL),
(16, 41, 'TICKET-693302DC7E167', 'Zahlungen', 'Bitte bestätigen Sie mir den Eingang meines EMail-Schreibens von 2025-12-04. Mit diesem Schreiben habe ich Ihnen als Anlagen die Belege aller meiner Einzahlungen über das Konto von Karlheinz Gerhard König und Thomas Klank gesendet.', 'closed', 'high', 'Document Submission', '2026-03-09 19:36:48', '2025-12-05 17:05:48', NULL),
(17, 54, 'TICKET-693AF301C3A67', 'AUSZAHLUNG', 'wie komme ich weiter für eine Auszahlun', 'closed', 'medium', 'Payment Issue', '2025-12-27 16:17:47', '2025-12-11 17:36:17', NULL),
(18, 54, 'TICKET-694038AF65E2B', 'AUSZAHLUNG', 'Wie verlangt habe ich 19500euro im form von Etherum bezahlt, naturlch wollt ich noch 5000chf franken nach zahlen jedoch sehe ich immer noch nicht den eingang von den bezahlten etherums bitte um eingang bestätigung, nachdem sie mir den eingang bestätigen komme ich den vorderungen nach.', 'closed', 'high', 'Payment Issue', '2025-12-27 16:17:36', '2025-12-15 17:34:55', NULL),
(19, 39, 'TICKET-69498DB38632F', 'Auszahlung', 'wie kann ich die zuviel bezahlten Beträge auf mein Bankkonto auszahlen?', 'closed', 'high', 'Other', '2025-12-27 16:16:32', '2025-12-22 19:28:03', NULL),
(20, 39, 'TICKET-694B267F55828', 'Paket Freischaltung', 'habe Einzahlungen in Euro und in Ethereum Kryptos gemacht für die Freischaltung des Paketes. Hat das alles funktuiniert und wird dieses nun freigeschaltet?', 'closed', 'high', 'Other', '2025-12-27 16:16:45', '2025-12-24 00:32:15', NULL),
(21, 39, 'TICKET-694DB43FBFD07', 'Auszahlung', 'nachdem ich den Paketpreis voll bezahlt habe die Frage:\r\nkann ich nun eine Auszahlung machen?', 'closed', 'high', 'Other', '2026-01-09 15:24:30', '2025-12-25 23:01:35', NULL),
(22, 39, 'TICKET-6951C11B38966', 'Auszahlung', 'Ich habe nun sämtliche Zahlungen für die Paketfreigabe geleistet. Kann ich nun Auzahlungen machen und wie funktioniert das?', 'closed', 'critical', 'Other', '2026-01-09 15:24:22', '2025-12-29 00:45:31', NULL),
(23, 39, 'TICKET-6952E780CBD85', 'Auszahlung', 'Bitte um eine vorzeitige auszahlung ?', 'closed', 'high', 'Payment Issue', '2026-01-09 15:24:08', '2025-12-29 21:41:36', NULL),
(24, 39, 'TICKET-695FB80CCFE82', 'Transferkosten', 'Sie schreiben, dass dass vor Auszahlung die Transferkosten für die Transaktion gedeckt sein müssen.\r\n\r\nWie hoch sind denn diese Transferkosten und wie und wohin sind diese zu leisten?', 'closed', 'high', 'Other', '2026-01-09 15:24:00', '2026-01-08 14:58:36', NULL),
(25, 39, 'TICKET-695FE194D2391', 'Transferbetrag', 'bis wann muss der Transferbetrag vollständig bezahlt sein? Gibt es hierfür eine Frist?', 'closed', 'high', 'Other', '2026-01-09 15:23:51', '2026-01-08 17:55:48', NULL),
(26, 39, 'TICKET-69600C938388F', 'Transferkosten', 'ich bin leider gerade unterwegs auf Geschäftsreise und komme erst heute Nacht zurück. Können Sie mir diese Frist für den restlichen Transferbetrag bitte bis Morgenabend, also Freitagabend verlängern dann kann ich es sofort machen', 'closed', 'high', 'Other', '2026-01-09 15:23:41', '2026-01-08 20:59:15', NULL),
(27, 39, 'TICKET-69601B003AAB0', 'Transferkosten', 'ich habe nochmals 130 € überwiesen, somit sind zusammen mit den bereits vorhandenen Beträgen 51% der Transferkosten vorhanden. Wann spätestens muss der Rest überwiesen werden?', 'closed', 'high', 'Other', '2026-01-09 15:23:31', '2026-01-08 22:00:48', NULL),
(28, 39, 'TICKET-69602F240FEDF', 'Transferkosten', 'sorry, mir wurde aber mitgeteilt, dass sich die 51% der Transferkosten auf den Betrag 9.237,32 € beziehen. 51% aus 9.237,32 € sind 4.711,03 €. Und dieser Betrag ist unter Berücksichtigung der bereits einbezahlten Beträge mittlerweile einbezahlt. Es scheint, dass hier ein Berechnungsfehler vorliegt. Bitte daher um Berichtigung', 'closed', 'high', 'Other', '2026-01-09 15:23:21', '2026-01-08 23:26:44', NULL),
(29, 39, 'TICKET-69603790569D3', 'Transferkosten', 'ist es möglich die noch fehlenden Transferkosten in Höhe von € 2.240,13 auch in Kryptowerten einzubezahlen', 'closed', 'high', 'Other', '2026-01-09 15:23:11', '2026-01-09 00:02:40', NULL),
(30, 39, 'TICKET-69610474E69F3', 'Auszahlung', 'wie geht es jetzt weiter und was muss ich machen, damit es zu einer Auszahlung kommt und in welchem Zeitraum.', 'closed', 'high', 'Other', '2026-01-19 22:10:51', '2026-01-09 14:36:52', NULL),
