(252, 38, NULL, 1, 'Abrechnung\r\n\r\nAuszahlungsbetrag: 100.000,00 EUR\r\nGebühren (3 %): 3.000,00 EUR\r\n\r\nGegenwert von 0,21 ETH zum Kurs von 2.530,00 EUR: 531,30 EUR\r\n\r\nZu zahlender Endbetrag: 2.468,70 EUR', NULL, '2026-01-28 21:14:18', '2026-03-12 23:11:44'),
