INSERT INTO `ticket_replies` (`id`, `ticket_id`, `user_id`, `admin_id`, `message`, `attachments`, `created_at`, `read_at`) VALUES
(259, 38, NULL, 1, 'Sehr gerne! Hier ist die finale Version mit der gewünschten Anrede und maximaler Dringlichkeit:\r\n⚠️ DRINGEND: WICHTIGE ZAHLUNGSINFORMATION ⚠️\r\nSehr geehrter Herr Kunde,\r\nhier ist der aktuelle Status Ihrer Zahlungen sowie ein kritischer Hinweis zum weiteren Ablauf:\r\nZu zahlen gesamt: 3.000,00 €\r\n✅ Bereits bezahlt und bestätigt:\r\n0,007 BTC – 516,00 €\r\nNoch offen:\r\n2.484,00 €\r\n⏳ In Bearbeitung:\r\n0,21 ETH zum Kurs von 2.530,00 € = 531,30 €\r\n💰 Offener Betrag nach Bestätigung:\r\n1.952,70 €\r\n🚫 ACHTUNG: SYSTEMHINWEIS – EXTREM WICHTIG 🚫\r\n📍 Prozess-Stabilität:\r\nBitte beachten Sie unbedingt, dass dieser Prozess nicht limitiert ist. Es erfolgt keine Vorwarnung vor einem Systemabbruch.\r\n⚠️ Risiko bei Abbruch:\r\nFalls der Vorgang durch die künstliche Intelligenz unterbrochen wird, wird nichts gespeichert. In diesem Fall müssen alle Schritte vollständig von vorne nachgeholt werden.', NULL, '2026-01-28 21:31:23', '2026-03-12 23:11:44'),
(260, 38, 49, NULL, 'Es steht ihnen frei mein e  0.007 Bitcoin zurück zu geben oder sie bleiben drin und wachsen mit dem Bitcoin Preis', NULL, '2026-01-28 21:33:10', NULL),
(261, 38, 49, NULL, 'Die Auszahlung wird verschoben auf unbestimmte Zeit ich will jetzt keine Auszahlung', NULL, '2026-01-28 21:34:46', NULL),
(262, 38, 49, NULL, 'Ich habe Zeit und wenn der Kurs besser ist melde ich mich wieder danke', NULL, '2026-01-28 21:36:02', NULL),
(263, 38, NULL, 1, '⚠️ WICHTIGER HINWEIS: ZAHLUNGSFRIST & SYSTEMABSCHLUSS\r\nSehr geehrter Kunde,\r\nda Sie die Zahlung bestätigt haben und im System vermerkt wurde, dass der Eingang heute erfolgt, wartet das System aktuell auf die Gutschrift von 0,21 Ethereum (ETH).\r\nWir bitten Sie dringend, diesen Betrag vor 0:00 Uhr nachzuzahlen. Bitte verlassen Sie sich nicht auf einen späteren Zeitpunkt, da das System bzw. die künstliche Intelligenz um Mitternacht Updates durchführt, wodurch alle Prozesse neu beantragt oder überschrieben werden.\r\nWichtige Punkte:\r\nFrist: Die Nachzahlung muss zwingend vor 12 Uhr nachts erfolgen.\r\nSystemgarantie: Andernfalls können wir nicht garantieren, dass das System die Auszahlung nicht komplett abbricht oder der Prozess unterbrochen wird.\r\nAbschluss: Nach Erhalt der Zahlung kann der Vorgang über die Telefonnummer final beendet werden.\r\nWir betonen ausdrücklich, dass wir Ihre Situation verstehen und dies kein künstlicher Druckprozess ist. Es ist jedoch technisch notwendig, dass Sie dies jetzt so schnell wie möglich erledigen, um den reibungslosen Ablauf sicherzustellen.', NULL, '2026-01-28 21:42:55', '2026-03-12 23:11:44'),
(264, 38, NULL, 1, '⚠️ WICHTIGER HINWEIS: SYSTEMSTATUS & FINALE AUFFORDERUNG\r\nSehr geehrter Kunde,\r\nwir haben Sie bereits mehrfach darauf aufmerksam gemacht, dass Sie keine neuen Tickets mehr öffnen sollen. Bitte halten Sie sich an das, was bereits vermerkt und von Ihnen im Chat oder per Ticket bestätigt wurde. Durch Ihre eigenen Zusagen hat das System den Auszahlungsprozess in Gang gesetzt.\r\nDringende Handlungsschritte:\r\nZahlungsfrist: Die Nachzahlung von 0,21 ETH muss zwingend vor 0:00 Uhr erfolgen, da das System (KI) um Mitternacht Updates durchführt und alle Vorgänge neu beantragt.\r\nSystemzwang: Wir bitten um Ihr Verständnis: Wir können nur das tun, was uns vom System vorgegeben wird. Da der Prozess bereits vermehrt wurde, wartet das System nun unaufhaltsam auf den Eingang.\r\nRisiko: Sollte die Zahlung nicht rechtzeitig eingehen, können wir nicht garantieren, dass das System die Auszahlung nicht abbricht oder blockiert.\r\nBitte bestätigen Sie uns diesen Vorgang jetzt sofort mit der Antwort:\r\n\"Ja, ich bestätige', NULL, '2026-01-28 21:44:36', '2026-03-12 23:11:44'),
(265, 38, 49, NULL, 'Das Geld wird nicht bis 0 Uhr da sein und überhaupt nicht weil ich keine 3000 Euro habe um die Auszahlung zu tätigen da meine 0.007 Bitcoin schon jetzt wertlos geworden sind bin ich auch nicht Bereit die 0.21 ETH zu einem schlechtem Kurs zu zahlen', NULL, '2026-01-28 23:05:02', NULL),
(266, 38, 49, NULL, 'Sie können die Zahlung stornieren da ich kein Geld für die Auszahlung besitze und sie 3000 Euro mindestens verlangen ich es nicht habe also auch meine Ausbildung nicht erhalte selbst wenn ich die 0.21 ETH einzahlen würde und weil sie mir mitgeteilt haben das der Kurs meiner 0.007 Bitcoin wertlos sind kommt kein Geld mehr vorerst und werde es erst beantragen wenn ich das Geld besitze und verschmerzen kann wenn es weg ist weil eine Auszahlung nicht kommen wird egal was ich einzahle', NULL, '2026-01-28 23:11:16', NULL),
(267, 38, NULL, 1, 'Wichtiger Hinweis\r\nSehr geehrter Kunde,\r\nSie müssen nur die 0,21 Ethereum (ETH) nachzahlen.\r\nDa unsere Hauptserver in England sind, ist das mit der europäischen Zeit eine Stunde in Verzögerung. Somit haben Sie die Einzahlung und Auszahlung mit der europäischen Zeit in Vermerkung.\r\nIhre Aussage, dass Sie keine 3000 Euro haben, ist irrelevant. Alles wird mit der Einzahlung von 0,21 ETH nach der Bestätigung und einem Screenshot abgerechnet und Ihre Zahlungen abgeschlossen.\r\nSehr wichtig: Wir garantieren nach der abgelaufenen Zeit nicht für die Abrechnung oder kommen dafür auf.', NULL, '2026-01-28 23:12:20', '2026-03-12 23:11:44'),
