(365, 48, NULL, 1, 'Sehr geehrter Herr König,\r\nvielen Dank für die bereits eingereichten Unterlagen und die notarielle Bestätigung.\r\nUm die Umschreibung unter der Ticket-Nummer 69A405D673441 abschließen zu können, benötigt unser System für die finale Datenüberschreibung noch einmal eine zusammenfassende Bestätigung der Daten Ihrer Schwester (Frau Richter):\r\nVollständiger Name:\r\nGeburtsdatum:\r\nE-Mail-Adresse:\r\nAktuelle Anschrift:\r\nBitte lassen Sie uns diese Informationen kurz zukommen. Sobald uns diese Angaben vorliegen, wird die Umschreibung innerhalb von 60 Minuten im System vorgenommen.\r\nIm Anschluss erhält Frau Richter automatisch eine E-Mail an die angegebene Adresse, um die Daten final zu bestätigen und die Verifizierung durchzuführen.\r\nVielen Dank für Ihre Mithilfe.\r\nMit freundlichen Grüßen', NULL, '2026-03-02 21:06:42', NULL),
(366, 48, 50, NULL, 'der Name meiner Schwester ist\r\nCornelia Richter\r\nHanfelde 42a \r\n48282 Emsdetten\r\nGeburtsdatum: 14.07.1965\r\nE-Mail-Adresse: richtercornelia14@gmail.com', NULL, '2026-03-04 13:59:27', NULL),
(367, 50, NULL, 1, 'Sehr geehrter Herr Veit,\r\n\r\num den Auszahlungsprozess zu beginnen, senden wir Ihnen per E-Mail eine Vertragsvereinbarung für die Auszahlung zu.', NULL, '2026-03-04 19:12:47', NULL),
(368, 52, NULL, 1, 'Sehr geehrter Kunde,\r\nhier sind Ihre Bankdaten für die Einzahlung:\r\nEmpfänger: Gerhard Siegel\r\nIBAN: LT76 3250 0317 9190 3416\r\nBIC: REVOLT21\r\nBank: Revolut Bank UAB\r\nAdresse: Konstitucijos ave. 21B, 08130, Vilnius, Lithuania\r\nBIC der Senderbank: CHASDEFX\r\nInformation: Ihr Satoshi Einzahlungspaket', NULL, '2026-03-05 19:49:14', NULL),
(369, 52, 50, NULL, 'Überweisung ist erledigt', NULL, '2026-03-05 19:57:27', NULL),
(370, 52, NULL, 1, 'Hallo Frau Richter,\r\n\r\nwir möchten Sie darüber informieren, dass Ihre Einzahlung derzeit in Bearbeitung ist.\r\n\r\nBitte beachten Sie, dass die Bearbeitung je nach Zahlungsweg 1 bis 3 Werktage dauern kann.', NULL, '2026-03-05 20:09:09', NULL),
(371, 53, NULL, 1, 'Hallo Frau Richter,\r\n\r\nwir sehen, dass Sie gestern Abend eine E-Mail von unserer Finanzabteilung erhalten haben.\r\nDennoch sende ich Ihnen die E-Mail hier noch einmal zur Sicherheit weiter.\r\nFür die Zukunft bitten wir Sie, auch Ihren Spam-Ordner zu überprüfen.\r\n\r\nSehr geehrte Frau Richter,\r\n\r\nwir möchten Sie darüber informieren, dass auf Ihrem Konto eine Einzahlung in Höhe von 2.730,00 EUR eingegangen ist.\r\n\r\nStatus: Vorübergehend eingefroren\r\n\r\nGrund:\r\nGemäß unseren gesetzlichen Vorgaben zur Geldwäscheprävention (AML) sowie den Richtlinien zur Identitätsprüfung (KYC) können Einzahlungen auf Ihr KryptoX-Konto ausschließlich von einem Bankkonto erfolgen, das auf Ihren eigenen Namen registriert ist.\r\n\r\nDie oben genannte Einzahlung wurde jedoch von folgender Drittperson vorgenommen:\r\nKarl-Heinz König\r\n\r\nDa der Name des Einzahlenden nicht mit dem Kontoinhaber Cornelia Richter übereinstimmt, ist es uns aus regulatorischen und sicherheitsrelevanten Gründen derzeit nicht möglich, die Transaktion automatisch Ihrem Konto gutzuschreiben.\r\n\r\nBitte beachten Sie jedoch, dass das Geld nicht verloren ist. Der eingegangene Betrag wird nach Abschluss der internen Prüfung Ihrem KryptoX-Konto als Rückerstattung gutgeschrieben bzw. entsprechend rückabgewickelt.\r\n\r\nFür zukünftige Einzahlungen bitten wir Sie sicherzustellen, dass Überweisungen ausschließlich von einem Bankkonto erfolgen, das auf den Namen Cornelia Richter registriert ist. Einzahlungen von Drittpersonen können aus rechtlichen Gründen nicht akzeptiert werden.\r\n\r\nSollten Sie hierzu Fragen haben, steht Ihnen unser Support-Team jederzeit gerne zur Verfügung.\r\n\r\nMit freundlichen Grüßen\r\nKryptoX Finance Department', NULL, '2026-03-07 19:37:27', NULL),
(372, 53, 50, NULL, 'ich handele zur Zeit im Auftrag meines Bruders, da er nicht in der Lage ist aus gesundheitlichen Gründen seine finanziellen Angelegenheiten zu erledigen. Ich wußte leider nicht dass das so läuft. Dann darf ich Sie bitten mir den Betrag wieder zu erstatten. \r\nVielen Dank für Ihr Verständnis\r\nViele Grüße\r\nCornelia Richter', NULL, '2026-03-07 20:14:13', NULL);
INSERT INTO `ticket_replies` (`id`, `ticket_id`, `user_id`, `admin_id`, `message`, `attachments`, `created_at`, `read_at`) VALUES
(373, 53, NULL, 1, 'Sehr geehrte Frau Richter,\r\n\r\nim Rahmen der Überprüfung Ihrer ausstehenden Einzahlung wurde festgestellt, dass ein Datenabgleich (Data-Mismatch) zwischen dem registrierten Kontoinhaber und dem verwendeten Zahlungsinstrument vorliegt. Die betreffende Transaktion wurde über ein Bankkonto einer Drittperson initiiert und stimmt daher nicht mit den bei uns hinterlegten Verifizierungsdaten des Account-Inhabers überein.\r\n\r\nGemäß den internationalen regulatorischen Anforderungen zur Bekämpfung von Geldwäsche und Terrorismusfinanzierung (AML) sowie den Vorgaben zur Kundenidentifizierung (KYC) sind Kryptowährungsbörsen und Finanzplattformen verpflichtet, sicherzustellen, dass Einzahlungen ausschließlich vom verifizierten Kontoinhaber selbst erfolgen. Zahlungen von Drittpersonen dürfen aus rechtlichen Gründen nicht verarbeitet werden.\r\n\r\nDa die vorliegende Einzahlung von einem fremden Bankkonto durchgeführt wurde, befindet sich der Betrag derzeit im Status „Pending“.\r\n\r\nZur Lösung des Vorgangs\r\n\r\nDamit die Sicherheitsvalidierung abgeschlossen werden kann, ist eine Synchronisation erforderlich. Diese erfolgt, indem der registrierte Account-Inhaber persönlich das entsprechende Abonnement-Paket aktiviert. Sobald das Abonnement aktiviert wurde, erkennt das System die Identität an.\r\n\r\nWichtige Bedingungen für die Freischaltung\r\n\r\nDas Paket muss zu 100 % mit dem Namen übereinstimmen, der auf dem Krypto-Account registriert ist.\r\n\r\nNach der Aktivierung haben Sie ein Zeitfenster von genau 60 Minuten, um die Gelder zurückzusenden.\r\n\r\nDa es um eine Summe von 2,7 Millionen Euro geht, muss der Kunde innerhalb dieser 60 Minuten die 2.730 € zurückerstatten.\r\n\r\nSobald die 2,7 Millionen von der Trust Wallet eingehen, ist eine Korrektur nicht mehr möglich, da die einmalige Auszahlungsfunktion aktiv wird.\r\n\r\nIn diesem Zuge werden zudem hohe Steuern zur Deckung fällig.\r\n\r\nWir bitten Sie daher, das entsprechende Abonnement über Ihr verifiziertes Bankkonto abzuschließen, um den Prozess zu finalisieren.', NULL, '2026-03-07 20:32:06', NULL),
(374, 53, 50, NULL, 'dann sagen sie mir doch bitte über welches Bankkonto das laufen muss', NULL, '2026-03-07 21:06:34', NULL),
(375, 53, NULL, 1, 'Hallo Frau Richter,\r\n\r\n🏦 Kontodaten & Wichtige Hinweise\r\n\r\nEmpfänger: Gerhard Siegel\r\nIBAN: LT76 3250 0317 9190 3416\r\nBIC: REVOLT21\r\nBank: Revolut Bank UAB (Vilnius, Lithuania)\r\nBIC der Senderbank: CHASDEFX\r\nVerwendungszweck : RV\r\n\r\n⚠️ ZWEI SEHR WICHTIGE PUNKTE:\r\nExakte Namensübereinstimmung:\r\nEs ist zwingend erforderlich, dass der angegebene Name (Gerhard Siegel) zu 100 % exakt mit dem im Bankkonto hinterlegten Namen übereinstimmt. Schon kleine Abweichungen können dazu führen, dass die Zahlung von der Bank abgelehnt oder die Verifizierung nicht anerkannt wird.', NULL, '2026-03-07 21:14:47', NULL),
(376, 53, 50, NULL, 'ist es denn zwingend notwendig so ein Paket zu buchen um das Geld auszuzahlen oder gibt es\r\neine Alternative.', NULL, '2026-03-08 10:10:10', NULL),
(377, 53, NULL, 1, 'Sehr geehrte Frau Richter,\r\nBitte beachten Sie, dass der Zugriff auf unsere Dienste erst durch den Abschluss eines Abonnements freigeschaltet wird. Mit der Wahl Ihres Pakets aktivieren Sie den Algorithmus und genießen uneingeschränkten Zugang zu allen Systemvorteilen', NULL, '2026-03-08 13:36:00', NULL),
