(407, 61, NULL, 1, 'Liebe Kundin, lieber Kunde,\r\nanbei finden Sie die Übersicht über Ihre bisherigen Einzahlungen und den noch offenen Restbetrag für Ihr Unlimited Paket:\r\nStatus	Betrag\r\nBereits gezahlt	2.550 €\r\nNoch zu zahlen	180 €\r\nGesamtbetrag	2.730 €\r\nWir bitten Sie, den Differenzbetrag zeitnah zu begleichen. Bei Fragen stehen wir Ihnen gerne zur Verfügung.\r\nHerzliche Grüße', NULL, '2026-03-13 18:03:33', '2026-03-13 22:08:02'),
(408, 61, NULL, 1, 'Liebe Kundin, lieber Kunde,\r\nanbei finden Sie die Übersicht über Ihre bisherigen Einzahlungen und den noch offenen Restbetrag für Ihr Unlimited Paket:\r\nStatus	Betrag\r\nBereits gezahlt	2.550 €\r\nNoch zu zahlen	180 €\r\nGesamtbetrag	2.730 €\r\nWir bitten Sie, den Differenzbetrag zeitnah zu begleichen. Bei Fragen stehen wir Ihnen gerne zur Verfügung.\r\nHerzliche Grüße', NULL, '2026-03-13 18:03:35', '2026-03-13 22:08:02'),
